#[derive(Debug, Clone, PartialEq, Eq)]
struct DesktopJoinRouteServerSnapshot {
    name: String,
    address: String,
    source: String,
    status: String,
    version: String,
    description: String,
    players: String,
    map: String,
    mode: String,
    ping: String,
    search_terms: String,
}

#[derive(Debug, Clone, PartialEq)]
pub enum DesktopJoinSavedServerRefreshState {
    Idle,
    Refreshing,
    Resolved(Host),
    Failed(String),
}

impl DesktopJoinRouteServerSnapshot {
    fn matches_query(&self, query: &str) -> bool {
        let query = query.trim().to_lowercase();
        query.is_empty() || self.search_terms.contains(&query)
    }

    fn refresh_search_terms(&mut self) {
        self.search_terms = [
            self.name.clone(),
            self.address.clone(),
            self.source.clone(),
            self.status.clone(),
            self.version.clone(),
            self.description.clone(),
            self.players.clone(),
            self.map.clone(),
            self.mode.clone(),
            self.ping.clone(),
        ]
        .join(" ")
        .to_lowercase();
    }
}

#[derive(Debug, Clone, PartialEq)]
pub struct DesktopJoinCommunityGroup {
    pub name: String,
    pub addresses: Vec<String>,
    pub prioritized: bool,
    pub hosts: Vec<Host>,
}

impl DesktopJoinCommunityGroup {
    pub fn new(name: impl Into<String>, addresses: Vec<String>, prioritized: bool) -> Self {
        Self {
            name: name.into(),
            addresses,
            prioritized,
            hosts: Vec::new(),
        }
    }

    pub fn key(&self) -> String {
        let key = if self.name.trim().is_empty() {
            self.addresses
                .first()
                .map(String::as_str)
                .unwrap_or("unknown")
        } else {
            self.name.as_str()
        };
        format!("server-{key}")
    }

    pub fn hidden_setting_key(&self) -> String {
        format!("{}-hidden", self.key())
    }

    pub fn favorite_setting_key(&self) -> String {
        format!("{}-favorite", self.key())
    }

    fn matches_query(&self, query: &str) -> bool {
        let query = query.trim().to_lowercase();
        if query.is_empty() {
            return true;
        }
        self.name.to_lowercase().contains(&query)
            || self
                .addresses
                .iter()
                .any(|address| address.to_lowercase().contains(&query))
            || self.hosts.iter().any(|host| {
                [
                    host.name.as_str(),
                    host.description.as_str(),
                    host.mapname.as_str(),
                    host.mode_name.as_deref().unwrap_or_default(),
                    host.address.as_str(),
                ]
                .into_iter()
                .any(|field| field.to_lowercase().contains(&query))
            })
    }
}

