pub enum DesktopCustomRulesToggle {
    Waves,
    WaveSending,
    WaveTimer,
    InfiniteResources,
    SchematicsAllowed,
    HideBannedBlocks,
    BlockWhitelist,
    UnitWhitelist,
    AttackMode,
    Pvp,
    CoreCapture,
}

impl DesktopCustomRulesToggle {
    fn label_key(self) -> &'static str {
        match self {
            Self::Waves => "@rules.waves",
            Self::WaveSending => "@rules.wavesending",
            Self::WaveTimer => "@rules.wavetimer",
            Self::InfiniteResources => "@rules.infiniteresources",
            Self::SchematicsAllowed => "@rules.schematic",
            Self::HideBannedBlocks => "@rules.hidebannedblocks",
            Self::BlockWhitelist => "@bannedblocks.whitelist",
            Self::UnitWhitelist => "@bannedunits.whitelist",
            Self::AttackMode => "@rules.attack",
            Self::Pvp => "@mode.pvp.name",
            Self::CoreCapture => "@rules.corecapture",
        }
    }

    fn value(self, rules: &Rules) -> bool {
        match self {
            Self::Waves => rules.waves,
            Self::WaveSending => rules.wave_sending,
            Self::WaveTimer => rules.wave_timer,
            Self::InfiniteResources => rules.infinite_resources,
            Self::SchematicsAllowed => rules.schematics_allowed,
            Self::HideBannedBlocks => rules.hide_banned_blocks,
            Self::BlockWhitelist => rules.block_whitelist,
            Self::UnitWhitelist => rules.unit_whitelist,
            Self::AttackMode => rules.attack_mode,
            Self::Pvp => rules.pvp,
            Self::CoreCapture => rules.core_capture,
        }
    }

    fn enabled(self, rules: &Rules) -> bool {
        match self {
            Self::WaveSending | Self::WaveTimer => rules.waves,
            _ => true,
        }
    }

    fn toggle(self, rules: &mut Rules) {
        match self {
            Self::Waves => rules.waves = !rules.waves,
            Self::WaveSending => rules.wave_sending = !rules.wave_sending,
            Self::WaveTimer => rules.wave_timer = !rules.wave_timer,
            Self::InfiniteResources => rules.infinite_resources = !rules.infinite_resources,
            Self::SchematicsAllowed => rules.schematics_allowed = !rules.schematics_allowed,
            Self::HideBannedBlocks => rules.hide_banned_blocks = !rules.hide_banned_blocks,
            Self::BlockWhitelist => rules.block_whitelist = !rules.block_whitelist,
            Self::UnitWhitelist => rules.unit_whitelist = !rules.unit_whitelist,
            Self::AttackMode => rules.attack_mode = !rules.attack_mode,
            Self::Pvp => rules.pvp = !rules.pvp,
            Self::CoreCapture => rules.core_capture = !rules.core_capture,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DesktopCustomRulesNumber {
    WinWave,
    WaveSpacing,
    InitialWaveSpacing,
    DropZoneRadius,
}

impl DesktopCustomRulesNumber {
    const ALL: [Self; 4] = [
        Self::WinWave,
        Self::WaveSpacing,
        Self::InitialWaveSpacing,
        Self::DropZoneRadius,
    ];

    fn label_key(self) -> &'static str {
        match self {
            Self::WinWave => "@rules.wavelimit",
            Self::WaveSpacing => "@rules.wavespacing",
            Self::InitialWaveSpacing => "@rules.initialwavespacing",
            Self::DropZoneRadius => "@rules.dropzoneradius",
        }
    }

    fn enabled(self, rules: &Rules) -> bool {
        match self {
            Self::WaveSpacing | Self::InitialWaveSpacing => rules.waves && rules.wave_timer,
            Self::WinWave | Self::DropZoneRadius => rules.waves,
        }
    }

    fn value_text(self, rules: &Rules) -> String {
        match self {
            Self::WinWave => rules.win_wave.to_string(),
            Self::WaveSpacing => format_custom_rules_number(rules.wave_spacing / 60.0),
            Self::InitialWaveSpacing => {
                format_custom_rules_number(rules.initial_wave_spacing / 60.0)
            }
            Self::DropZoneRadius => {
                format_custom_rules_number(rules.drop_zone_radius / TILE_SIZE as f32)
            }
        }
    }

    fn adjust(self, rules: &mut Rules, direction: i32) {
        let direction = direction.signum();
        if direction == 0 || !self.enabled(rules) {
            return;
        }
        match self {
            Self::WinWave => {
                rules.win_wave = (rules.win_wave + direction).max(0);
            }
            Self::WaveSpacing => {
                let seconds = (rules.wave_spacing / 60.0 + direction as f32 * 10.0).max(1.0);
                rules.wave_spacing = seconds * 60.0;
            }
            Self::InitialWaveSpacing => {
                let seconds =
                    (rules.initial_wave_spacing / 60.0 + direction as f32 * 10.0).max(0.0);
                rules.initial_wave_spacing = seconds * 60.0;
            }
            Self::DropZoneRadius => {
                let tiles = (rules.drop_zone_radius / TILE_SIZE as f32 + direction as f32).max(0.0);
                rules.drop_zone_radius = tiles * TILE_SIZE as f32;
            }
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DesktopWeatherNumber {
    MinDuration,
    MaxDuration,
    MinFrequency,
    MaxFrequency,
}

impl DesktopWeatherNumber {
    const ALL: [Self; 4] = [
        Self::MinDuration,
        Self::MaxDuration,
        Self::MinFrequency,
        Self::MaxFrequency,
    ];

    fn label(self) -> &'static str {
        match self {
            Self::MinDuration => "d-",
            Self::MaxDuration => "d+",
            Self::MinFrequency => "f-",
            Self::MaxFrequency => "f+",
        }
    }

    fn value_text(self, entry: &WeatherEntry) -> String {
        let value = match self {
            Self::MinDuration => entry.min_duration,
            Self::MaxDuration => entry.max_duration,
            Self::MinFrequency => entry.min_frequency,
            Self::MaxFrequency => entry.max_frequency,
        };
        format_custom_rules_number(value / 60.0)
    }

    fn adjust(self, entry: &mut WeatherEntry, direction: i32) {
        if direction == 0 || entry.always {
            return;
        }
        let delta = direction.signum() as f32 * 60.0;
        match self {
            Self::MinDuration => {
                entry.min_duration = (entry.min_duration + delta).max(0.0);
                if entry.max_duration < entry.min_duration {
                    entry.max_duration = entry.min_duration;
                }
            }
            Self::MaxDuration => {
                entry.max_duration = (entry.max_duration + delta).max(0.0);
                if entry.min_duration > entry.max_duration {
                    entry.min_duration = entry.max_duration;
                }
            }
            Self::MinFrequency => {
                entry.min_frequency = (entry.min_frequency + delta).max(0.0);
                if entry.max_frequency < entry.min_frequency {
                    entry.max_frequency = entry.min_frequency;
                }
            }
            Self::MaxFrequency => {
                entry.max_frequency = (entry.max_frequency + delta).max(0.0);
                if entry.min_frequency > entry.max_frequency {
                    entry.min_frequency = entry.max_frequency;
                }
            }
        }
    }
}

