#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct AboutLinkEntry {
    pub name: &'static str,
    pub title: &'static str,
    pub description: &'static str,
    pub url: &'static str,
    pub icon: &'static str,
    pub color_hex: &'static str,
}

impl AboutLinkEntry {
    fn color_rgba(&self) -> [f32; 4] {
        about_color_hex_to_rgba(self.color_hex)
    }

    fn dark_color_rgba(&self) -> [f32; 4] {
        let [r, g, b, a] = self.color_rgba();
        [r * 0.6, g * 0.6, b * 0.8, a]
    }
}

fn about_hex_pair_to_unit(bytes: &[u8], index: usize) -> Option<f32> {
    let high = bytes.get(index).copied()?;
    let low = bytes.get(index + 1).copied()?;
    let high = (high as char).to_digit(16)?;
    let low = (low as char).to_digit(16)?;
    Some(((high << 4) + low) as f32 / 255.0)
}

fn about_color_hex_to_rgba(color_hex: &str) -> [f32; 4] {
    if color_hex == "accent" {
        return [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, Pal::ACCENT.a];
    }
    let hex = color_hex.strip_prefix('#').unwrap_or(color_hex);
    let bytes = hex.as_bytes();
    let Some(r) = about_hex_pair_to_unit(bytes, 0) else {
        return [1.0, 1.0, 1.0, 1.0];
    };
    let Some(g) = about_hex_pair_to_unit(bytes, 2) else {
        return [1.0, 1.0, 1.0, 1.0];
    };
    let Some(b) = about_hex_pair_to_unit(bytes, 4) else {
        return [1.0, 1.0, 1.0, 1.0];
    };
    [r, g, b, 1.0]
}

fn desktop_ui_icon_glyph_or_label(icon_name: &str, fallback: &str) -> String {
    upstream_ui_icon_glyph_string(icon_name).unwrap_or_else(|| fallback.to_string())
}

fn schematic_search_normalize(value: &str) -> String {
    value
        .to_lowercase()
        .chars()
        .filter(|ch| {
            !matches!(
                ch,
                '`' | '~'
                    | '!'
                    | '@'
                    | '#'
                    | '$'
                    | '%'
                    | '^'
                    | '&'
                    | '*'
                    | '('
                    | ')'
                    | '-'
                    | '_'
                    | '='
                    | '+'
                    | '{'
                    | '}'
                    | '|'
                    | ';'
                    | ':'
                    | '\''
                    | '"'
                    | ','
                    | '<'
                    | '.'
                    | '>'
                    | '/'
                    | '?'
            )
        })
        .collect()
}

fn schematic_text_snippet(value: &str, max_chars: usize) -> String {
    let value = value.trim();
    if value.is_empty() {
        return String::new();
    }

    let mut out = String::new();
    for (index, ch) in value.chars().enumerate() {
        if index >= max_chars {
            out.push_str("...");
            break;
        }
        out.push(ch);
    }

    out
}

fn schematic_source_summary(entry: &DesktopSchematicCardEntry) -> String {
    if entry.has_steam_id {
        "source: workshop".to_string()
    } else if let Some(mod_name) = entry
        .mod_name
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        format!("source: mod {}", schematic_text_snippet(mod_name, 24))
    } else {
        "source: local".to_string()
    }
}

fn schematic_description_summary(entry: &DesktopSchematicCardEntry) -> Option<String> {
    let description = entry.description.trim();
    (!description.is_empty())
        .then(|| format!("description: {}", schematic_text_snippet(description, 48)))
}

fn schematic_label_summary(labels: &[String]) -> Option<String> {
    (!labels.is_empty())
        .then(|| format!("tags: {}", schematic_text_snippet(&labels.join(", "), 38)))
}

fn schematic_tags_json_escape(value: &str) -> String {
    let mut escaped = String::with_capacity(value.len());
    for ch in value.chars() {
        match ch {
            '\\' => escaped.push_str("\\\\"),
            '"' => escaped.push_str("\\\""),
            '\n' => escaped.push_str("\\n"),
            '\r' => escaped.push_str("\\r"),
            '\t' => escaped.push_str("\\t"),
            _ => escaped.push(ch),
        }
    }
    escaped
}

fn schematic_tags_to_json(tags: &[String]) -> String {
    let body = tags
        .iter()
        .map(|tag| format!("\"{}\"", schematic_tags_json_escape(tag)))
        .collect::<Vec<_>>()
        .join(",");
    format!("[{body}]")
}

fn schematic_tags_from_json(value: &str) -> Vec<String> {
    let mut tags = Vec::new();
    let mut chars = value.trim().chars().peekable();
    if chars.next() != Some('[') {
        return tags;
    }
    loop {
        while matches!(chars.peek(), Some(ch) if ch.is_whitespace() || *ch == ',') {
            chars.next();
        }
        match chars.peek().copied() {
            Some(']') | None => break,
            Some('"') => {
                chars.next();
                let mut tag = String::new();
                while let Some(ch) = chars.next() {
                    match ch {
                        '"' => break,
                        '\\' => match chars.next() {
                            Some('n') => tag.push('\n'),
                            Some('r') => tag.push('\r'),
                            Some('t') => tag.push('\t'),
                            Some(other) => tag.push(other),
                            None => break,
                        },
                        other => tag.push(other),
                    }
                }
                if !tag.is_empty() && !tags.iter().any(|known| known == &tag) {
                    tags.push(tag);
                }
            }
            _ => break,
        }
    }
    tags
}

