fn desktop_unit_item_center(unit: &UnitComp) -> RenderPoint {
    let offset = if unit.type_info.item_offset_y.is_finite() {
        unit.type_info.item_offset_y
    } else {
        0.0
    };
    let (offset_x, offset_y) = desktop_rotate_offset(unit.rotation() + 180.0, offset, 0.0);
    RenderPoint::new(unit.x() + offset_x, unit.y() + offset_y)
}

fn desktop_unit_suppression_field_center(
    unit: &UnitComp,
    ability: &SuppressionFieldAbility,
) -> RenderPoint {
    let (offset_x, offset_y) = desktop_rotate_offset(unit.rotation() - 90.0, ability.x, ability.y);
    RenderPoint::new(unit.x() + offset_x, unit.y() + offset_y)
}

fn desktop_unit_shield_arc_center(unit: &UnitComp, ability: &ShieldArcAbility) -> RenderPoint {
    let (x, y) = ability.shield_position(unit.x(), unit.y(), unit.rotation());
    RenderPoint::new(x, y)
}

fn desktop_unit_energy_field_center(unit: &UnitComp, ability: &EnergyFieldAbility) -> RenderPoint {
    let (x, y) = ability.center(unit.x(), unit.y(), unit.rotation());
    RenderPoint::new(x, y)
}

fn desktop_arc_point(center: RenderPoint, radius: f32, angle: f32) -> RenderPoint {
    let (offset_x, offset_y) = desktop_rotate_offset(angle, radius, 0.0);
    RenderPoint::new(center.x + offset_x, center.y + offset_y)
}

fn desktop_arc_line_commands(
    center: RenderPoint,
    radius: f32,
    angle_span: f32,
    start_angle: f32,
    stroke: f32,
    color: [f32; 4],
    layer: f32,
) -> Vec<RenderCommand> {
    if radius <= f32::EPSILON || angle_span <= f32::EPSILON || stroke <= f32::EPSILON {
        return Vec::new();
    }

    let angle_span = angle_span.clamp(0.0, 360.0);
    let segments =
        ((angle_span / DESKTOP_SHIELD_ARC_MAX_SEGMENT_DEGREES).ceil() as usize).clamp(1, 128);
    let mut commands = Vec::with_capacity(segments);
    for segment in 0..segments {
        let t0 = segment as f32 / segments as f32;
        let t1 = (segment + 1) as f32 / segments as f32;
        let from = desktop_arc_point(center, radius, start_angle + angle_span * t0);
        let to = desktop_arc_point(center, radius, start_angle + angle_span * t1);
        commands.push(RenderCommand::draw_line(from, to, stroke, color, layer));
    }
    commands
}

fn desktop_unit_soft_shadow_sprite(unit: &UnitComp) -> &'static str {
    if unit.type_info.square_shape {
        "square-shadow"
    } else if unit.type_info.hit_size <= 10.0 {
        "particle"
    } else {
        "circle-shadow"
    }
}

fn desktop_unit_soft_shadow_layer(unit: &UnitComp) -> f32 {
    (desktop_unit_body_layer(unit) - 0.01).min(Layer::BULLET - 1.0)
}

fn desktop_unit_hard_shadow_layer(unit: &UnitComp) -> f32 {
    (desktop_unit_body_layer(unit) - 1.0).min(Layer::DARKNESS)
}

fn desktop_approach_delta(value: f32, target: f32, amount: f32) -> f32 {
    let amount = if amount.is_finite() {
        amount.max(0.0)
    } else {
        0.0
    };
    if value < target {
        (value + amount).min(target)
    } else {
        (value - amount).max(target)
    }
}

fn desktop_unit_hard_shadow_center(unit: &UnitComp) -> Option<RenderPoint> {
    if !unit.is_valid() || (!unit.is_flying() && unit.type_info.shadow_elevation <= 0.0) {
        return None;
    }

    let elevation = unit.elevation.clamp(unit.type_info.shadow_elevation, 1.0)
        * unit.type_info.shadow_elevation_scl
        * (1.0 - unit.drown_time).clamp(0.0, 1.0);

    Some(RenderPoint::new(
        unit.x() + UNIT_SHADOW_TX * elevation,
        unit.y() + UNIT_SHADOW_TY * elevation,
    ))
}

fn desktop_team_color_rgba(team: TeamId) -> u32 {
    match team.0 {
        0 => 0x4d4e58ff,
        1 => 0xffd37fff,
        2 => 0xf25555ff,
        3 => 0xa27ce5ff,
        4 => 0x54d67dff,
        5 => 0x6c87fdff,
        6 => 0xe05438ff,
        other => {
            let hash = desktop_splitmix32(other as u32 + 0x9e37_79b9);
            let r = 0x60 + ((hash >> 16) & 0x7f);
            let g = 0x60 + ((hash >> 8) & 0x7f);
            let b = 0x60 + (hash & 0x7f);
            (r << 24) | (g << 16) | (b << 8) | 0xff
        }
    }
}

fn desktop_splitmix32(mut value: u32) -> u32 {
    value = value.wrapping_add(0x9e37_79b9);
    value = (value ^ (value >> 16)).wrapping_mul(0x85eb_ca6b);
    value = (value ^ (value >> 13)).wrapping_mul(0xc2b2_ae35);
    value ^ (value >> 16)
}

fn desktop_unit_cell_color(unit: &UnitComp) -> [f32; 4] {
    let team = rgba8888_to_render_color(desktop_team_color_rgba(unit.team.team), 1.0);
    let healthf = unit.health.healthf().clamp(0.0, 1.0);
    [
        desktop_lerp(0.0, team[0], healthf),
        desktop_lerp(0.0, team[1], healthf),
        desktop_lerp(0.0, team[2], healthf),
        desktop_lerp(1.0, team[3], healthf),
    ]
}

fn desktop_unit_shield_color(unit: &UnitComp) -> [f32; 4] {
    let shield_rgba = unit
        .type_info
        .shield_color_rgba
        .unwrap_or_else(|| desktop_team_color_rgba(unit.team.team));
    let mut color = rgba8888_to_render_color(shield_rgba, 1.0);
    let hit = (unit.health.hit_time / 2.0).clamp(0.0, 1.0);
    color[0] = desktop_lerp(color[0], 1.0, hit);
    color[1] = desktop_lerp(color[1], 1.0, hit);
    color[2] = desktop_lerp(color[2], 1.0, hit);
    color[3] = 0.7 * unit.shield.shield_alpha.clamp(0.0, 1.0);
    color
}

fn desktop_unit_force_field_color(unit: &UnitComp) -> [f32; 4] {
    let shield_rgba = unit
        .type_info
        .shield_color_rgba
        .unwrap_or_else(|| desktop_team_color_rgba(unit.team.team));
    let mut color = rgba8888_to_render_color(shield_rgba, 1.0);
    let hit_alpha = unit.shield.shield_alpha.clamp(0.0, 1.0);
    color[0] = desktop_lerp(color[0], 1.0, hit_alpha);
    color[1] = desktop_lerp(color[1], 1.0, hit_alpha);
    color[2] = desktop_lerp(color[2], 1.0, hit_alpha);
    color
}

fn desktop_rotate_offset(rotation: f32, x: f32, y: f32) -> (f32, f32) {
    let radians = rotation.to_radians();
    let (sin, cos) = radians.sin_cos();
    (x * cos - y * sin, x * sin + y * cos)
}

fn desktop_line_angle_points(
    origin: RenderPoint,
    rotation: f32,
    length: f32,
) -> (RenderPoint, RenderPoint) {
    let (x, y) = desktop_rotate_offset(rotation, length, 0.0);
    (origin, RenderPoint::new(origin.x + x, origin.y + y))
}

fn desktop_line_angle_center_points(
    center: RenderPoint,
    rotation: f32,
    length: f32,
) -> (RenderPoint, RenderPoint) {
    let (x, y) = desktop_rotate_offset(rotation, length / 2.0, 0.0);
    (
        RenderPoint::new(center.x - x, center.y - y),
        RenderPoint::new(center.x + x, center.y + y),
    )
}

fn desktop_unit_engine_entries(unit: &UnitComp) -> Vec<(f32, f32, f32, f32)> {
    if !unit.type_info.engines.is_empty() {
        unit.type_info
            .engines
            .iter()
            .map(|engine| (engine.x, engine.y, engine.radius, engine.rotation))
            .collect()
    } else if unit.type_info.engine_size > 0.0 {
        vec![(
            0.0,
            -unit.type_info.engine_offset,
            unit.type_info.engine_size,
            -90.0,
        )]
    } else {
        Vec::new()
    }
}

fn desktop_unit_engine_layer(unit: &UnitComp) -> f32 {
    if unit.type_info.engine_layer > 0.0 {
        unit.type_info.engine_layer
    } else {
        desktop_unit_body_layer(unit)
    }
}

fn desktop_unit_weapon_layer(unit: &UnitComp, weapon: &Weapon) -> f32 {
    desktop_unit_body_layer(unit) + weapon.layer_offset
}

fn desktop_unit_weapon_pose(unit: &UnitComp, mount: &WeaponMount) -> (RenderPoint, f32) {
    let weapon = &mount.weapon;
    let unit_rotation = unit.rotation() - 90.0;
    let weapon_rotation = unit_rotation
        + if weapon.rotate {
            mount.rotation
        } else {
            weapon.base_rotation
        };
    let real_recoil = mount.recoil.max(0.0).powf(weapon.recoil_pow) * weapon.recoil;
    let (mount_x, mount_y) = desktop_rotate_offset(unit_rotation, weapon.x, weapon.y);
    let (recoil_x, recoil_y) = desktop_rotate_offset(weapon_rotation, 0.0, -real_recoil);

    (
        RenderPoint::new(unit.x() + mount_x + recoil_x, unit.y() + mount_y + recoil_y),
        weapon_rotation,
    )
}

fn desktop_puddle_fraction(amount: f32) -> f32 {
    (amount / (PuddleComp::MAX_LIQUID / 1.5)).clamp(0.0, 1.0)
}

fn desktop_puddle_draw_color(rgba: u32) -> [f32; 4] {
    let mut color = rgba8888_to_render_color(rgba, 1.0);
    color[0] *= 0.95;
    color[1] *= 0.95;
    color[2] *= 0.95;
    color
}

fn desktop_puddle_seeded_offsets(id: i32, length: f32) -> [(f32, f32); 3] {
    let mut state = (id as i64 as u64)
        .wrapping_mul(0x9e37_79b9_7f4a_7c15)
        .wrapping_add(0x632b_e59b_d9b4_e019);
    let mut next_unit = || {
        state ^= state >> 12;
        state ^= state << 25;
        state ^= state >> 27;
        let value = state.wrapping_mul(0x2545_f491_4f6c_dd1d);
        ((value >> 40) as f32) / ((1u64 << 24) as f32)
    };

    std::array::from_fn(|_| {
        let angle = next_unit() * std::f32::consts::TAU;
        let distance = next_unit() * length.max(0.0);
        (angle.cos() * distance, angle.sin() * distance)
    })
}

fn desktop_weather_rgba_property(rgba: u32) -> String {
    format!("{rgba:08x}")
}

const DESKTOP_WEATHER_BOUND_MAX: f32 = 10000.0 * 8.0;

#[derive(Debug, Clone, Copy)]
struct DesktopArcRand {
    seed0: u64,
    seed1: u64,
}

impl DesktopArcRand {
    fn with_seed(seed: i64) -> Self {
        let mut rand = Self { seed0: 0, seed1: 0 };
        rand.set_seed(seed);
        rand
    }

    fn set_seed(&mut self, seed: i64) {
        let seed = if seed == 0 {
            0x8000_0000_0000_0000
        } else {
            seed as u64
        };
        let hashed = desktop_murmur_hash3(seed);
        self.seed0 = hashed;
        self.seed1 = desktop_murmur_hash3(hashed);
    }

    fn next_long(&mut self) -> u64 {
        let mut seed0 = self.seed0;
        let seed1 = self.seed1;
        self.seed0 = seed1;
        seed0 ^= seed0 << 23;
        self.seed1 = seed0 ^ seed1 ^ (seed0 >> 17) ^ (seed1 >> 26);
        self.seed1.wrapping_add(seed1)
    }

    fn next_float(&mut self) -> f32 {
        ((self.next_long() >> 40) as f64 * (1.0 / (1u64 << 24) as f64)) as f32
    }

    fn random(&mut self, range: f32) -> f32 {
        self.next_float() * range
    }

    fn random_between(&mut self, min: f32, max: f32) -> f32 {
        min + self.next_float() * (max - min)
    }
}

fn desktop_murmur_hash3(mut value: u64) -> u64 {
    value ^= value >> 33;
    value = value.wrapping_mul(0xff51_afd7_ed55_8ccd);
    value ^= value >> 33;
    value = value.wrapping_mul(0xc4ce_b9fe_1a85_ec53);
    value ^= value >> 33;
    value
}

fn desktop_weather_rain_over_draw_lines(
    over: &RainDrawPlan,
    state: &WeatherState,
    camera: RenderCamera,
    render_time: f32,
) -> Vec<RenderCommand> {
    if over.density <= f32::EPSILON
        || over.intensity <= f32::EPSILON
        || state.opacity <= f32::EPSILON
    {
        return Vec::new();
    }

    let camera_rect = camera.world_rect();
    let padding = over.size_max * 0.9;
    let rain_rect = camera_rect.inflate(padding);
    if rain_rect.width <= f32::EPSILON || rain_rect.height <= f32::EPSILON {
        return Vec::new();
    }
    let total =
        ((rain_rect.width * rain_rect.height) / over.density * over.intensity).max(0.0) as usize;
    let mut rand = DesktopArcRand::with_seed(0);
    let mut commands = Vec::with_capacity(total);

    for _ in 0..total {
        let scl = rand.random_between(0.5, 1.0);
        let scl2 = rand.random_between(0.5, 1.0);
        let size = rand.random_between(over.size_min, over.size_max);
        let mut x = rand.random(DESKTOP_WEATHER_BOUND_MAX) + render_time * over.xspeed * scl2;
        let mut y = rand.random(DESKTOP_WEATHER_BOUND_MAX) - render_time * over.yspeed * scl;
        let tint = rand.random(1.0) * state.opacity;

        x = (x - rain_rect.x).rem_euclid(rain_rect.width) + rain_rect.x;
        y = (y - rain_rect.y).rem_euclid(rain_rect.height) + rain_rect.y;

        if !RenderRect::from_center(RenderPoint::new(x, y), size, size).intersects(camera_rect) {
            continue;
        }

        let dx = over.xspeed * scl2;
        let dy = -over.yspeed * scl;
        let len = (dx * dx + dy * dy).sqrt();
        if len <= f32::EPSILON {
            continue;
        }

        let line_len = size / 2.0;
        let from = RenderPoint::new(x, y);
        let to = RenderPoint::new(x + dx / len * line_len, y + dy / len * line_len);
        commands.push(RenderCommand::draw_line(
            from,
            to,
            over.stroke,
            rgba8888_to_render_color(over.color_rgba, tint),
            Layer::WEATHER,
        ));
    }

    commands
}

fn desktop_render_color_mul_rgb(mut color: [f32; 4], multiplier: f32) -> [f32; 4] {
    color[0] = (color[0] * multiplier).clamp(0.0, 1.0);
    color[1] = (color[1] * multiplier).clamp(0.0, 1.0);
    color[2] = (color[2] * multiplier).clamp(0.0, 1.0);
    color
}

fn desktop_weather_splash_slope(life: f32) -> f32 {
    (1.0 - (life * 2.0 - 1.0).abs()).clamp(0.0, 1.0)
}

fn desktop_angle_vector_degrees(angle_degrees: f32, length: f32) -> (f32, f32) {
    let radians = angle_degrees.to_radians();
    (radians.cos() * length, radians.sin() * length)
}

fn desktop_weather_splash_regions(splashes: &[String]) -> Vec<String> {
    if splashes.iter().any(|splash| !splash.is_empty()) {
        splashes.to_vec()
    } else {
        (0..mindustry_core::mindustry::r#type::RainWeather::SPLASH_COUNT)
            .map(|index| format!("splash-{index}"))
            .collect()
    }
}

fn desktop_weather_texture_symbol_from_path(path: &str) -> String {
    let normalized = path.trim().replace('\\', "/").to_ascii_lowercase();
    let file_name = normalized.rsplit('/').next().unwrap_or(&normalized);
    file_name
        .rsplit_once('.')
        .map(|(stem, _)| stem)
        .unwrap_or(file_name)
        .to_string()
}

fn desktop_weather_noise_render_commands(
    noise: &ParticleNoiseLayerPlan,
    camera: RenderCamera,
) -> Vec<RenderCommand> {
    let camera_rect = camera.world_rect();
    if camera_rect.width.abs() <= f32::EPSILON
        || camera_rect.height.abs() <= f32::EPSILON
        || noise.opacity <= f32::EPSILON
    {
        return Vec::new();
    }

    vec![RenderCommand::draw_sprite(
        desktop_weather_texture_symbol_from_path(&noise.noise_path),
        camera_rect,
        rgba8888_to_render_color(noise.color_rgba, noise.opacity),
        0.0,
        Layer::WEATHER - 1.0,
    )]
}

fn desktop_weather_particle_sin(value: f32, scale: f32, magnitude: f32) -> f32 {
    if scale.abs() <= f32::EPSILON {
        0.0
    } else {
        (value / scale).sin() * magnitude
    }
}

fn desktop_weather_particle_render_commands(
    particles: &ParticleDrawParticlesPlan,
    camera: RenderCamera,
    render_time: f32,
) -> Vec<RenderCommand> {
    if particles.density <= f32::EPSILON
        || particles.intensity <= f32::EPSILON
        || particles.opacity <= f32::EPSILON
        || particles.size_max <= f32::EPSILON
    {
        return Vec::new();
    }

    let camera_rect = camera.world_rect();
    let particle_rect = camera_rect.inflate(particles.size_max * 1.5);
    if particle_rect.width <= f32::EPSILON || particle_rect.height <= f32::EPSILON {
        return Vec::new();
    }

    let total = ((particle_rect.width * particle_rect.height) / particles.density
        * particles.intensity)
        .max(0.0) as usize;
    let mut rand = DesktopArcRand::with_seed(0);
    let mut commands = Vec::with_capacity(total);

    for _ in 0..total {
        let scl = rand.random_between(0.5, 1.0);
        let scl2 = rand.random_between(0.5, 1.0);
        let size = rand.random_between(particles.size_min, particles.size_max);
        let mut x = rand.random(DESKTOP_WEATHER_BOUND_MAX) + render_time * particles.windx * scl2;
        let mut y = rand.random(DESKTOP_WEATHER_BOUND_MAX) + render_time * particles.windy * scl;
        let alpha = rand.random_between(particles.min_alpha, particles.max_alpha);
        let rotation = if particles.random_particle_rotation {
            rand.random(360.0)
        } else {
            0.0
        };

        x += desktop_weather_particle_sin(
            y,
            rand.random_between(particles.sin_scl_min, particles.sin_scl_max),
            rand.random_between(particles.sin_mag_min, particles.sin_mag_max),
        );
        x = (x - particle_rect.x).rem_euclid(particle_rect.width) + particle_rect.x;
        y = (y - particle_rect.y).rem_euclid(particle_rect.height) + particle_rect.y;

        let rect = RenderRect::from_center(RenderPoint::new(x, y), size, size);
        if !rect.intersects(camera_rect) {
            continue;
        }

        commands.push(RenderCommand::draw_sprite(
            particles.region.clone(),
            rect,
            rgba8888_to_render_color(particles.color_rgba, alpha * particles.opacity),
            rotation,
            Layer::WEATHER,
        ));
    }

    commands
}

fn desktop_weather_virtual_source_paths(content_loader: &ContentLoader) -> Vec<String> {
    let mut paths = Vec::new();

    for weather in content_loader.weathers() {
        match weather {
            WeatherContent::Rain(rain) => {
                paths.extend(
                    desktop_weather_splash_regions(&rain.splashes)
                        .into_iter()
                        .map(|splash| format!("sprites/{splash}.png")),
                );
            }
            WeatherContent::Particle(particle) => {
                paths.push(format!("sprites/{}.png", particle.particle_region));
                if particle.draw_noise {
                    paths.push(format!("sprites/{}.png", particle.noise_path));
                }
            }
        }
    }

    paths
}

fn desktop_block_full_icon_region_content_id(region: &str) -> Option<ContentId> {
    region
        .strip_prefix("block-fullIcon:")
        .and_then(|id| id.parse::<ContentId>().ok())
}

fn desktop_world_label_align(align: WorldLabelAlign) -> RenderTextAlign {
    match align {
        WorldLabelAlign::Left => RenderTextAlign::Start,
        WorldLabelAlign::Center => RenderTextAlign::Center,
        WorldLabelAlign::Right => RenderTextAlign::End,
    }
}

fn desktop_world_label_text_size(font_size: f32) -> f32 {
    (font_size.max(0.0) * 12.0).max(1.0)
}

fn desktop_world_label_background_rect(
    text: &str,
    position: RenderPoint,
    font_size: f32,
) -> RenderRect {
    let width = (text.len() as f32 * 10.0 * font_size.max(0.0)).max(1.0) + 8.0;
    let height = desktop_world_label_text_size(font_size) + 6.0;
    RenderRect::from_center(position, width, height)
}

fn minimap_overlay_world_to_screen(
    plan: &MinimapOverlayPlan,
    screen_rect: RenderRect,
    x: f32,
    y: f32,
) -> Option<RenderPoint> {
    if plan.world_rect.width <= f32::EPSILON
        || plan.world_rect.height <= f32::EPSILON
        || screen_rect.width <= f32::EPSILON
        || screen_rect.height <= f32::EPSILON
    {
        return None;
    }
    Some(RenderPoint::new(
        screen_rect.x + ((x - plan.world_rect.x) / plan.world_rect.width) * screen_rect.width,
        screen_rect.y + ((y - plan.world_rect.y) / plan.world_rect.height) * screen_rect.height,
    ))
}

fn minimap_overlay_world_len_to_screen(plan: &MinimapOverlayPlan, value: f32) -> f32 {
    if plan.scale_factor <= f32::EPSILON {
        value.max(1.0)
    } else {
        (value / plan.scale_factor).max(1.0)
    }
}

fn minimap_overlay_lerp_color(from: u32, to: u32, progress: f32) -> [f32; 4] {
    let from = rgba8888_to_render_color(from, 1.0);
    let to = rgba8888_to_render_color(to, 1.0);
    let progress = progress.clamp(0.0, 1.0);
    [
        from[0] + (to[0] - from[0]) * progress,
        from[1] + (to[1] - from[1]) * progress,
        from[2] + (to[2] - from[2]) * progress,
        from[3] + (to[3] - from[3]) * progress,
    ]
}

fn minimap_overlay_dark_color(rgba: u32) -> [f32; 4] {
    let mut color = rgba8888_to_render_color(rgba, 1.0);
    color[0] *= 0.25;
    color[1] *= 0.25;
    color[2] *= 0.25;
    color
}

fn minimap_overlay_world_rect_to_screen(
    plan: &MinimapOverlayPlan,
    screen_rect: RenderRect,
    rect: MinimapRect,
) -> Option<RenderRect> {
    let min = minimap_overlay_world_to_screen(plan, screen_rect, rect.x, rect.y)?;
    let max = minimap_overlay_world_to_screen(
        plan,
        screen_rect,
        rect.x + rect.width,
        rect.y + rect.height,
    )?;
    Some(RenderRect::new(min.x, min.y, max.x - min.x, max.y - min.y))
}

fn minimap_overlay_render_pass(
    plan: &MinimapOverlayPlan,
    screen_rect: RenderRect,
) -> Option<RenderPass> {
    if plan.commands.is_empty() {
        return None;
    }
    let mut pass = RenderPass::new(RenderPassKind::Minimap)
        .with_order(RenderPassKind::Minimap.default_order());
    for command in &plan.commands {
        match command {
            MinimapOverlayCommand::UnitIcon {
                x,
                y,
                rotation,
                team_color,
                region,
                scale,
                ..
            } => {
                let Some(center) = minimap_overlay_world_to_screen(plan, screen_rect, *x, *y)
                else {
                    continue;
                };
                let size = minimap_overlay_world_len_to_screen(plan, *scale);
                pass.push(RenderCommand::draw_sprite(
                    region.clone(),
                    RenderRect::from_center(center, size, size),
                    rgba8888_to_render_color(*team_color, 1.0),
                    *rotation,
                    Layer::END,
                ));
            }
            MinimapOverlayCommand::PlayerLabel {
                x,
                y,
                text,
                color,
                background,
                ..
            } => {
                let Some(position) = minimap_overlay_world_to_screen(plan, screen_rect, *x, *y)
                else {
                    continue;
                };
                if *background {
                    pass.push(RenderCommand::fill_rect(
                        RenderRect::from_center(
                            position,
                            (text.len() as f32 * 7.0).max(8.0) + 6.0,
                            14.0,
                        ),
                        [0.0, 0.0, 0.0, 0.45],
                        Layer::END - 0.02,
                    ));
                }
                pass.push(RenderCommand::draw_text_styled(
                    text.clone(),
                    position,
                    rgba8888_to_render_color(*color, 1.0),
                    10.0,
                    0.0,
                    RenderTextStyle::new(RenderTextAlign::Center)
                        .with_vertical_align(RenderTextVerticalAlign::Center)
                        .with_outline(true),
                    Layer::END,
                ));
            }
            MinimapOverlayCommand::Ping {
                x,
                y,
                name,
                text,
                color,
                ..
            } => {
                let Some(position) = minimap_overlay_world_to_screen(plan, screen_rect, *x, *y)
                else {
                    continue;
                };
                let dark_color = minimap_overlay_dark_color(*color);
                let ping_color = rgba8888_to_render_color(*color, 1.0);
                pass.push(RenderCommand::draw_polygon(
                    position,
                    12.0,
                    4,
                    0.0,
                    dark_color,
                    false,
                    Layer::END - 0.03,
                ));
                pass.push(RenderCommand::draw_polygon(
                    RenderPoint::new(position.x, position.y + 30.0),
                    16.0,
                    3,
                    -90.0,
                    dark_color,
                    true,
                    Layer::END - 0.02,
                ));
                pass.push(RenderCommand::draw_polygon(
                    position,
                    12.0,
                    4,
                    0.0,
                    ping_color,
                    false,
                    Layer::END - 0.01,
                ));
                pass.push(RenderCommand::draw_polygon(
                    RenderPoint::new(position.x, position.y + 30.0),
                    10.0,
                    3,
                    -90.0,
                    ping_color,
                    true,
                    Layer::END,
                ));
                let (name_y, name_size) = if text.is_some() {
                    (65.0, 7.0)
                } else {
                    (50.0, 10.0)
                };
                pass.push(RenderCommand::draw_text_styled(
                    name.clone(),
                    RenderPoint::new(position.x, position.y + name_y),
                    ping_color,
                    name_size,
                    0.0,
                    RenderTextStyle::new(RenderTextAlign::Center)
                        .with_vertical_align(RenderTextVerticalAlign::Center)
                        .with_outline(true),
                    Layer::END,
                ));
                if let Some(text) = text {
                    pass.push(RenderCommand::draw_text_styled(
                        text.clone(),
                        RenderPoint::new(position.x, position.y + 50.0),
                        [1.0, 1.0, 1.0, 1.0],
                        10.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Center)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_outline(true),
                        Layer::END,
                    ));
                }
            }
            MinimapOverlayCommand::FogTexture {
                layer,
                color,
                alpha,
            } => {
                let layer_offset = match layer {
                    MinimapFogLayer::Dynamic => 0.0,
                    MinimapFogLayer::Static => 0.01,
                };
                pass.push(RenderCommand::fill_rect(
                    screen_rect,
                    rgba8888_to_render_color(*color, *alpha),
                    Layer::END - 0.5 + layer_offset,
                ));
            }
            MinimapOverlayCommand::Spawn {
                x,
                y,
                icon_region,
                icon_size,
                radius,
                pulse,
                team_color,
            } => {
                let Some(center) = minimap_overlay_world_to_screen(plan, screen_rect, *x, *y)
                else {
                    continue;
                };
                let color = rgba8888_to_render_color(*team_color, 1.0);
                let icon_size = minimap_overlay_world_len_to_screen(plan, *icon_size);
                pass.push(RenderCommand::draw_sprite(
                    icon_region.clone(),
                    RenderRect::from_center(center, icon_size, icon_size),
                    color,
                    0.0,
                    Layer::END - 0.02,
                ));
                let radius = minimap_overlay_world_len_to_screen(plan, *radius);
                pass.push(RenderCommand::draw_circle(
                    center,
                    radius,
                    color,
                    false,
                    Layer::END - 0.01,
                ));
                if *pulse > f32::EPSILON {
                    pass.push(RenderCommand::draw_circle(
                        center,
                        radius * *pulse,
                        color,
                        false,
                        Layer::END,
                    ));
                }
            }
            MinimapOverlayCommand::CameraBounds(rect) => {
                if let Some(rect) = minimap_overlay_world_rect_to_screen(plan, screen_rect, *rect) {
                    pass.push(RenderCommand::stroke_rect(
                        rect,
                        [1.0, 1.0, 1.0, 0.85],
                        1.0,
                        Layer::END,
                    ));
                }
            }
            MinimapOverlayCommand::Indicator {
                x,
                y,
                radius,
                alpha,
                color_from,
                color_to,
                ..
            } => {
                let Some(center) = minimap_overlay_world_to_screen(plan, screen_rect, *x, *y)
                else {
                    continue;
                };
                pass.push(RenderCommand::draw_circle(
                    center,
                    minimap_overlay_world_len_to_screen(plan, *radius),
                    minimap_overlay_lerp_color(*color_from, *color_to, *alpha),
                    false,
                    Layer::END,
                ));
            }
            MinimapOverlayCommand::Marker { x, y, label, .. } => {
                let Some(position) = minimap_overlay_world_to_screen(plan, screen_rect, *x, *y)
                else {
                    continue;
                };
                pass.push(RenderCommand::draw_text_styled(
                    label.clone(),
                    position,
                    [1.0, 1.0, 1.0, 1.0],
                    10.0,
                    0.0,
                    RenderTextStyle::new(RenderTextAlign::Center)
                        .with_vertical_align(RenderTextVerticalAlign::Center)
                        .with_outline(true),
                    Layer::END,
                ));
            }
        }
    }
    (!pass.commands.is_empty()).then_some(pass)
}

impl DesktopStandardEffectRenderFrame {
    pub fn to_light_render_pass(&self) -> Option<RenderPass> {
        let circle_lights = self
            .light_primitives
            .iter()
            .filter(|primitive| primitive.radius > f32::EPSILON && primitive.opacity > 0.0)
            .map(|primitive| LightPrimitive {
                center: primitive.center,
                radius: primitive.radius,
                color: primitive.color_rgba.unwrap_or(DecalColor::WHITE),
                opacity: primitive.opacity,
            })
            .collect::<Vec<_>>();
        if circle_lights.is_empty() {
            return None;
        }
        LightRendererPlan {
            circle_lights,
            commands: Vec::new(),
        }
        .to_render_pass()
    }

    pub fn to_render_pass(&self) -> Option<RenderPass> {
        let mut pass = RenderPass::new(RenderPassKind::Overlay);
        for primitive in &self.circle_primitives {
            if primitive.radius <= f32::EPSILON {
                continue;
            }
            let filled = matches!(
                primitive.kind,
                StandardEffectDrawKind::FilledCircle
                    | StandardEffectDrawKind::SeededCircleParticles
            );
            pass.push(RenderCommand::draw_circle(
                RenderPoint::new(primitive.center.0, primitive.center.1),
                primitive.radius,
                desktop_effect_render_color(primitive.color, primitive.alpha),
                filled,
                Layer::EFFECT,
            ));
        }
        for primitive in &self.line_primitives {
            if primitive.length <= f32::EPSILON || primitive.stroke <= f32::EPSILON {
                continue;
            }
            let angle = primitive.angle.to_radians();
            let from = RenderPoint::new(primitive.start.0, primitive.start.1);
            let to = RenderPoint::new(
                primitive.start.0 + angle.cos() * primitive.length,
                primitive.start.1 + angle.sin() * primitive.length,
            );
            if let Some(region) = &primitive.region {
                let rect = RenderRect::from_center(
                    RenderPoint::new((from.x + to.x) * 0.5, (from.y + to.y) * 0.5),
                    primitive.length,
                    primitive.stroke,
                );
                pass.push(RenderCommand::draw_sprite(
                    region.clone(),
                    rect,
                    desktop_effect_render_color(primitive.color, primitive.alpha),
                    primitive.angle,
                    Layer::EFFECT,
                ));
                continue;
            }
            pass.push(RenderCommand::draw_line(
                from,
                to,
                primitive.stroke,
                desktop_effect_render_color(primitive.color, primitive.alpha),
                Layer::EFFECT,
            ));
        }
        for primitive in &self.square_primitives {
            if primitive.radius <= f32::EPSILON {
                continue;
            }
            pass.push(RenderCommand::draw_polygon(
                RenderPoint::new(primitive.center.0, primitive.center.1),
                primitive.radius * std::f32::consts::SQRT_2,
                4,
                primitive.rotation + 45.0,
                desktop_effect_render_color(primitive.color, primitive.alpha),
                primitive.stroke <= f32::EPSILON,
                Layer::EFFECT,
            ));
        }
        for primitive in &self.rect_primitives {
            if primitive.width <= f32::EPSILON || primitive.height <= f32::EPSILON {
                continue;
            }
            let rect = RenderRect::from_center(
                RenderPoint::new(primitive.center.0, primitive.center.1),
                primitive.width,
                primitive.height,
            );
            let color = desktop_effect_render_color(primitive.color, primitive.alpha);
            match (&primitive.kind, &primitive.region) {
                (StandardEffectDrawKind::TexturedRect, Some(region))
                    if region.starts_with("block-fullIcon:") =>
                {
                    if let Some(symbol) = desktop_block_full_icon_region_content_id(region)
                        .and_then(|id| self.block_full_icon_regions.get(&id))
                    {
                        pass.push(RenderCommand::draw_sprite(
                            symbol.clone(),
                            rect,
                            color,
                            primitive.rotation,
                            Layer::EFFECT,
                        ));
                    }
                }
                (StandardEffectDrawKind::TexturedRect, Some(region))
                    if !region.starts_with("block-fullIcon:") =>
                {
                    pass.push(RenderCommand::draw_sprite(
                        region.clone(),
                        rect,
                        color,
                        primitive.rotation,
                        Layer::EFFECT,
                    ));
                }
                (StandardEffectDrawKind::FilledRect, _)
                    if primitive.rotation.abs() <= f32::EPSILON =>
                {
                    pass.push(RenderCommand::fill_rect(rect, color, Layer::EFFECT));
                }
                _ => {}
            }
        }
        for primitive in &self.triangle_primitives {
            if primitive.width <= f32::EPSILON || primitive.length <= f32::EPSILON {
                continue;
            }
            pass.push(RenderCommand::draw_triangle(
                RenderPoint::new(primitive.center.0, primitive.center.1),
                primitive.width,
                primitive.length,
                primitive.rotation,
                desktop_effect_render_color(primitive.color, primitive.alpha),
                Layer::EFFECT,
            ));
        }
        (!pass.commands.is_empty()).then_some(pass)
    }
}

