pub trait DesktopGraphicsRenderer {
    fn render_graphics_frame(&mut self, frame: &DesktopGraphicsFrame) -> GraphicsFrameStats;

    fn render_graphics_frame_for_surface(
        &mut self,
        frame: &DesktopGraphicsFrame,
        _effect_buffer_surface: DesktopGraphicsEffectBufferSurface,
    ) -> GraphicsFrameStats {
        self.render_graphics_frame(frame)
    }
}

#[derive(Debug, Clone, Default, PartialEq)]
pub struct HeadlessDesktopGraphicsRenderer {
    pub frames_rendered: usize,
    pub last_stats: GraphicsFrameStats,
    pub last_execution: DesktopGraphicsExecutionSummary,
    pub last_trace: DesktopGraphicsExecutionTrace,
    pub last_opengl_backend_plan: DesktopGraphicsOpenGlBackendFramePlan,
    pub last_opengl_backend_execution_state: DesktopGraphicsOpenGlBackendExecutionState,
    pub last_opengl_backend_executor_state: DesktopGraphicsOpenGlBackendExecutorState,
    pub last_live_backend_state: DesktopGraphicsLiveBackendExecutionState,
}

impl DesktopGraphicsRenderer for HeadlessDesktopGraphicsRenderer {
    fn render_graphics_frame(&mut self, frame: &DesktopGraphicsFrame) -> GraphicsFrameStats {
        self.render_graphics_frame_with_effect_buffer_surface(frame, None)
    }

    fn render_graphics_frame_for_surface(
        &mut self,
        frame: &DesktopGraphicsFrame,
        effect_buffer_surface: DesktopGraphicsEffectBufferSurface,
    ) -> GraphicsFrameStats {
        self.render_graphics_frame_with_effect_buffer_surface(frame, Some(effect_buffer_surface))
    }
}

impl HeadlessDesktopGraphicsRenderer {
    fn render_graphics_frame_with_effect_buffer_surface(
        &mut self,
        frame: &DesktopGraphicsFrame,
        effect_buffer_surface: Option<DesktopGraphicsEffectBufferSurface>,
    ) -> GraphicsFrameStats {
        let stats = frame.stats().clone();
        let trace = DesktopGraphicsExecutionTrace::from_frame(frame);
        let opengl_backend_plan =
            DesktopGraphicsOpenGlBackendFramePlan::from_frame_with_effect_buffer_surface(
                frame,
                effect_buffer_surface,
            );
        let execution = DesktopGraphicsExecutionSummary::from_trace(frame, &trace);
        let mut opengl_backend_step_sink = DesktopGraphicsOpenGlBackendExecutor::default();
        opengl_backend_plan.drive_framebuffer_attachment_sink(&mut opengl_backend_step_sink);
        let opengl_backend_execution_state =
            opengl_backend_plan.drive_step_sink(&mut opengl_backend_step_sink);
        opengl_backend_step_sink
            .state
            .sprite_texture_upload_plans
            .extend(opengl_backend_plan.texture_upload_plans.clone());
        let mut live_backend_sink = DesktopGraphicsNullLiveBackendDrawSpriteSink;
        let mut block_particle_sink = DesktopGraphicsNullLiveBackendBlockParticleSink;
        let mut block_particle_draw_call_sink =
            DesktopGraphicsNullLiveBackendBlockParticleDrawCallSink;
        let mut render_command_sink = DesktopGraphicsNullLiveBackendRenderCommandSink;
        let mut render_target_sink = DesktopGraphicsNullLiveBackendRenderTargetSink;
        let live_backend_state = trace.drive_live_backend_sinks(
            &mut live_backend_sink,
            &mut block_particle_sink,
            &mut block_particle_draw_call_sink,
            &mut render_command_sink,
            &mut render_target_sink,
        );
        self.frames_rendered += 1;
        self.last_stats = stats.clone();
        self.last_execution = execution;
        self.last_trace = trace;
        self.last_opengl_backend_plan = opengl_backend_plan;
        self.last_opengl_backend_execution_state = opengl_backend_execution_state;
        self.last_opengl_backend_executor_state = opengl_backend_step_sink.state;
        self.last_live_backend_state = live_backend_state;
        stats
    }
}

#[cfg(feature = "opengl-backend")]
#[derive(Debug, Clone, PartialEq)]
pub struct DesktopOpenGlBackendGraphicsRenderer<R> {
    pub runtime: R,
    pub frames_rendered: usize,
    pub sprite_texture_resource_table: DesktopGraphicsOpenGlBackendTextureResourceTable,
    pub submitted_frame_texture_generations: BTreeMap<String, u64>,
    pub resolver_allocator: DesktopGraphicsOpenGlBackendHandleAllocator,
    pub resolver_cache: DesktopGraphicsOpenGlBackendHandleCache,
    pub resolver_location_cache: DesktopGraphicsOpenGlBackendLocationCache,
    pub last_stats: GraphicsFrameStats,
    pub last_opengl_backend_plan: DesktopGraphicsOpenGlBackendFramePlan,
    pub last_opengl_backend_execution_state: DesktopGraphicsOpenGlBackendExecutionState,
    pub last_resolved_command_executor_state:
        DesktopGraphicsOpenGlBackendResolvedCommandExecutorState,
    pub last_driver_state: DesktopGraphicsOpenGlBackendDriverExecutionState,
    pub last_effect_buffer_surface: Option<DesktopGraphicsEffectBufferSurface>,
}

#[cfg(feature = "opengl-backend")]
impl<R> DesktopOpenGlBackendGraphicsRenderer<R> {
    pub fn new(runtime: R) -> Self {
        Self {
            runtime,
            frames_rendered: 0,
            sprite_texture_resource_table:
                DesktopGraphicsOpenGlBackendTextureResourceTable::default(),
            submitted_frame_texture_generations: BTreeMap::new(),
            resolver_allocator: DesktopGraphicsOpenGlBackendHandleAllocator::default(),
            resolver_cache: DesktopGraphicsOpenGlBackendHandleCache::default(),
            resolver_location_cache: DesktopGraphicsOpenGlBackendLocationCache::default(),
            last_stats: GraphicsFrameStats::default(),
            last_opengl_backend_plan: DesktopGraphicsOpenGlBackendFramePlan::default(),
            last_opengl_backend_execution_state:
                DesktopGraphicsOpenGlBackendExecutionState::default(),
            last_resolved_command_executor_state:
                DesktopGraphicsOpenGlBackendResolvedCommandExecutorState::default(),
            last_driver_state: DesktopGraphicsOpenGlBackendDriverExecutionState::default(),
            last_effect_buffer_surface: None,
        }
    }

    pub fn runtime(&self) -> &R {
        &self.runtime
    }

    pub fn runtime_mut(&mut self) -> &mut R {
        &mut self.runtime
    }

    fn is_reusable_full_frame_texture_upload(
        recreate_texture: bool,
        kind: DesktopGraphicsOpenGlBackendTextureUploadKind,
    ) -> bool {
        recreate_texture
            && matches!(
                kind,
                DesktopGraphicsOpenGlBackendTextureUploadKind::FullPage
            )
    }

    fn retain_pending_frame_texture_uploads(
        &self,
        plan: &mut DesktopGraphicsOpenGlBackendFramePlan,
    ) {
        plan.texture_upload_plans.retain(|upload| {
            if !Self::is_reusable_full_frame_texture_upload(upload.recreate_texture, upload.kind) {
                return true;
            }
            self.submitted_frame_texture_generations
                .get(&upload.texture_key)
                .map(|submitted_generation| *submitted_generation < upload.generation)
                .unwrap_or(true)
        });
    }

    fn remember_resolved_frame_texture_uploads(
        &mut self,
        uploads: &[DesktopGraphicsOpenGlBackendResolvedTextureUpload],
    ) {
        for upload in uploads {
            if Self::is_reusable_full_frame_texture_upload(upload.recreate_texture, upload.kind) {
                self.submitted_frame_texture_generations
                    .insert(upload.texture_key.clone(), upload.generation);
            }
        }
    }
}

#[cfg(feature = "opengl-backend")]
impl<R> Default for DesktopOpenGlBackendGraphicsRenderer<R>
where
    R: Default,
{
    fn default() -> Self {
        Self::new(R::default())
    }
}

#[cfg(feature = "opengl-backend")]
impl<R> DesktopGraphicsRenderer for DesktopOpenGlBackendGraphicsRenderer<R>
where
    R: DesktopGraphicsOpenGlBackendRuntime,
{
    fn render_graphics_frame(&mut self, frame: &DesktopGraphicsFrame) -> GraphicsFrameStats {
        self.render_graphics_frame_with_effect_buffer_surface(frame, None)
    }

    fn render_graphics_frame_for_surface(
        &mut self,
        frame: &DesktopGraphicsFrame,
        effect_buffer_surface: DesktopGraphicsEffectBufferSurface,
    ) -> GraphicsFrameStats {
        self.render_graphics_frame_with_effect_buffer_surface(frame, Some(effect_buffer_surface))
    }
}

#[cfg(feature = "opengl-backend")]
impl<R> DesktopOpenGlBackendGraphicsRenderer<R>
where
    R: DesktopGraphicsOpenGlBackendRuntime,
{
    fn render_graphics_frame_with_effect_buffer_surface(
        &mut self,
        frame: &DesktopGraphicsFrame,
        effect_buffer_surface: Option<DesktopGraphicsEffectBufferSurface>,
    ) -> GraphicsFrameStats {
        desktop_runtime_trace("opengl.renderer: begin");
        if let Some(surface) = effect_buffer_surface {
            self.runtime.resize_surface(surface.size);
        }

        let stats = frame.stats().clone();
        let trace_renderer = desktop_runtime_trace_enabled();
        if trace_renderer {
            desktop_runtime_trace(format!(
                "opengl.renderer: frame stats passes={} commands={}",
                stats.render_passes, stats.render_commands
            ));
        }
        let mut opengl_backend_plan =
            DesktopGraphicsOpenGlBackendFramePlan::from_frame_with_effect_buffer_surface(
                frame,
                effect_buffer_surface,
            );
        self.retain_pending_frame_texture_uploads(&mut opengl_backend_plan);
        if trace_renderer {
            desktop_runtime_trace(format!(
                "opengl.renderer: backend plan steps={} texture_uploads={}",
                opengl_backend_plan.steps.len(),
                opengl_backend_plan.texture_upload_plans.len()
            ));
        }
        let mut opengl_backend_step_sink = DesktopGraphicsOpenGlBackendExecutor::default();
        opengl_backend_step_sink.state.sprite_texture_resource_table =
            self.sprite_texture_resource_table.clone();
        opengl_backend_plan.drive_framebuffer_attachment_sink(&mut opengl_backend_step_sink);
        let opengl_backend_execution_state =
            opengl_backend_plan.drive_step_sink(&mut opengl_backend_step_sink);
        if trace_renderer {
            desktop_runtime_trace(format!(
                "opengl.renderer: backend executor commands={}",
                opengl_backend_step_sink.state.draw_commands.len()
            ));
        }
        opengl_backend_step_sink
            .state
            .sprite_texture_upload_plans
            .extend(opengl_backend_plan.texture_upload_plans.clone());

        let mut resolving_executor = DesktopGraphicsResolvingOpenGlBackendCommandExecutor {
            allocator: self.resolver_allocator.clone(),
            cache: self.resolver_cache.clone(),
            location_cache: self.resolver_location_cache.clone(),
            ..Default::default()
        };
        let resolved_command_executor_state =
            opengl_backend_step_sink.drive_resolving_command_executor(&mut resolving_executor);
        let mut next_sprite_texture_resource_table = opengl_backend_step_sink
            .state
            .sprite_texture_resource_table
            .clone();
        next_sprite_texture_resource_table
            .apply_resolved_uploads(resolving_executor.resolved_texture_uploads.clone());
        if trace_renderer {
            desktop_runtime_trace(format!(
                "opengl.renderer: resolved draw_commands={} shader_commands={}",
                resolving_executor.draw_commands.len(),
                resolving_executor.resolved_shader_commands.len()
            ));
        }
        let driver_state = self.runtime.submit_resolving_executor(&resolving_executor);
        self.runtime.present_frame();

        self.frames_rendered += 1;
        self.remember_resolved_frame_texture_uploads(&resolving_executor.resolved_texture_uploads);
        self.sprite_texture_resource_table = next_sprite_texture_resource_table;
        self.resolver_allocator = resolving_executor.allocator.clone();
        self.resolver_cache = resolving_executor.cache.clone();
        self.resolver_location_cache = resolving_executor.location_cache.clone();
        self.last_stats = stats.clone();
        self.last_opengl_backend_plan = opengl_backend_plan;
        self.last_opengl_backend_execution_state = opengl_backend_execution_state;
        self.last_resolved_command_executor_state = resolved_command_executor_state;
        self.last_driver_state = driver_state;
        self.last_effect_buffer_surface = effect_buffer_surface;
        stats
    }
}

