    #[cfg(test)]
    fn default_menu_frame_input_for_viewport(viewport: RenderViewport) -> MenuFrameInput {
        MenuFrameInput {
            graphics_width: viewport.width.max(1.0),
            graphics_height: viewport.height.max(1.0),
            scene_margin_top: 0.0,
            scene_margin_bottom: 0.0,
            scl4: 4.0,
            delta: 1.0 / 60.0,
        }
    }

    fn menu_frame_input_for_viewport(&self, viewport: RenderViewport) -> MenuFrameInput {
        MenuFrameInput {
            graphics_width: viewport.width.max(1.0),
            graphics_height: viewport.height.max(1.0),
            scene_margin_top: self.menu_scene_margin_top,
            scene_margin_bottom: self.menu_scene_margin_bottom,
            scl4: 4.0 * self.menu_ui_scale.max(0.01),
            delta: self.menu_frame_delta_seconds.clamp(1.0 / 240.0, 0.25),
        }
    }

    fn fast_menu_render_pass_from_plan(
        &self,
        plan: &MenuFramePlan,
        viewport: RenderViewport,
    ) -> RenderPass {
        let camera = self.default_render_camera_for_viewport(viewport);
        let width = viewport.width.max(1.0);
        let height = viewport.height.max(1.0);
        let mut pass = RenderPass::new(RenderPassKind::Custom("menu-fast".to_string()))
            .with_viewport(viewport)
            .with_camera(camera);

        pass.push(RenderCommand::custom(
            "menu-fast-background",
            vec![
                RenderProperty::new("reason", "native-fast-path-before-menu-world-batching"),
                RenderProperty::new("width", width.to_string()),
                RenderProperty::new("height", height.to_string()),
            ],
        ));
        pass.push(RenderCommand::clear([0.018, 0.024, 0.036, 1.0]));
        pass.extend(self.menu_background_layer_commands(viewport));
        pass.extend(plan.ui.to_render_commands());
        pass
    }

    fn menu_button_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<MenuButtonRole> {
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let input = self.menu_frame_input_for_viewport(viewport);
        self.menu_renderer_state.hit_test_ui(input, x, y)
    }

    fn menu_input_event_from_window_space(
        surface_size: DesktopSurfaceSize,
        input: &DesktopInputTickEvent,
    ) -> DesktopInputTickEvent {
        // Winit cursor events are window-space (origin at top-left); all menu and route-shell hit
        // tests below this point use Mindustry/Scene2D-style surface-space (origin at bottom-left).
        // MouseButton carries no position, so only CursorMoved is flipped here; never flip again in
        // `apply_menu_input_events` or route-specific `*_at_surface_point` helpers.
        match input {
            DesktopInputTickEvent::CursorMoved { x, y } => DesktopInputTickEvent::CursorMoved {
                x: *x,
                y: surface_size.height as f32 - *y,
            },
            _ => input.clone(),
        }
    }

    fn menu_chrome_action_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuChromeAction> {
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let chrome = self.current_menu_chrome_layout_for_viewport(viewport);
        chrome.action_at_point(RenderPoint::new(x, y))
    }

    fn is_primary_menu_mouse_button(button: &str) -> bool {
        matches!(
            button,
            "left" | "Left" | "primary" | "Primary" | "MouseLeft" | "mouse-left" | "0"
        )
    }

    fn is_secondary_menu_mouse_button(button: &str) -> bool {
        matches!(
            button,
            "right" | "Right" | "secondary" | "Secondary" | "MouseRight" | "mouse-right" | "1"
        )
    }

    fn is_menu_back_key(key_code: &str) -> bool {
        matches!(
            key_code,
            "Escape" | "Esc" | "Back" | "AndroidBack" | "BrowserBack"
        )
    }

    fn is_shift_key_code(key_code: &str) -> bool {
        matches!(
            key_code,
            "Shift" | "shift" | "ShiftLeft" | "shiftLeft" | "ShiftRight" | "shiftRight"
        )
    }

    fn menu_role_requires_play_guard(role: MenuButtonRole) -> bool {
        matches!(
            role,
            MenuButtonRole::Campaign
                | MenuButtonRole::CustomGame
                | MenuButtonRole::LoadGame
                | MenuButtonRole::Editor
        )
    }

    fn block_menu_action_for_content_errors(&mut self, role: MenuButtonRole) -> bool {
        if !Self::menu_role_requires_play_guard(role) || !self.content_loader.has_content_errors() {
            return false;
        }
        self.active_menu_route = None;
        if role == MenuButtonRole::Campaign {
            self.campaign_planet_dialog = None;
        }
        self.last_menu_route_shell_action = None;
        self.last_menu_guard_message = Some(MENU_PLAY_GUARD_MESSAGE.into());
        true
    }

    fn apply_menu_back_key(&mut self) -> bool {
        if self.has_renderable_world_for_default_frame()
            && self.game_state.is_paused()
            && self.active_menu_route.is_none()
        {
            self.game_state.set(GameStateState::Playing);
            self.last_menu_route_shell_action = None;
            return true;
        }
        if self.menu_mobile_terminal_open {
            self.menu_mobile_terminal_open = false;
            self.last_menu_chrome_action = None;
            return true;
        }
        if self.save_game_pending_save.is_some() {
            self.last_menu_route_shell_action = None;
            return true;
        }
        if self.load_game_pending_load.is_some() {
            self.last_menu_route_shell_action = None;
            return true;
        }
        if self.join_route_loadfrag_visible() {
            self.dispatch_menu_route_shell_action(DesktopMenuRouteShellAction::CancelJoinConnect);
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::Join)
            && self.join_connection_error_dialog_message.is_some()
        {
            self.dispatch_menu_route_shell_action(
                DesktopMenuRouteShellAction::CloseJoinConnectionError,
            );
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::Join)
            && self.join_version_mismatch_dialog_message.is_some()
        {
            self.dispatch_menu_route_shell_action(
                DesktopMenuRouteShellAction::CloseJoinVersionMismatch,
            );
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::Settings) {
            let action = if self.last_settings_rebind_key.is_some() {
                DesktopSettingsAction::CancelKeyRebind
            } else if self.settings_planet_chooser_open {
                DesktopSettingsAction::ClosePlanetChooser
            } else if self.settings_child_dialog.is_some() {
                DesktopSettingsAction::CloseChildDialog
            } else {
                DesktopSettingsAction::BackToMain
            };
            self.dispatch_menu_route_shell_action(DesktopMenuRouteShellAction::Settings(action));
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::Database)
            && self.last_database_content_opened.is_some()
        {
            self.last_database_content_opened = None;
            self.database_search_focused = false;
            self.last_menu_route_shell_action =
                Some(DesktopMenuRouteShellAction::CloseDatabaseContent);
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::About)
            && self.about_route_page == DesktopAboutRoutePage::Credits
        {
            self.about_route_page = DesktopAboutRoutePage::Links;
            self.last_menu_route_shell_action = None;
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::Mods) && self.mods_browser_dialog_open {
            self.mods_browser_dialog_open = false;
            self.last_menu_route_shell_action = Some(DesktopMenuRouteShellAction::CloseModsBrowser);
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::Mods)
            && self.mods_delete_dialog_index.is_some()
        {
            self.mods_delete_dialog_index = None;
            self.last_menu_route_shell_action = Some(DesktopMenuRouteShellAction::CancelModsDelete);
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::LoadGame)
            && self.load_game_rename_dialog_slot.is_some()
        {
            self.load_game_rename_dialog_slot = None;
            self.load_game_rename_text.clear();
            self.last_menu_route_shell_action =
                Some(DesktopMenuRouteShellAction::LoadGameRenameCancel);
            return true;
        }
        if matches!(
            self.active_menu_route,
            Some(DesktopMenuRoute::LoadGame | DesktopMenuRoute::SaveGame)
        ) && self.load_game_delete_dialog_slot.is_some()
        {
            self.load_game_delete_dialog_slot = None;
            self.last_menu_route_shell_action =
                Some(DesktopMenuRouteShellAction::LoadGameDeleteCancel);
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::SaveGame)
            && self.save_game_new_dialog_open
        {
            self.save_game_new_dialog_open = false;
            self.save_game_new_text.clear();
            self.last_menu_route_shell_action =
                Some(DesktopMenuRouteShellAction::SaveGameNewCancel);
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::SaveGame)
            && self.save_game_overwrite_dialog_slot.is_some()
        {
            self.save_game_overwrite_dialog_slot = None;
            self.last_menu_route_shell_action =
                Some(DesktopMenuRouteShellAction::SaveGameOverwriteCancel);
            return true;
        }
        if self.active_menu_route == Some(DesktopMenuRoute::Editor)
            && (self.editor_import_overwrite_pending.is_some()
                || self.editor_import_error.is_some())
        {
            self.clear_editor_import_map_dialog();
            self.last_menu_route_shell_action =
                Some(DesktopMenuRouteShellAction::CancelEditorImportOverwrite);
            return true;
        }
        if matches!(
            self.active_menu_route,
            Some(DesktopMenuRoute::CustomGame | DesktopMenuRoute::Editor)
        ) && (self.map_play_dialog_index.is_some()
            || self.editor_map_info_dialog_index.is_some())
        {
            self.dispatch_menu_route_shell_action(DesktopMenuRouteShellAction::CloseMapCardDialog);
            return true;
        }
        if let Some(route) = self.active_menu_route.take() {
            if route == DesktopMenuRoute::Campaign {
                self.campaign_planet_dialog = None;
            }
            self.mods_selected_mod_index = None;
            self.mods_content_dialog_index = None;
            self.mods_delete_dialog_index = None;
            self.mods_import_dialog_open = false;
            self.mods_browser_dialog_open = false;
            self.mods_search_focused = false;
            self.mods_browser_search.clear();
            self.mods_browser_sort_date = false;
            self.tech_tree_select_dialog_open = false;
            self.tech_tree_selected_node = None;
            self.map_list_filter_dialog_open = false;
            self.map_list_planet_filter_dialog_open = false;
            self.map_list_search_focused = false;
            self.clear_editor_new_map_dialog();
            self.clear_editor_import_map_dialog();
            self.load_game_search_focused = false;
            self.last_database_content_opened = None;
            self.load_game_pending_load = None;
            self.load_game_rename_dialog_slot = None;
            self.load_game_delete_dialog_slot = None;
            self.load_game_rename_text.clear();
            self.join_add_dialog_open = false;
            self.join_add_server_focused = false;
            self.join_add_server_edit_index = None;
            self.join_info_dialog_open = false;
            self.join_version_mismatch_dialog_message = None;
            self.join_connection_error_dialog_message = None;
            self.join_reconnect_target = None;
            self.join_reconnect_receiver = None;
            self.join_delete_dialog_index = None;
            self.save_game_new_dialog_open = false;
            self.save_game_new_text.clear();
            self.save_game_overwrite_dialog_slot = None;
            self.save_game_pending_save = None;
            self.map_play_dialog_index = None;
            self.editor_map_info_dialog_index = None;
            self.last_menu_dispatch = None;
            self.last_menu_route_shell_action = None;
            return true;
        }
        if self.menu_renderer_state.selected_root != MenuButtonRole::Play
            || self.menu_renderer_state.has_active_desktop_submenu()
        {
            self.menu_renderer_state.reset_desktop_root();
            return true;
        }
        false
    }

    fn dispatch_menu_action(&mut self, role: MenuButtonRole) -> DesktopMenuActionDispatch {
        let submenu_was_active = self.menu_renderer_state.has_active_desktop_submenu();
        let role_opens_desktop_submenu = self.menu_renderer_state.role_has_desktop_submenu(role);
        let submenu_changed = self.menu_renderer_state.select_desktop_root(role);
        if submenu_was_active && !submenu_changed && !role_opens_desktop_submenu {
            self.menu_renderer_state.reset_desktop_root();
        }
        self.last_menu_guard_message = None;
        self.last_menu_info_message = None;
        self.last_custom_menu_action = None;
        if role == MenuButtonRole::Workshop {
            self.dispatch_menu_platform_action(DesktopMenuPlatformAction::OpenWorkshop);
            self.active_menu_route = None;
            self.mods_selected_mod_index = None;
            self.mods_content_dialog_index = None;
            self.mods_delete_dialog_index = None;
            self.mods_import_dialog_open = false;
            self.mods_browser_dialog_open = false;
            self.mods_search_focused = false;
            self.mods_browser_search.clear();
            self.mods_browser_sort_date = false;
            self.tech_tree_select_dialog_open = false;
            self.tech_tree_selected_node = None;
            self.map_list_filter_dialog_open = false;
            self.map_list_planet_filter_dialog_open = false;
            self.map_list_search_focused = false;
            self.clear_editor_new_map_dialog();
            self.clear_editor_import_map_dialog();
            self.load_game_search_focused = false;
            self.map_play_dialog_index = None;
            self.editor_map_info_dialog_index = None;
            let dispatch = DesktopMenuActionDispatch {
                role,
                submenu_changed,
                route: None,
                close_requested: false,
            };
            self.last_menu_dispatch = Some(dispatch);
            return dispatch;
        }
        if !submenu_changed {
            if let Some((label, action_id)) = self
                .menu_renderer_state
                .custom_button(role)
                .map(|custom| (custom.label.clone(), custom.action_id.clone()))
            {
                self.active_menu_route = None;
                self.mods_selected_mod_index = None;
                self.mods_content_dialog_index = None;
                self.mods_delete_dialog_index = None;
                self.mods_import_dialog_open = false;
                self.mods_browser_dialog_open = false;
                self.mods_browser_search.clear();
                self.mods_browser_sort_date = false;
                self.tech_tree_selected_node = None;
                self.map_list_planet_filter_dialog_open = false;
                self.map_list_search_focused = false;
                self.clear_editor_new_map_dialog();
                self.clear_editor_import_map_dialog();
                self.load_game_search_focused = false;
                self.map_play_dialog_index = None;
                self.editor_map_info_dialog_index = None;
                self.last_custom_menu_action = Some(DesktopCustomMenuAction {
                    role,
                    label,
                    action_id,
                });
                let dispatch = DesktopMenuActionDispatch {
                    role,
                    submenu_changed,
                    route: None,
                    close_requested: false,
                };
                self.last_menu_dispatch = Some(dispatch);
                return dispatch;
            }
        }
        if self.block_menu_action_for_content_errors(role) {
            let dispatch = DesktopMenuActionDispatch {
                role,
                submenu_changed,
                route: None,
                close_requested: false,
            };
            self.last_menu_dispatch = Some(dispatch);
            return dispatch;
        }
        let route = if submenu_changed {
            self.active_menu_route = None;
            self.mods_selected_mod_index = None;
            self.mods_content_dialog_index = None;
            self.mods_delete_dialog_index = None;
            self.mods_import_dialog_open = false;
            self.mods_browser_dialog_open = false;
            self.mods_search_focused = false;
            self.mods_browser_search.clear();
            self.mods_browser_sort_date = false;
            self.tech_tree_select_dialog_open = false;
            self.tech_tree_selected_node = None;
            self.map_list_filter_dialog_open = false;
            self.map_list_planet_filter_dialog_open = false;
            self.map_list_search_focused = false;
            self.clear_editor_new_map_dialog();
            self.clear_editor_import_map_dialog();
            self.load_game_search_focused = false;
            self.map_play_dialog_index = None;
            self.editor_map_info_dialog_index = None;
            None
        } else {
            DesktopMenuRoute::from_menu_button(role)
        };
        if let Some(route) = route {
            self.active_menu_route = Some(route);
            self.mods_selected_mod_index = None;
            self.mods_content_dialog_index = None;
            self.mods_delete_dialog_index = None;
            self.mods_import_dialog_open = false;
            self.mods_browser_dialog_open = false;
            self.mods_search_focused = false;
            self.mods_browser_search.clear();
            self.mods_browser_sort_date = false;
            self.tech_tree_select_dialog_open = false;
            self.tech_tree_selected_node = None;
            self.map_list_filter_dialog_open = false;
            self.map_list_planet_filter_dialog_open = false;
            self.map_list_search_focused = false;
            self.clear_editor_new_map_dialog();
            self.clear_editor_import_map_dialog();
            self.database_search_focused = false;
            self.map_play_dialog_index = None;
            self.editor_map_info_dialog_index = None;
            self.last_map_card_action = None;
            if route == DesktopMenuRoute::Campaign {
                self.campaign_planet_dialog = Some(CampaignPlanetDialogState::look(
                    &self.content_loader,
                    &self.game_state,
                ));
            } else if route == DesktopMenuRoute::About {
                self.about_route_page = DesktopAboutRoutePage::Links;
                self.about_links_scroll_offset = 0;
                self.about_credits_scroll_offset = 0;
            } else if route == DesktopMenuRoute::Mods {
                self.mods_search.clear();
                self.mods_search_focused = false;
            } else if matches!(
                route,
                DesktopMenuRoute::LoadGame | DesktopMenuRoute::SaveGame
            ) {
                self.refresh_load_game_slots();
                self.load_game_search.clear();
                self.load_game_search_focused = true;
                self.load_game_scroll_offset = 0;
                self.load_game_hidden_modes.clear();
                self.load_game_rename_dialog_slot = None;
                self.load_game_pending_load = None;
                self.load_game_delete_dialog_slot = None;
                self.load_game_rename_text.clear();
                self.save_game_new_dialog_open = false;
                self.save_game_new_text.clear();
                self.save_game_overwrite_dialog_slot = None;
                self.save_game_pending_save = None;
                self.load_game_error = None;
            } else if route == DesktopMenuRoute::Settings {
                self.settings_dialog_state = DesktopSettingsDialogState::default();
                self.settings_child_dialog = None;
                self.settings_planet_chooser_open = false;
                self.last_settings_action = None;
                self.last_settings_hovered_control = None;
                self.last_settings_pressed_control = None;
                self.settings_scroll_drag_state = None;
                self.settings_scroll_offsets.clear();
            } else if route == DesktopMenuRoute::Database {
                self.database_search.clear();
                self.database_search_focused = false;
                self.database_selected_tab = self.database_default_selected_tab_index();
                self.database_scroll_offset = 0;
                self.last_database_content_opened = None;
                self.last_database_icon_copy_action = None;
            } else if route == DesktopMenuRoute::Join {
                self.join_search.clear();
                self.join_search_focused = false;
                self.join_add_dialog_open = false;
                self.join_add_server_focused = false;
                self.join_add_server_edit_index = None;
                self.join_info_dialog_open = false;
                self.join_delete_dialog_index = None;
                self.join_server_disclaimer_pending_target = None;
                self.join_server_disclaimer_pending_version = None;
                self.ensure_join_community_server_cache_loaded();
                self.refresh_join_local_hosts();
            } else if route == DesktopMenuRoute::Schematics {
                self.load_schematic_tags_from_settings();
                self.schematic_search.clear();
                self.schematic_search_focused = true;
                self.schematic_info_dialog = None;
                self.schematic_modal = None;
                self.schematic_edit_name.clear();
                self.schematic_edit_description.clear();
                self.last_schematic_card_action = None;
                self.last_schematic_tag_toggled = None;
                self.last_schematic_modal_button = None;
            } else if matches!(
                route,
                DesktopMenuRoute::CustomGame | DesktopMenuRoute::Editor
            ) {
                self.load_map_list_filter_state_from_settings();
                self.map_list_search.clear();
                self.map_list_search_focused = true;
                self.map_list_scroll_offset = 0;
                self.last_map_card_action = None;
            }
        }
        let close_requested = role == MenuButtonRole::Quit;
        if close_requested {
            self.active_menu_route = None;
            self.mods_selected_mod_index = None;
            self.mods_import_dialog_open = false;
            self.mods_browser_dialog_open = false;
            self.mods_browser_search.clear();
            self.mods_browser_sort_date = false;
            self.tech_tree_selected_node = None;
            self.map_list_search_focused = false;
            self.clear_editor_new_map_dialog();
            self.clear_editor_import_map_dialog();
            self.load_game_search_focused = false;
            self.map_play_dialog_index = None;
            self.editor_map_info_dialog_index = None;
        }
        let dispatch = DesktopMenuActionDispatch {
            role,
            submenu_changed,
            route,
            close_requested,
        };
        self.last_menu_dispatch = Some(dispatch);
        dispatch
    }

    fn dispatch_menu_platform_action(&mut self, action: DesktopMenuPlatformAction) {
        match action {
            DesktopMenuPlatformAction::OpenWorkshop => {
                let mut platform = DefaultPlatform;
                platform.open_workshop();
                self.last_menu_platform_action = Some(DesktopMenuPlatformAction::OpenWorkshop);
            }
        }
    }

    fn dispatch_menu_chrome_action(&mut self, action: DesktopMenuChromeAction) {
        match action {
            DesktopMenuChromeAction::Discord => {
                self.active_menu_route = Some(DesktopMenuRoute::Discord);
                self.last_menu_route_shell_action = None;
                self.last_menu_chrome_action = Some(DesktopMenuChromeAction::Discord);
            }
            DesktopMenuChromeAction::MobileTerminalToggle => {
                self.menu_mobile_terminal_open = !self.menu_mobile_terminal_open;
                self.last_menu_chrome_action = Some(DesktopMenuChromeAction::MobileTerminalToggle);
            }
            DesktopMenuChromeAction::InfoOpenAbout => {
                self.active_menu_route = Some(DesktopMenuRoute::About);
                self.about_route_page = DesktopAboutRoutePage::Links;
                self.about_links_scroll_offset = 0;
                self.about_credits_scroll_offset = 0;
                self.last_menu_route_shell_action = None;
                self.last_menu_chrome_action = Some(DesktopMenuChromeAction::InfoOpenAbout);
            }
            DesktopMenuChromeAction::Becheck => {
                self.last_menu_info_message = Some(MENU_BECHECK_NO_UPDATES_MESSAGE.into());
                self.last_menu_chrome_action = Some(DesktopMenuChromeAction::Becheck);
            }
        }
        self.last_menu_action = None;
    }

    pub fn refresh_load_game_slots(&mut self) -> usize {
        let save_dir = PathBuf::from(&self.client.context.paths.save_dir);
        let entries = match std::fs::read_dir(&save_dir) {
            Ok(entries) => entries
                .filter_map(|entry| entry.ok().map(|entry| entry.path()))
                .collect::<Vec<_>>(),
            Err(error) if error.kind() == io::ErrorKind::NotFound => {
                self.load_game_slots.clear();
                self.load_game_error = None;
                return 0;
            }
            Err(error) => {
                self.load_game_slots.clear();
                self.load_game_error = Some(format!(
                    "failed to read save dir {}: {error}",
                    save_dir.display()
                ));
                return 0;
            }
        };

        let mut slots = collect_valid_save_slot_records(entries.iter(), |path| {
            let primary = std::fs::read(path)?;
            let backup_path = backup_file_for_path(path);
            let backup = std::fs::read(backup_path).ok();
            read_deflated_save_meta_with_backup(primary.as_slice(), backup.as_deref())
        });
        slots.sort_by(|a, b| {
            b.timestamp()
                .cmp(&a.timestamp())
                .then_with(|| a.index().cmp(&b.index()))
        });
        self.merge_load_game_preview_textures(&slots);
        let count = slots.len();
        self.load_game_slots = slots;
        self.load_game_error = None;
        count
    }

    fn load_game_preview_dir(&self) -> PathBuf {
        PathBuf::from(&self.client.context.paths.data_dir).join("previews")
    }

    fn load_game_slot_preview_symbol(slot: &SaveSlotRecord) -> String {
        format!("save_slot_{}", slot.index())
    }

    fn load_game_slot_preview_fallback_tint(slot: &SaveSlotRecord) -> [f32; 4] {
        let hash = slot.index().bytes().fold(0usize, |acc, byte| {
            acc.wrapping_mul(31).wrapping_add(byte as usize)
        });
        let color = HOST_PALETTE_COLORS[hash % HOST_PALETTE_COLORS.len()];
        let r = ((color >> 24) & 0xff) as f32 / 255.0;
        let g = ((color >> 16) & 0xff) as f32 / 255.0;
        let b = ((color >> 8) & 0xff) as f32 / 255.0;
        [
            (r * 0.42 + 0.22).min(0.92),
            (g * 0.42 + 0.22).min(0.92),
            (b * 0.42 + 0.22).min(0.92),
            0.96,
        ]
    }

    fn load_game_slot_preview_file_in_dir(
        slot: &SaveSlotRecord,
        preview_dir: &Path,
    ) -> Option<PathBuf> {
        let preview = slot.preview_file(preview_dir);
        preview.exists().then_some(preview)
    }

    fn load_game_slot_preview_symbol_if_loaded(&self, slot: &SaveSlotRecord) -> Option<String> {
        let symbol = Self::load_game_slot_preview_symbol(slot);
        self.texture_atlas.has(&symbol).then_some(symbol)
    }

    fn merge_load_game_preview_textures(&mut self, slots: &[SaveSlotRecord]) -> usize {
        let preview_dir = self.load_game_preview_dir();
        let preview_atlas =
            TextureAtlasPlan::from_sprite_sources(slots.iter().filter_map(|slot| {
                Self::load_game_slot_preview_file_in_dir(slot, &preview_dir).map(|path| {
                    TextureAtlasSpriteSourceDescriptor::new(
                        path.display().to_string(),
                        Self::load_game_slot_preview_symbol(slot),
                    )
                    .with_page_hint("ui")
                })
            }));
        let mut merged = 0;
        for page in preview_atlas.pages {
            let page_type = page.page_type;
            for region in page.regions {
                let _ = self
                    .texture_atlas
                    .insert_or_replace_region(page_type, region);
                merged += 1;
            }
        }
        merged
    }

