    fn push_settings_language_dialog_content(&self, pass: &mut RenderPass, dialog: RenderRect) {
        let offset = self.settings_language_scroll_offset.min(
            SETTINGS_LANGUAGE_OPTIONS
                .len()
                .saturating_sub(SETTINGS_LANGUAGE_VISIBLE_ROWS),
        );
        let list_clip = Self::settings_language_list_clip_rect(dialog);
        let scrollpane = Self::settings_language_scrollpane_rect(dialog);
        let scroll_track_symbol = Self::settings_scroll_track_symbol();
        let scroll_knob_symbol = Self::settings_scroll_knob_symbol();
        pass.push(RenderCommand::set_clip(list_clip));
        for (index, option) in SETTINGS_LANGUAGE_OPTIONS
            .iter()
            .skip(offset)
            .take(SETTINGS_LANGUAGE_VISIBLE_ROWS)
            .enumerate()
        {
            let rect = Self::settings_language_row_rect(dialog, index);
            let selected = self.settings_locale == option.code;
            let hovered = self
                .last_menu_cursor
                .map(|point| rect.contains_point(point))
                .unwrap_or(false);
            pass.push(RenderCommand::draw_sprite(
                Self::settings_text_button_symbol("flatTogglet", hovered, selected),
                rect,
                if selected {
                    [0.82, 0.94, 1.0, 0.98]
                } else if hovered {
                    [0.78, 0.86, 0.94, 0.92]
                } else {
                    [0.56, 0.64, 0.72, 0.78]
                },
                0.0,
                Layer::END_PIXELED + 0.098 + index as f32 * 0.0001,
            ));
            pass.push(RenderCommand::draw_text_styled(
                option.display_name,
                RenderPoint::new(rect.center().x, rect.center().y),
                if selected {
                    [0.98, 1.0, 1.0, 1.0]
                } else {
                    [0.86, 0.92, 0.96, 1.0]
                },
                10.5,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true)
                    .with_outline(true),
                Layer::END_PIXELED + 0.122 + index as f32 * 0.0001,
            ));
        }
        pass.push(RenderCommand::clear_clip());
        Self::push_settings_scrollbar(
            pass,
            scrollpane,
            SETTINGS_LANGUAGE_OPTIONS.len(),
            offset as f32 * SETTINGS_LANGUAGE_ROW_HEIGHT,
            scroll_track_symbol,
            scroll_knob_symbol,
        );
    }

    fn push_settings_controls_dialog_content(&self, pass: &mut RenderPass, dialog: RenderRect) {
        let search = Self::settings_keybind_search_rect(dialog);
        pass.push(RenderCommand::draw_sprite(
            Self::settings_text_field_background_symbol(),
            search,
            if self.settings_keybind_search_focused {
                [1.0, 1.0, 1.0, 0.96]
            } else {
                [1.0, 1.0, 1.0, 0.72]
            },
            0.0,
            Layer::END_PIXELED + 0.098,
        ));
        pass.push(RenderCommand::draw_text_styled(
            desktop_ui_icon_glyph_or_label("zoom", "zoom"),
            RenderPoint::new(search.x + 22.0, search.center().y),
            [0.82, 0.9, 1.0, 1.0],
            13.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_font(RenderFontId::Icon)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            Layer::END_PIXELED + 0.105,
        ));
        pass.push(RenderCommand::draw_text_styled(
            if self.settings_keybind_search.is_empty() {
                "keybind search"
            } else {
                self.settings_keybind_search.as_str()
            },
            RenderPoint::new(search.x + 48.0, search.center().y),
            if self.settings_keybind_search_focused {
                [0.92, 0.96, 1.0, 1.0]
            } else {
                [0.62, 0.72, 0.8, 1.0]
            },
            11.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Start)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            Layer::END_PIXELED + 0.106,
        ));
        if self.settings_keybind_search_focused {
            let cursor_x =
                (search.x + 48.0 + self.settings_keybind_search.chars().count() as f32 * 7.0)
                    .min(search.right() - 10.0);
            pass.push(RenderCommand::draw_sprite(
                Self::settings_text_field_cursor_symbol(),
                RenderRect::new(cursor_x, search.y + 6.0, 2.0, search.height - 12.0),
                [1.0, 1.0, 1.0, 0.95],
                0.0,
                Layer::END_PIXELED + 0.1065,
            ));
        }

        let filtered_specs = self.settings_keybind_filtered_specs();
        let item_count = filtered_specs.len().saturating_add(1);
        let offset = self
            .settings_keybind_scroll_offset
            .min(item_count.saturating_sub(SETTINGS_KEYBIND_VISIBLE_ROWS));
        let mut last_category = filtered_specs[..offset.min(filtered_specs.len())]
            .iter()
            .rev()
            .find_map(|spec| spec.category);
        for (index, item_index) in (offset..item_count)
            .take(SETTINGS_KEYBIND_VISIBLE_ROWS)
            .enumerate()
        {
            if item_index == filtered_specs.len() {
                self.push_settings_text_button(
                    pass,
                    Self::settings_keybind_reset_all_rect(dialog, index),
                    self.localize_bundle_markup_text("@settings.reset"),
                    Some("refresh"),
                    Layer::END_PIXELED + 0.129 + index as f32 * 0.0001,
                );
                continue;
            }
            let spec = filtered_specs[item_index];
            if spec.category != last_category {
                if let Some(category) = spec.category {
                    let rect = Self::settings_keybind_category_rect(dialog, index);
                    pass.push(RenderCommand::draw_text_styled(
                        Self::settings_keybind_category_label(category),
                        RenderPoint::new(rect.x + 8.0, rect.center().y),
                        [0.56, 0.62, 0.68, 1.0],
                        10.5,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Start)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true)
                            .with_outline(true),
                        Layer::END_PIXELED + 0.107 + index as f32 * 0.0001,
                    ));
                    let separator = RenderRect::new(
                        rect.x + 138.0,
                        rect.center().y - 1.5,
                        (rect.width - 146.0).max(0.0),
                        3.0,
                    );
                    if separator.width > 0.0 {
                        pass.push(RenderCommand::fill_rect(
                            separator,
                            [0.32, 0.36, 0.40, 0.88],
                            Layer::END_PIXELED + 0.1075 + index as f32 * 0.0001,
                        ));
                    }
                }
                last_category = spec.category;
            }

            let row = Self::settings_keybind_row_rect(dialog, index);
            pass.push(RenderCommand::draw_text_styled(
                Self::settings_keybind_bundle_label(spec.name),
                RenderPoint::new(row.x + 8.0, row.center().y),
                [0.94, 0.96, 0.98, 1.0],
                10.5,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Start)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true)
                    .with_outline(true),
                Layer::END_PIXELED + 0.108 + index as f32 * 0.0001,
            ));
            pass.push(RenderCommand::draw_text_styled(
                self.settings_keybind_effective_value(spec),
                RenderPoint::new(row.x + row.width * 0.44, row.center().y),
                if self.settings_keybind_overrides.contains_key(spec.name) {
                    [1.0, 0.86, 0.48, 1.0]
                } else {
                    [0.48, 0.74, 1.0, 1.0]
                },
                10.5,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Start)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.109 + index as f32 * 0.0001,
            ));
            self.push_settings_text_button(
                pass,
                Self::settings_keybind_rebind_button_rect(dialog, index),
                self.localize_bundle_markup_text("@settings.rebind"),
                None,
                Layer::END_PIXELED + 0.110 + index as f32 * 0.0001,
            );
            self.push_settings_text_button_enabled(
                pass,
                Self::settings_keybind_reset_button_rect(dialog, index),
                self.localize_bundle_markup_text("@settings.resetKey"),
                None,
                Layer::END_PIXELED + 0.111 + index as f32 * 0.0001,
                self.settings_keybind_overrides.contains_key(spec.name),
            );
        }
    }

