    fn push_settings_route_controls(&self, pass: &mut RenderPass, panel: RenderRect) {
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return;
        };
        let table = self.settings_dialog_state.page.key();
        let track_symbol = Self::settings_slider_track_symbol();
        let scroll_track_symbol = Self::settings_scroll_track_symbol();
        let scroll_knob_symbol = Self::settings_scroll_knob_symbol();
        let specs = Self::settings_pref_widget_specs(table);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let table_container = Self::settings_pref_table_container_rect_for_panel(panel);
        let scroll_offset = self.settings_scroll_offset_pixels(table, clip);

        pass.push(RenderCommand::draw_sprite(
            Self::settings_drawable_symbol("button"),
            table_container,
            [1.0, 1.0, 1.0, 0.74],
            0.0,
            Layer::END_PIXELED + 0.020,
        ));
        pass.push(RenderCommand::stroke_rect(
            table_container,
            [0.22, 0.34, 0.42, 0.70],
            1.0,
            Layer::END_PIXELED + 0.021,
        ));
        pass.push(RenderCommand::set_clip(clip));
        for (index, spec) in specs.iter().copied().enumerate() {
            let control_id = DesktopSettingsControlId::new(spec.table, spec.key);
            let hovered = self.last_settings_hovered_control == Some(control_id);
            let pressed = self.last_settings_pressed_control == Some(control_id);
            let row = Self::settings_pref_widget_row_rect_for_clip_with_scroll(
                clip,
                index,
                scroll_offset,
            );
            if hovered || pressed {
                pass.push(RenderCommand::fill_rect(
                    row,
                    if pressed {
                        [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, 0.18]
                    } else {
                        [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, 0.10]
                    },
                    Layer::END_PIXELED + 0.025,
                ));
            }
            match spec.kind {
                DesktopSettingsPrefKind::Check => {
                    let checked = self.setting_bool_effective_value(spec);
                    let control = Self::settings_pref_widget_check_box_rect(row);
                    let label_point = Self::settings_pref_widget_check_label_point(row);
                    pass.push(RenderCommand::draw_text_styled(
                        Self::settings_pref_label(spec.key),
                        label_point,
                        [0.82, 0.9, 0.96, 1.0],
                        12.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Start)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.03,
                    ));
                    pass.push(RenderCommand::draw_sprite(
                        Self::settings_check_box_symbol(checked, hovered, pressed),
                        control,
                        [1.0, 1.0, 1.0, 1.0],
                        0.0,
                        Layer::END_PIXELED + 0.032,
                    ));
                }
                DesktopSettingsPrefKind::Slider => {
                    let Some(range) = spec.range_step else {
                        continue;
                    };
                    let value = self
                        .setting_slider_effective_value(spec)
                        .unwrap_or(range.min)
                        .clamp(range.min, range.max);
                    let track = Self::settings_pref_widget_slider_track_rect(row);
                    let t = if range.max > range.min {
                        (value - range.min) as f32 / (range.max - range.min) as f32
                    } else {
                        0.0
                    }
                    .clamp(0.0, 1.0);
                    let stack = Self::settings_pref_widget_slider_stack_rect(row);
                    let content = Self::settings_pref_widget_slider_content_rect(stack);
                    let knob_size = 24.0;
                    let knob = RenderRect::new(
                        track.x + t * track.width - knob_size * 0.5,
                        row.y + row.height * 0.5 - knob_size * 0.5,
                        knob_size,
                        knob_size,
                    );
                    pass.push(RenderCommand::draw_sprite(
                        track_symbol.clone(),
                        track,
                        [1.0, 1.0, 1.0, 1.0],
                        0.0,
                        Layer::END_PIXELED + 0.032,
                    ));
                    pass.push(RenderCommand::draw_sprite(
                        Self::settings_slider_knob_symbol(hovered, pressed),
                        knob,
                        [1.0, 1.0, 1.0, 1.0],
                        0.0,
                        Layer::END_PIXELED + 0.033,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        Self::settings_pref_label(spec.key),
                        RenderPoint::new(content.x, row.y + row.height * 0.5),
                        [0.82, 0.9, 0.96, 1.0],
                        12.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::Start)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.034,
                    ));
                    pass.push(RenderCommand::draw_text_styled(
                        self.settings_slider_display_value(spec, value),
                        RenderPoint::new(content.right(), row.y + row.height * 0.5),
                        [0.72, 0.84, 0.9, 1.0],
                        11.0,
                        0.0,
                        RenderTextStyle::new(RenderTextAlign::End)
                            .with_vertical_align(RenderTextVerticalAlign::Center)
                            .with_integer_position(true),
                        Layer::END_PIXELED + 0.035,
                    ));
                }
            }
        }
        pass.push(RenderCommand::clear_clip());
        Self::push_settings_scrollbar(
            pass,
            clip,
            specs.len(),
            scroll_offset,
            scroll_track_symbol,
            scroll_knob_symbol,
        );
    }

    fn settings_route_control_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopSettingsAction> {
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return None;
        };
        let table = self.settings_dialog_state.page.key();
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let scroll_offset = self.settings_scroll_offset_pixels(table, clip);
        if !clip.contains_point(point) {
            return None;
        }
        for (index, spec) in Self::settings_pref_widget_specs(table)
            .iter()
            .copied()
            .enumerate()
        {
            let row = Self::settings_pref_widget_row_rect_for_clip_with_scroll(
                clip,
                index,
                scroll_offset,
            );
            if !row.contains_point(point) {
                continue;
            }
            match spec.kind {
                DesktopSettingsPrefKind::Check => {
                    let hit = Self::settings_pref_widget_check_hit_rect(row);
                    if !hit.contains_point(point) {
                        continue;
                    }
                    return Some(DesktopSettingsAction::ToggleSetting(spec.table, spec.key));
                }
                DesktopSettingsPrefKind::Slider => {
                    let stack = Self::settings_pref_widget_slider_stack_rect(row);
                    if !stack.contains_point(point) {
                        continue;
                    }
                    let range = spec.range_step?;
                    let track = Self::settings_pref_widget_slider_track_rect(row);
                    let value = Self::settings_slider_value_from_track_x(range, track, point.x);
                    return Some(DesktopSettingsAction::SetSliderValue(
                        spec.table, spec.key, value,
                    ));
                }
            };
        }
        None
    }

    fn settings_control_id_from_action(
        action: DesktopSettingsAction,
    ) -> Option<DesktopSettingsControlId> {
        match action {
            DesktopSettingsAction::ToggleSetting(table, key)
            | DesktopSettingsAction::SetSliderValue(table, key, _) => {
                Some(DesktopSettingsControlId::new(table, key))
            }
            _ => None,
        }
    }

    fn settings_control_id_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<DesktopSettingsControlId> {
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return None;
        }
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let point = RenderPoint::new(x, y);
        self.settings_route_control_action_at_point(panel, point)
            .and_then(Self::settings_control_id_from_action)
    }

    fn settings_drag_action_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        _y: f32,
    ) -> Option<DesktopSettingsAction> {
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return None;
        }
        let pressed = self.last_settings_pressed_control?;
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return None;
        };
        let table = self.settings_dialog_state.page.key();
        if pressed.table != table {
            return None;
        }
        let spec = settings_pref_spec(pressed.table, pressed.key)?;
        if spec.kind != DesktopSettingsPrefKind::Slider {
            return None;
        }
        let range = spec.range_step?;
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let scroll_offset = self.settings_scroll_offset_pixels(table, clip);
        let index = Self::settings_pref_widget_specs(table)
            .iter()
            .position(|candidate| candidate.table == spec.table && candidate.key == spec.key)?;
        let row =
            Self::settings_pref_widget_row_rect_for_clip_with_scroll(clip, index, scroll_offset);
        let track = Self::settings_pref_widget_slider_track_rect(row);
        let value = Self::settings_slider_value_from_track_x(range, track, x);
        Some(DesktopSettingsAction::SetSliderValue(
            spec.table, spec.key, value,
        ))
    }

    fn settings_scrollbar_drag_state_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<DesktopSettingsScrollDragState> {
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return None;
        }
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return None;
        };
        let table = self.settings_dialog_state.page.key();
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let row_count = Self::settings_pref_widget_specs(table).len();
        let scroll_offset = self.settings_scroll_offset_pixels(table, clip);
        let knob = Self::settings_scrollbar_knob_rect_for_clip(clip, row_count, scroll_offset)?;
        let point = RenderPoint::new(x, y);
        if knob.contains_point(point) {
            Some(DesktopSettingsScrollDragState::new(table, y - knob.y))
        } else {
            None
        }
    }

    fn apply_settings_scrollbar_drag(&mut self, surface_size: DesktopSurfaceSize, y: f32) -> bool {
        let Some(drag_state) = self.settings_scroll_drag_state else {
            return false;
        };
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return false;
        }
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return false;
        };
        let table = self.settings_dialog_state.page.key();
        if drag_state.table != table {
            return false;
        }
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        let row_count = Self::settings_pref_widget_specs(table).len();
        let max = Self::settings_max_scroll_offset_for_clip(clip, row_count);
        if max <= 0 {
            return false;
        }
        let Some(knob) = Self::settings_scrollbar_knob_rect_for_clip(
            clip,
            row_count,
            self.settings_scroll_offset_pixels(table, clip),
        ) else {
            return false;
        };
        let travel = (clip.height - knob.height).max(0.0);
        if travel <= f32::EPSILON {
            return false;
        }
        let knob_y =
            (y - drag_state.grab_offset_y).clamp(clip.y, clip.y + clip.height - knob.height);
        let raw_scroll = ((clip.y + clip.height - knob.height - knob_y) / travel) * max as f32;
        let next = raw_scroll.round().clamp(0.0, max as f32) as i32;
        self.settings_scroll_offsets.insert(table, next);
        true
    }

    fn apply_settings_scroll_delta(
        &mut self,
        surface_size: DesktopSurfaceSize,
        delta_y: f32,
    ) -> bool {
        if self.active_menu_route == Some(DesktopMenuRoute::Settings)
            && self.settings_child_dialog == Some(DesktopSettingsChildDialog::Language)
        {
            let Some(cursor) = self.last_menu_cursor else {
                return false;
            };
            let viewport = self.default_render_viewport_for_surface(surface_size);
            let panel =
                Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
            let dialog = Self::settings_child_dialog_rect_for_panel(panel);
            if dialog.contains_point(cursor) {
                return self.apply_settings_language_scroll_delta(delta_y);
            }
        }
        if self.active_menu_route == Some(DesktopMenuRoute::Settings)
            && self.settings_child_dialog == Some(DesktopSettingsChildDialog::Controls)
        {
            let Some(cursor) = self.last_menu_cursor else {
                return false;
            };
            let viewport = self.default_render_viewport_for_surface(surface_size);
            let panel =
                Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
            let dialog = Self::settings_child_dialog_rect_for_panel(panel);
            if dialog.contains_point(cursor) {
                return self.apply_settings_keybind_scroll_delta(delta_y);
            }
        }
        let (DesktopSettingsPage::Game
        | DesktopSettingsPage::Graphics
        | DesktopSettingsPage::Sound) = self.settings_dialog_state.page
        else {
            return false;
        };
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return false;
        }
        let Some(cursor) = self.last_menu_cursor else {
            return false;
        };
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let clip = Self::settings_pref_widget_clip_rect_for_panel(panel);
        if !clip.contains_point(cursor) {
            return false;
        }
        let table = self.settings_dialog_state.page.key();
        let row_count = Self::settings_pref_widget_specs(table).len();
        let max = Self::settings_max_scroll_offset_for_clip(clip, row_count);
        if max <= 0 {
            return false;
        }
        let current = self
            .settings_scroll_offsets
            .get(table)
            .copied()
            .unwrap_or(0);
        let delta = (-delta_y * 40.0).round() as i32;
        let next = (current + delta).clamp(0, max);
        self.settings_scroll_offsets.insert(table, next);
        true
    }

    fn apply_settings_keybind_scroll_delta(&mut self, delta_y: f32) -> bool {
        let filtered_len = self.settings_keybind_filtered_specs().len();
        let max = filtered_len
            .saturating_add(1)
            .saturating_sub(SETTINGS_KEYBIND_VISIBLE_ROWS);
        if max == 0 {
            return false;
        }
        let current = self.settings_keybind_scroll_offset.min(max);
        let rows = delta_y.abs().ceil().max(1.0) as isize;
        let step = if delta_y < 0.0 {
            rows
        } else if delta_y > 0.0 {
            -rows
        } else {
            0
        };
        let next = (current as isize + step).clamp(0, max as isize) as usize;
        self.settings_keybind_scroll_offset = next;
        next != current
    }

    fn commit_settings_keybind_rebind(&mut self, key_code: &str) -> bool {
        let Some(name) = self.last_settings_rebind_key else {
            return false;
        };
        let display = Self::settings_key_code_display(key_code);
        let axis = Self::settings_keybind_spec_by_name(name)
            .map(|spec| spec.axis)
            .unwrap_or(false);
        if axis && !Self::settings_key_code_is_axis(key_code) {
            if let Some(min) = self.settings_keybind_pending_axis_min.take() {
                self.set_settings_keybind_override(name, format!("{min} / {display}"));
                self.last_settings_rebind_key = None;
            } else {
                self.settings_keybind_pending_axis_min = Some(display);
            }
            return true;
        }
        let value = if axis { display } else { display };
        self.set_settings_keybind_override(name, value);
        self.last_settings_rebind_key = None;
        self.settings_keybind_pending_axis_min = None;
        true
    }

    fn settings_key_code_is_axis(key_code: &str) -> bool {
        matches!(key_code, "Scroll" | "scroll")
    }

    fn settings_key_code_display(key_code: &str) -> String {
        match key_code {
            "controlLeft" | "ControlLeft" => "Ctrl Left".into(),
            "shiftLeft" | "ShiftLeft" => "Shift Left".into(),
            "escape" | "Escape" => "Escape".into(),
            "space" | "Space" => "Space".into(),
            "tab" | "Tab" => "Tab".into(),
            "enter" | "Enter" => "Enter".into(),
            "primary" => "Mouse Left".into(),
            "secondary" => "Mouse Right".into(),
            "middle" => "Mouse Middle".into(),
            "Scroll" | "scroll" => "Scroll".into(),
            other => other.to_string(),
        }
    }

    fn settings_visible_planets(
        &self,
    ) -> Vec<&mindustry_core::mindustry::content::planets::PlanetContent> {
        self.content_loader
            .catalog()
            .planets
            .iter()
            .filter(|planet| {
                planet.generator.is_some() && planet.sector_count > 0 && planet.meta.accessible
            })
            .collect()
    }

    fn settings_visible_planet_count(&self) -> usize {
        self.content_loader
            .catalog()
            .planets
            .iter()
            .filter(|planet| {
                planet.generator.is_some() && planet.sector_count > 0 && planet.meta.accessible
            })
            .count()
    }

    fn settings_selected_planet_label(&self) -> String {
        self.content_loader
            .catalog()
            .planets
            .iter()
            .find(|planet| planet.name() == self.settings_dialog_state.selected_planet)
            .map(|planet| planet.localized_name().to_string())
            .unwrap_or_else(|| self.settings_dialog_state.selected_planet.clone())
    }

    fn settings_data_confirm_message(&self, action: DesktopSettingsAction) -> String {
        match action {
            DesktopSettingsAction::ClearAllData => {
                self.format_bundle_text("settings.clearall.confirm", &[])
            }
            DesktopSettingsAction::ClearSaves => {
                self.format_bundle_text("settings.clearsaves.confirm", &[])
            }
            DesktopSettingsAction::ClearResearch => {
                self.format_bundle_text("settings.clearresearch.confirm", &[])
            }
            DesktopSettingsAction::ClearCampaignSaves => {
                self.format_bundle_text("settings.clearcampaignsaves.confirm", &[])
            }
            DesktopSettingsAction::ClearPlanetResearch => self.format_bundle_text(
                "settings.clearplanetresearch.confirm",
                &[self.settings_selected_planet_label().as_str()],
            ),
            DesktopSettingsAction::ClearPlanetCampaignSaves => self.format_bundle_text(
                "settings.clearplanetcampaignsaves.confirm",
                &[self.settings_selected_planet_label().as_str()],
            ),
            _ => "@confirm".into(),
        }
    }

    fn settings_route_lines(&self) -> Vec<String> {
        let state = &self.settings_dialog_state;
        let mut lines = vec![
            format!("settings page: {}", state.page.key()),
            "style: Tex.button / Styles.flatt".into(),
        ];

        match state.page {
            DesktopSettingsPage::Main => {
                let entries = self.settings_visible_main_menu_entries();
                lines.push(format!("categories: {}", entries.len()));
                for entry in entries {
                    lines.push(format!(
                        "category: {} {} target:{}",
                        entry.label,
                        Self::settings_icon_line(entry.icon),
                        entry.target
                    ));
                }
                for table in ["game", "graphics", "sound"] {
                    if let Some(highlights) = settings_pref_highlight_summary_line(table) {
                        lines.push(format!(
                            "pref table: {table} settings: {} critical: {highlights}",
                            settings_pref_count(table)
                        ));
                    }
                }
                lines.push(format!(
                    "data actions: {}",
                    self.settings_visible_data_actions().len()
                ));
            }
            DesktopSettingsPage::Game
            | DesktopSettingsPage::Graphics
            | DesktopSettingsPage::Sound => {
                let table = state.page.key();
                lines.push(format!(
                    "table: {table} settings: {}",
                    settings_pref_count(table)
                ));
                if let Some(highlights) = settings_pref_highlight_summary_line(table) {
                    for highlight in highlights.split(" | ") {
                        lines.push(format!("critical: {highlight}"));
                    }
                }
                lines.push("button: reset-to-defaults".into());
                lines.push("button: back".into());
            }
            DesktopSettingsPage::Data => {
                lines.push(format!("planet: {}", state.selected_planet));
                for action in self.settings_visible_data_actions() {
                    lines.push(format!(
                        "data action: {} {}",
                        action.label,
                        Self::settings_icon_line(action.icon)
                    ));
                }
                lines.push("button: back".into());
            }
        }

        if let Some(child) = self.settings_child_dialog {
            match child {
                DesktopSettingsChildDialog::Language => {
                    lines.push(format!(
                        "child dialog: LanguageDialog locales:{} selected:{}",
                        SETTINGS_LANGUAGE_OPTIONS.len(),
                        self.settings_locale
                    ));
                }
                DesktopSettingsChildDialog::Controls => {
                    lines.push(format!(
                        "child dialog: KeybindDialog binds:{} filtered:{} offset:{} search:{}",
                        SETTINGS_KEYBIND_SPECS.len(),
                        self.settings_keybind_filtered_specs().len(),
                        self.settings_keybind_scroll_offset,
                        self.settings_keybind_search
                    ));
                }
                DesktopSettingsChildDialog::PlanetData => {
                    lines.push(format!(
                        "child dialog: PlanetDataDialog planet:{} actions:2 planets:{}",
                        self.settings_dialog_state.selected_planet,
                        self.settings_visible_planet_count()
                    ));
                    if self.settings_planet_chooser_open {
                        lines.push(format!(
                            "child dialog: PlanetSelectDialog options:{} columns:{}",
                            self.settings_visible_planet_count(),
                            SETTINGS_PLANET_OPTION_COLUMNS
                        ));
                    }
                    lines.push("@settings.clearplanetresearch".into());
                    lines.push("@settings.clearplanetcampaignsaves".into());
                }
            }
        }

        lines
    }

    fn settings_route_line_rect_for_panel(panel: RenderRect, line_index: usize) -> RenderRect {
        let center_y = panel.y + panel.height - 118.0 - line_index as f32 * 20.0;
        RenderRect::new(panel.x + 22.0, center_y - 9.0, panel.width - 44.0, 18.0)
    }

    fn settings_main_menu_button_rect_for_panel(panel: RenderRect, index: usize) -> RenderRect {
        let x = panel.x + 36.0 + SETTINGS_MENU_BUTTON_MARGIN_LEFT;
        let top = panel.y + panel.height - 124.0 - index as f32 * SETTINGS_MENU_BUTTON_HEIGHT;
        RenderRect::new(
            x,
            top - SETTINGS_MENU_BUTTON_HEIGHT,
            SETTINGS_MENU_BUTTON_WIDTH,
            SETTINGS_MENU_BUTTON_HEIGHT,
        )
    }

    fn settings_main_menu_container_rect_for_panel(
        panel: RenderRect,
        entry_count: usize,
    ) -> RenderRect {
        let entry_count = entry_count.max(1);
        let first = Self::settings_main_menu_button_rect_for_panel(panel, 0);
        let last = Self::settings_main_menu_button_rect_for_panel(panel, entry_count - 1);
        let pad = 14.0;
        RenderRect::new(
            first.x - pad,
            last.y - pad,
            SETTINGS_MENU_BUTTON_WIDTH + pad * 2.0,
            first.bottom() - last.y + pad * 2.0,
        )
    }

    fn settings_main_menu_entry_index_at_point(
        panel: RenderRect,
        point: RenderPoint,
        entry_count: usize,
    ) -> Option<usize> {
        (0..entry_count).find(|index| {
            Self::settings_main_menu_button_rect_for_panel(panel, *index).contains_point(point)
        })
    }

    #[cfg(test)]
    fn settings_data_action_button_rect_for_panel(panel: RenderRect, index: usize) -> RenderRect {
        Self::settings_data_action_button_rect_for_panel_with_count(
            panel,
            index,
            SETTINGS_DATA_ACTIONS.len(),
        )
    }

    fn settings_data_action_button_rect_for_panel_with_count(
        panel: RenderRect,
        index: usize,
        action_count: usize,
    ) -> RenderRect {
        let dialog =
            Self::settings_data_actions_container_rect_for_panel_with_count(panel, action_count);
        let columns = Self::settings_data_action_column_count_for_panel(panel);
        let column = index % columns;
        let row = index / columns;
        let total_width = columns as f32 * SETTINGS_DATA_BUTTON_WIDTH
            + columns.saturating_sub(1) as f32 * SETTINGS_DATA_BUTTON_GAP;
        let start_x = dialog.center().x - total_width * 0.5;
        let top = dialog.y + dialog.height
            - 48.0
            - row as f32 * (SETTINGS_DATA_BUTTON_HEIGHT + SETTINGS_DATA_BUTTON_GAP);
        RenderRect::new(
            start_x + column as f32 * (SETTINGS_DATA_BUTTON_WIDTH + SETTINGS_DATA_BUTTON_GAP),
            top - SETTINGS_DATA_BUTTON_HEIGHT,
            SETTINGS_DATA_BUTTON_WIDTH,
            SETTINGS_DATA_BUTTON_HEIGHT,
        )
    }

    fn settings_data_action_column_count_for_panel(_panel: RenderRect) -> usize {
        1
    }

    #[cfg(test)]
    fn settings_data_actions_container_rect_for_panel(panel: RenderRect) -> RenderRect {
        Self::settings_data_actions_container_rect_for_panel_with_count(
            panel,
            SETTINGS_DATA_ACTIONS.len(),
        )
    }

    fn settings_data_actions_container_rect_for_panel_with_count(
        panel: RenderRect,
        action_count: usize,
    ) -> RenderRect {
        let columns = Self::settings_data_action_column_count_for_panel(panel);
        let rows = (action_count + columns - 1) / columns;
        let content_width = columns as f32 * SETTINGS_DATA_BUTTON_WIDTH
            + columns.saturating_sub(1) as f32 * SETTINGS_DATA_BUTTON_GAP;
        let content_height = rows as f32 * SETTINGS_DATA_BUTTON_HEIGHT
            + rows.saturating_sub(1) as f32 * SETTINGS_DATA_BUTTON_GAP;
        let width = (content_width + 28.0).max(content_width);
        let height = content_height + 64.0;
        let y = panel.center().y - height * 0.5;
        RenderRect::new(panel.x + (panel.width - width) * 0.5, y, width, height)
    }

    fn settings_reset_button_rect_for_panel(panel: RenderRect) -> RenderRect {
        RenderRect::new(
            panel.x + (panel.width - SETTINGS_RESET_BUTTON_WIDTH) * 0.5,
            panel.y + SETTINGS_BACK_BUTTON_HEIGHT + 30.0,
            SETTINGS_RESET_BUTTON_WIDTH,
            SETTINGS_RESET_BUTTON_HEIGHT,
        )
    }

