    fn settings_action_for_main_menu_entry(
        entry: &DesktopSettingsMenuEntry,
    ) -> Option<DesktopSettingsAction> {
        match entry.target {
            "game" => Some(DesktopSettingsAction::OpenPage(DesktopSettingsPage::Game)),
            "graphics" => Some(DesktopSettingsAction::OpenPage(
                DesktopSettingsPage::Graphics,
            )),
            "sound" => Some(DesktopSettingsAction::OpenPage(DesktopSettingsPage::Sound)),
            "language-dialog" => Some(DesktopSettingsAction::OpenLanguageDialog),
            "controls-dialog" => Some(DesktopSettingsAction::OpenControlsDialog),
            "data-dialog" => Some(DesktopSettingsAction::OpenPage(DesktopSettingsPage::Data)),
            _ => None,
        }
    }

    fn settings_action_for_main_entry(&self, index: usize) -> Option<DesktopSettingsAction> {
        self.settings_visible_main_menu_entries()
            .get(index)
            .and_then(|entry| Self::settings_action_for_main_menu_entry(entry))
    }

    fn settings_route_action_for_line(&self, line_index: usize) -> Option<DesktopSettingsAction> {
        match self.settings_dialog_state.page {
            DesktopSettingsPage::Main => line_index
                .checked_sub(3)
                .and_then(|index| self.settings_action_for_main_entry(index)),
            DesktopSettingsPage::Data => {
                let actions = self.settings_visible_data_actions();
                if let Some(action_index) = line_index.checked_sub(3) {
                    if let Some(action) = actions.get(action_index) {
                        return Some(action.action);
                    }
                    if action_index == actions.len() {
                        return Some(DesktopSettingsAction::BackToMain);
                    }
                }
                None
            }
            DesktopSettingsPage::Game
            | DesktopSettingsPage::Graphics
            | DesktopSettingsPage::Sound => {
                let table = self.settings_dialog_state.page.key();
                let reset_line = 3 + settings_pref_highlight_keys(table).len();
                let back_line = reset_line + 1;
                if line_index == reset_line {
                    Some(DesktopSettingsAction::ResetCurrentPage)
                } else if line_index == back_line {
                    Some(DesktopSettingsAction::BackToMain)
                } else {
                    None
                }
            }
        }
    }

    fn settings_child_dialog_rect_for_panel(panel: RenderRect) -> RenderRect {
        Self::schematic_info_dialog_rect_for_panel(panel)
    }

    fn settings_child_dialog_title(dialog: DesktopSettingsChildDialog) -> &'static str {
        match dialog {
            DesktopSettingsChildDialog::Language => "@settings.language",
            DesktopSettingsChildDialog::Controls => "@settings.controls",
            DesktopSettingsChildDialog::PlanetData => "@settings.data",
        }
    }

    fn settings_child_dialog_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopMenuRouteShellAction> {
        self.settings_child_dialog?;
        let dialog = Self::settings_child_dialog_rect_for_panel(panel);
        if self.last_settings_rebind_key.is_some() {
            return None;
        }
        if self.settings_child_dialog == Some(DesktopSettingsChildDialog::PlanetData)
            && self.settings_planet_chooser_open
        {
            let chooser = Self::settings_planet_chooser_dialog_rect(
                panel,
                self.settings_visible_planet_count(),
            );
            if Self::schematic_info_button_rect(chooser, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::Settings(
                    DesktopSettingsAction::ClosePlanetChooser,
                ));
            }
            for index in 0..self.settings_visible_planet_count() {
                if Self::settings_planet_option_rect(chooser, index).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::Settings(
                        DesktopSettingsAction::SelectPlanet(index),
                    ));
                }
            }
            return None;
        }
        if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::Settings(
                DesktopSettingsAction::CloseChildDialog,
            ));
        }
        match self.settings_child_dialog {
            Some(DesktopSettingsChildDialog::Language) => {
                let offset = self.settings_language_scroll_offset.min(
                    SETTINGS_LANGUAGE_OPTIONS
                        .len()
                        .saturating_sub(SETTINGS_LANGUAGE_VISIBLE_ROWS),
                );
                for (index, option) in SETTINGS_LANGUAGE_OPTIONS
                    .iter()
                    .skip(offset)
                    .take(SETTINGS_LANGUAGE_VISIBLE_ROWS)
                    .enumerate()
                {
                    if Self::settings_language_row_rect(dialog, index).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::Settings(
                            DesktopSettingsAction::SelectLanguage(option.code),
                        ));
                    }
                }
            }
            Some(DesktopSettingsChildDialog::Controls) => {
                if Self::settings_keybind_search_rect(dialog).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::Settings(
                        DesktopSettingsAction::FocusKeybindSearch,
                    ));
                }
                let filtered_specs = self.settings_keybind_filtered_specs();
                let item_count = filtered_specs.len().saturating_add(1);
                let offset = self
                    .settings_keybind_scroll_offset
                    .min(item_count.saturating_sub(SETTINGS_KEYBIND_VISIBLE_ROWS));
                for (index, item_index) in (offset..item_count)
                    .take(SETTINGS_KEYBIND_VISIBLE_ROWS)
                    .enumerate()
                {
                    if item_index == filtered_specs.len() {
                        if Self::settings_keybind_reset_all_rect(dialog, index)
                            .contains_point(point)
                        {
                            return Some(DesktopMenuRouteShellAction::Settings(
                                DesktopSettingsAction::ResetAllKeys,
                            ));
                        }
                        continue;
                    }
                    let spec = filtered_specs[item_index];
                    if Self::settings_keybind_rebind_button_rect(dialog, index)
                        .contains_point(point)
                    {
                        return Some(DesktopMenuRouteShellAction::Settings(
                            DesktopSettingsAction::StartKeyRebind(spec.name),
                        ));
                    }
                    if self.settings_keybind_overrides.contains_key(spec.name)
                        && Self::settings_keybind_reset_button_rect(dialog, index)
                            .contains_point(point)
                    {
                        return Some(DesktopMenuRouteShellAction::Settings(
                            DesktopSettingsAction::ResetKey(spec.name),
                        ));
                    }
                }
            }
            Some(DesktopSettingsChildDialog::PlanetData) => {
                if Self::settings_planet_data_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::Settings(
                        DesktopSettingsAction::OpenPlanetChooser,
                    ));
                }
                if Self::settings_planet_data_button_rect(dialog, 1).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::Settings(
                        DesktopSettingsAction::ClearPlanetResearch,
                    ));
                }
                if Self::settings_planet_data_button_rect(dialog, 2).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::Settings(
                        DesktopSettingsAction::ClearPlanetCampaignSaves,
                    ));
                }
            }
            None => {}
        }
        None
    }

