    fn settings_keybind_filtered_specs(&self) -> Vec<&'static DesktopKeybindSpec> {
        let query = self.settings_keybind_search.to_lowercase();
        if query.is_empty() {
            return SETTINGS_KEYBIND_SPECS.iter().collect();
        }
        SETTINGS_KEYBIND_SPECS
            .iter()
            .filter(|spec| {
                Self::settings_keybind_bundle_label(spec.name)
                    .to_lowercase()
                    .contains(&query)
            })
            .collect()
    }

    fn settings_route_shell_action_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        if self.active_menu_route != Some(DesktopMenuRoute::Settings) {
            return None;
        }
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Settings);
        let point = RenderPoint::new(x, y);
        if self.pending_settings_confirm_action.is_some() {
            let dialog = Self::settings_data_confirm_dialog_rect(panel);
            if Self::settings_data_confirm_cancel_rect(dialog).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::Settings(
                    DesktopSettingsAction::CancelPendingDataAction,
                ));
            }
            if Self::settings_data_confirm_ok_rect(dialog).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::Settings(
                    DesktopSettingsAction::ConfirmPendingDataAction,
                ));
            }
            return None;
        }
        if self.settings_child_dialog.is_some() {
            return self.settings_child_dialog_action_at_point(panel, point);
        }
        if self.settings_dialog_state.page == DesktopSettingsPage::Main {
            let entries = self.settings_visible_main_menu_entries();
            if let Some(index) =
                Self::settings_main_menu_entry_index_at_point(panel, point, entries.len())
            {
                return self
                    .settings_action_for_main_entry(index)
                    .map(DesktopMenuRouteShellAction::Settings);
            }
            if Self::settings_back_button_rect_for_panel(panel).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::Settings(
                    DesktopSettingsAction::BackToMain,
                ));
            }
        }
        if matches!(
            self.settings_dialog_state.page,
            DesktopSettingsPage::Game | DesktopSettingsPage::Graphics | DesktopSettingsPage::Sound
        ) && Self::settings_reset_button_rect_for_panel(panel).contains_point(point)
        {
            return Some(DesktopMenuRouteShellAction::Settings(
                DesktopSettingsAction::ResetCurrentPage,
            ));
        }
        if self.settings_dialog_state.page != DesktopSettingsPage::Main
            && Self::settings_back_button_rect_for_panel(panel).contains_point(point)
        {
            return Some(DesktopMenuRouteShellAction::Settings(
                DesktopSettingsAction::BackToMain,
            ));
        }
        if self.settings_dialog_state.page == DesktopSettingsPage::Data {
            let actions = self.settings_visible_data_actions();
            for (index, action) in actions.iter().enumerate() {
                if Self::settings_data_action_button_rect_for_panel_with_count(
                    panel,
                    index,
                    actions.len(),
                )
                .contains_point(point)
                {
                    return Some(DesktopMenuRouteShellAction::Settings(action.action));
                }
            }
        }
        if let Some(action) = self.settings_route_control_action_at_point(panel, point) {
            return Some(DesktopMenuRouteShellAction::Settings(action));
        }
        self.settings_route_lines()
            .iter()
            .enumerate()
            .find(|(line_index, _)| {
                Self::settings_route_line_rect_for_panel(panel, *line_index).contains_point(point)
            })
            .and_then(|(line_index, _)| self.settings_route_action_for_line(line_index))
            .map(DesktopMenuRouteShellAction::Settings)
    }

