    fn load_game_visible_slot_capacity_for_list(list: RenderRect) -> usize {
        let rows = Self::load_game_visible_row_capacity_for_list(list);
        rows * Self::load_game_slot_column_count_for_list(list)
    }

    fn load_game_visible_row_capacity_for_list(list: RenderRect) -> usize {
        ((list.height + LOAD_SLOT_CARD_GAP) / (LOAD_SLOT_CARD_HEIGHT + LOAD_SLOT_CARD_GAP))
            .floor()
            .max(1.0) as usize
    }

    fn load_game_total_rows_for_count(list: RenderRect, total_slots: usize) -> usize {
        let columns = Self::load_game_slot_column_count_for_list(list).max(1);
        total_slots.div_ceil(columns)
    }

    fn load_game_scroll_start_slot_for_list(list: RenderRect, scroll_offset: usize) -> usize {
        scroll_offset * Self::load_game_slot_column_count_for_list(list).max(1)
    }

    fn load_game_scrollbar_track_rect_for_list(list: RenderRect) -> RenderRect {
        RenderRect::new(
            list.right() - 8.0,
            list.y + 6.0,
            6.0,
            (list.height - 12.0).max(1.0),
        )
    }

    fn load_game_scrollbar_knob_rect_for_list(
        list: RenderRect,
        total_slots: usize,
        scroll_offset: usize,
    ) -> Option<RenderRect> {
        let visible_rows = Self::load_game_visible_row_capacity_for_list(list);
        let total_rows = Self::load_game_total_rows_for_count(list, total_slots);
        if total_rows <= visible_rows || visible_rows == 0 {
            return None;
        }
        let track = Self::load_game_scrollbar_track_rect_for_list(list);
        let knob_height =
            (track.height * visible_rows as f32 / total_rows as f32).clamp(36.0, track.height);
        let max_scroll = total_rows.saturating_sub(visible_rows).max(1);
        let travel = (track.height - knob_height).max(0.0);
        let t = (scroll_offset.min(max_scroll) as f32 / max_scroll as f32).clamp(0.0, 1.0);
        Some(RenderRect::new(
            track.x - 2.0,
            track.y + track.height - knob_height - travel * t,
            10.0,
            knob_height,
        ))
    }

    fn push_load_game_scrollbar(
        pass: &mut RenderPass,
        list: RenderRect,
        total_slots: usize,
        scroll_offset: usize,
    ) {
        let Some(knob) =
            Self::load_game_scrollbar_knob_rect_for_list(list, total_slots, scroll_offset)
        else {
            return;
        };
        pass.push(RenderCommand::draw_sprite(
            Self::settings_scroll_track_symbol(),
            Self::load_game_scrollbar_track_rect_for_list(list),
            [1.0, 1.0, 1.0, 0.82],
            0.0,
            Layer::END_PIXELED + 0.046,
        ));
        pass.push(RenderCommand::draw_sprite(
            Self::settings_scroll_knob_symbol(),
            knob,
            [1.0, 1.0, 1.0, 0.98],
            0.0,
            Layer::END_PIXELED + 0.047,
        ));
    }

    fn filtered_load_game_slot_indices(&self) -> Vec<usize> {
        let query = schematic_search_normalize(&self.load_game_search);
        self.load_game_slots
            .iter()
            .enumerate()
            .filter_map(|(index, slot)| {
                if query.is_empty()
                    || schematic_search_normalize(&self.load_game_slot_display_title(slot))
                        .contains(&query)
                    || schematic_search_normalize(&slot.index()).contains(&query)
                    || slot
                        .file
                        .file_name()
                        .and_then(|file| file.to_str())
                        .map(schematic_search_normalize)
                        .is_some_and(|file| file.contains(&query))
                {
                    let mode = Self::load_game_slot_gamemode(slot);
                    (!self.load_game_hidden_modes.contains(&mode)).then_some(index)
                } else {
                    None
                }
            })
            .collect()
    }

    fn load_game_slot_at_surface_point(
        &self,
        surface_size: DesktopSurfaceSize,
        x: f32,
        y: f32,
    ) -> Option<usize> {
        if !matches!(
            self.active_menu_route,
            Some(DesktopMenuRoute::LoadGame | DesktopMenuRoute::SaveGame)
        ) {
            return None;
        }
        if self.load_game_pending_load.is_some() || self.save_game_pending_save.is_some() {
            return None;
        }
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel = Self::active_menu_route_shell_panel_for_route(
            viewport,
            self.active_menu_route.unwrap(),
        );
        let list = Self::load_game_list_rect_for_panel(panel);
        let point = RenderPoint::new(x, y);
        let start_row = self
            .load_game_scroll_offset
            .min(self.max_load_game_scroll_offset(list));
        let start = Self::load_game_scroll_start_slot_for_list(list, start_row);
        self.filtered_load_game_slot_indices()
            .into_iter()
            .skip(start)
            .enumerate()
            .find(|(visible_index, _)| {
                let card = Self::load_game_slot_card_rect_for_panel(panel, *visible_index);
                Self::load_game_slot_card_visible_in_list(list, card) && card.contains_point(point)
            })
            .map(|(_, slot_index)| slot_index)
    }

    fn load_game_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::LoadGame);
        let point = RenderPoint::new(x, y);
        if self.load_game_pending_load.is_some() {
            return None;
        }
        if self.load_game_rename_dialog_slot.is_some() {
            let dialog = Self::load_game_rename_dialog_rect_for_panel(panel);
            if Self::load_game_rename_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::LoadGameRenameCancel);
            }
            if !self.load_game_rename_text.is_empty()
                && Self::load_game_rename_button_rect(dialog, 1).contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::LoadGameRenameOk);
            }
            return None;
        }
        if self.load_game_delete_dialog_slot.is_some() {
            let dialog = Self::load_game_delete_dialog_rect_for_panel(panel);
            if Self::load_game_rename_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::LoadGameDeleteCancel);
            }
            if Self::load_game_rename_button_rect(dialog, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::LoadGameDeleteOk);
            }
            return None;
        }
        if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseRoute);
        }
        if Self::load_game_import_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::LoadGameImport);
        }
        let search = Self::load_game_search_rect_for_panel(panel);
        for (mode_index, mode) in Gamemode::ALL
            .into_iter()
            .filter(|mode| !mode.hidden())
            .enumerate()
        {
            if Self::load_game_mode_filter_button_rect(search, mode_index).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::ToggleLoadGameMode(mode));
            }
        }
        if search.contains_point(point) {
            return Some(DesktopMenuRouteShellAction::FocusLoadGameSearch);
        }
        let list = Self::load_game_list_rect_for_panel(panel);
        let start_row = self
            .load_game_scroll_offset
            .min(self.max_load_game_scroll_offset(list));
        let start = Self::load_game_scroll_start_slot_for_list(list, start_row);
        for (visible_index, slot_index) in self
            .filtered_load_game_slot_indices()
            .into_iter()
            .skip(start)
            .enumerate()
        {
            let card = Self::load_game_slot_card_rect_for_panel(panel, visible_index);
            if !Self::load_game_slot_card_visible_in_list(list, card) {
                continue;
            }
            for action_index in 0..4 {
                if Self::load_game_slot_action_button_rect(card, action_index).contains_point(point)
                {
                    if let Some(kind) = Self::load_game_slot_action_kind_for_index(action_index) {
                        return Some(DesktopMenuRouteShellAction::LoadGameSlot(slot_index, kind));
                    }
                }
            }
        }
        None
    }

    fn save_game_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::SaveGame);
        let point = RenderPoint::new(x, y);
        if self.save_game_pending_save.is_some() {
            return None;
        }
        if self.load_game_delete_dialog_slot.is_some() {
            let dialog = Self::load_game_delete_dialog_rect_for_panel(panel);
            if Self::load_game_rename_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::LoadGameDeleteCancel);
            }
            if Self::load_game_rename_button_rect(dialog, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::LoadGameDeleteOk);
            }
            return None;
        }
        if self.save_game_new_dialog_open {
            let dialog = Self::load_game_rename_dialog_rect_for_panel(panel);
            if Self::load_game_rename_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::SaveGameNewCancel);
            }
            if !self.save_game_new_text.is_empty()
                && Self::load_game_rename_button_rect(dialog, 1).contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::SaveGameNewOk);
            }
            return None;
        }
        if self.save_game_overwrite_dialog_slot.is_some() {
            let dialog = Self::save_game_overwrite_dialog_rect_for_panel(panel);
            if Self::load_game_rename_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::SaveGameOverwriteCancel);
            }
            if Self::load_game_rename_button_rect(dialog, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::SaveGameOverwriteOk);
            }
            return None;
        }
        if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseRoute);
        }
        if Self::load_game_import_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::SaveGameNew);
        }
        let search = Self::load_game_search_rect_for_panel(panel);
        for (mode_index, mode) in Gamemode::ALL
            .into_iter()
            .filter(|mode| !mode.hidden())
            .enumerate()
        {
            if Self::load_game_mode_filter_button_rect(search, mode_index).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::ToggleLoadGameMode(mode));
            }
        }
        if search.contains_point(point) {
            return Some(DesktopMenuRouteShellAction::FocusLoadGameSearch);
        }
        let list = Self::load_game_list_rect_for_panel(panel);
        let start_row = self
            .load_game_scroll_offset
            .min(self.max_load_game_scroll_offset(list));
        let start = Self::load_game_scroll_start_slot_for_list(list, start_row);
        for (visible_index, slot_index) in self
            .filtered_load_game_slot_indices()
            .into_iter()
            .skip(start)
            .enumerate()
        {
            let card = Self::load_game_slot_card_rect_for_panel(panel, visible_index);
            if !Self::load_game_slot_card_visible_in_list(list, card) {
                continue;
            }
            for action_index in 0..4 {
                if Self::load_game_slot_action_button_rect(card, action_index).contains_point(point)
                {
                    if let Some(kind) = Self::load_game_slot_action_kind_for_index(action_index) {
                        return Some(DesktopMenuRouteShellAction::LoadGameSlot(slot_index, kind));
                    }
                }
            }
        }
        None
    }

    fn dispatch_load_game_slot_action(
        &mut self,
        slot_index: usize,
    ) -> Option<DesktopLoadGameAction> {
        self.dispatch_load_game_slot_action_kind(slot_index, DesktopLoadGameActionKind::Load)
    }

    fn dispatch_load_game_slot_action_kind(
        &mut self,
        slot_index: usize,
        kind: DesktopLoadGameActionKind,
    ) -> Option<DesktopLoadGameAction> {
        let mut platform = DefaultPlatform;
        self.dispatch_load_game_slot_action_kind_with_platform(slot_index, kind, &mut platform)
    }

    fn dispatch_load_game_slot_action_kind_with_platform<P: Platform>(
        &mut self,
        slot_index: usize,
        kind: DesktopLoadGameActionKind,
        platform: &mut P,
    ) -> Option<DesktopLoadGameAction> {
        let slot = self.load_game_slots.get(slot_index)?.clone();
        let status = match kind {
            DesktopLoadGameActionKind::Load => "selected-for-load",
            DesktopLoadGameActionKind::ToggleAutosave => "toggle-autosave",
            DesktopLoadGameActionKind::Delete => "delete",
            DesktopLoadGameActionKind::Rename => "rename",
            DesktopLoadGameActionKind::Export => "export",
        };
        let action = DesktopLoadGameAction {
            slot: slot.index(),
            file: slot.file.display().to_string(),
            map_name: slot.meta.as_ref().and_then(|meta| meta.map_name.clone()),
            timestamp: slot.timestamp(),
            kind,
            status: status.into(),
        };
        if kind == DesktopLoadGameActionKind::Load {
            self.start_load_game_pending_load(action.clone());
        } else if kind == DesktopLoadGameActionKind::ToggleAutosave {
            let enabled = !self.load_game_slot_is_autosave(&slot);
            self.settings_overrides
                .insert(slot.autosave_setting_key(), enabled.to_string());
            self.refresh_load_game_slots();
        } else if kind == DesktopLoadGameActionKind::Delete {
            let mut delete_error = None;
            for target in slot.delete_targets() {
                match std::fs::remove_file(&target) {
                    Ok(()) => {}
                    Err(error) if error.kind() == io::ErrorKind::NotFound => {}
                    Err(error) => {
                        delete_error = Some(format!(
                            "failed to delete save {}: {error}",
                            target.display()
                        ));
                        break;
                    }
                }
            }
            if let Some(error) = delete_error {
                self.load_game_error = Some(error);
            } else {
                self.refresh_load_game_slots();
                self.load_game_scroll_offset = self.load_game_scroll_offset.min(
                    self.filtered_load_game_slot_indices()
                        .len()
                        .saturating_sub(1),
                );
            }
        } else if kind == DesktopLoadGameActionKind::Export {
            let request = platform.show_file_chooser(false, "@save", "msav");
            self.last_load_game_export_request = Some(request);
        } else if kind == DesktopLoadGameActionKind::Rename {
            self.load_game_rename_dialog_slot = Some(slot_index);
            self.load_game_rename_text = self.load_game_slot_display_title(&slot);
        }
        self.last_load_game_action = Some(action.clone());
        Some(action)
    }

    fn start_load_game_pending_load(&mut self, action: DesktopLoadGameAction) {
        self.load_game_error = None;
        self.last_load_game_result = None;
        self.load_game_search_focused = false;
        self.load_game_rename_dialog_slot = None;
        self.load_game_delete_dialog_slot = None;
        self.load_game_rename_text.clear();
        self.load_game_pending_load = Some(DesktopLoadGamePendingLoad::new(action));
    }

    fn tick_load_game_pending_load(&mut self) -> bool {
        let should_complete = match self.load_game_pending_load.as_mut() {
            Some(pending) => {
                if pending.frames_remaining > 0 {
                    pending.frames_remaining -= 1;
                }
                pending.frames_remaining == 0
            }
            None => false,
        };
        if should_complete {
            self.complete_load_game_pending_load();
        }
        should_complete
    }

    fn read_load_game_pending_save_meta(
        action: &DesktopLoadGameAction,
    ) -> Result<SaveMeta, String> {
        let path = PathBuf::from(&action.file);
        let primary = fs::read(&path).map_err(|error| {
            format!(
                "LoadDialog.runLoadSave failed to read save {}: {error}",
                path.display()
            )
        })?;
        let backup_path = backup_file_for_path(&path);
        let backup = fs::read(&backup_path).ok();
        read_deflated_save_meta_with_backup(primary.as_slice(), backup.as_deref())
            .map_err(|error| format!("@save.corrupted: {error}"))
    }

    fn apply_loaded_save_meta_to_state(&mut self, action: &DesktopLoadGameAction, meta: SaveMeta) {
        let mut rules = meta.rules.clone();
        let _ = rules.apply_json_str(&meta.rules_json);
        rules.editor = false;
        rules.sector = None;
        self.game_state.rules = rules;
        self.game_state.set_sector(None);
        self.game_state.wave = meta.wave;
        let mut map = MapDescriptor::from_save_meta(action.file.clone(), &meta);
        if let Some(map_name) = meta.map_name.clone().filter(|name| !name.trim().is_empty()) {
            map.tags.entry("name".into()).or_insert(map_name);
        }
        self.game_state.map = map;
    }

    fn reset_network_before_load_save(&mut self) {
        self.net_client.net_mut().reset();
        self.net_client.set_connect_config(None);
        self.last_applied_world_data = None;
    }

    fn fail_load_game_pending_load(
        &mut self,
        mut action: DesktopLoadGameAction,
        error: String,
    ) -> DesktopLoadGameAction {
        action.status = "corrupted".into();
        self.game_state.set(GameStateState::Menu);
        self.sync_runtime_state_from_game_state();
        self.load_game_error = Some("@save.corrupted".into());
        self.last_menu_guard_message = Some(error);
        self.last_load_game_result = Some(action.clone());
        action
    }

    fn complete_load_game_pending_load(&mut self) -> Option<DesktopLoadGameAction> {
        let mut pending = self.load_game_pending_load.take()?;
        self.reset_network_before_load_save();
        let meta = match Self::read_load_game_pending_save_meta(&pending.action) {
            Ok(meta) => meta,
            Err(error) => return Some(self.fail_load_game_pending_load(pending.action, error)),
        };
        self.apply_loaded_save_meta_to_state(&pending.action, meta);
        pending.action.status = "loaded".into();
        self.game_state.set(GameStateState::Playing);
        self.sync_runtime_state_from_game_state();
        self.active_menu_route = None;
        self.load_game_search_focused = false;
        self.load_game_rename_dialog_slot = None;
        self.load_game_delete_dialog_slot = None;
        self.load_game_rename_text.clear();
        self.save_game_new_dialog_open = false;
        self.save_game_new_text.clear();
        self.save_game_overwrite_dialog_slot = None;
        self.save_game_pending_save = None;
        self.last_menu_route_shell_action = None;
        self.last_menu_guard_message = Some(format!(
            "LoadDialog.runLoadSave loaded slot {}",
            pending.action.slot
        ));
        self.last_load_game_result = Some(pending.action.clone());
        Some(pending.action)
    }

    fn dispatch_load_game_import_with_platform<P: Platform>(
        &mut self,
        platform: &mut P,
    ) -> FileChooserRequest {
        let request = platform.show_file_chooser(true, "@save.import", "msav");
        self.last_load_game_import_request = Some(request.clone());
        request
    }

    fn next_load_game_slot_file(&self) -> PathBuf {
        let save_dir = PathBuf::from(&self.client.context.paths.save_dir);
        let mut index = 0usize;
        loop {
            let candidate = save_dir.join(format!("{index}.msav"));
            if !candidate.exists() {
                return candidate;
            }
            index += 1;
        }
    }

    fn import_load_game_save_file(
        &mut self,
        source: impl AsRef<Path>,
    ) -> Result<DesktopLoadGameImportResult, String> {
        let source = source.as_ref();
        let bytes = std::fs::read(source).map_err(|error| {
            format!("failed to read imported save {}: {error}", source.display())
        })?;
        let meta = read_deflated_save_meta(bytes.as_slice()).map_err(|error| {
            let message = format!("@save.import.invalid: {error}");
            self.load_game_error = Some(message.clone());
            message
        })?;
        if meta.has_sector() {
            self.load_game_error = Some("@save.nocampaign".into());
            return Err("@save.nocampaign".into());
        }
        let destination = self.next_load_game_slot_file();
        if let Some(parent) = destination.parent() {
            std::fs::create_dir_all(parent).map_err(|error| {
                format!("failed to create save dir {}: {error}", parent.display())
            })?;
        }
        std::fs::write(&destination, &bytes).map_err(|error| {
            format!(
                "failed to import save {} -> {}: {error}",
                source.display(),
                destination.display()
            )
        })?;
        let imported_name = source
            .file_stem()
            .and_then(|stem| stem.to_str())
            .filter(|stem| !stem.trim().is_empty())
            .unwrap_or("untitled")
            .to_string();
        self.load_game_slot_names.insert(
            SaveSlotRecord::new(destination.clone()).name_setting_key(),
            imported_name,
        );
        self.refresh_load_game_slots();
        let result = DesktopLoadGameImportResult {
            source: source.display().to_string(),
            destination: destination.display().to_string(),
            map_name: meta.map_name.clone(),
            timestamp: meta.timestamp,
            status: "imported".into(),
        };
        self.last_load_game_import_result = Some(result.clone());
        Ok(result)
    }

    fn normalize_load_game_export_destination(destination: impl AsRef<Path>) -> PathBuf {
        let destination = destination.as_ref();
        if destination
            .extension()
            .and_then(|extension| extension.to_str())
            .is_some_and(|extension| extension.eq_ignore_ascii_case("msav"))
        {
            destination.to_path_buf()
        } else {
            let mut normalized = destination.to_path_buf();
            normalized.set_extension("msav");
            normalized
        }
    }

    fn export_load_game_save_file_to(
        &mut self,
        slot_index: usize,
        destination: impl AsRef<Path>,
    ) -> Result<DesktopLoadGameExportResult, String> {
        let slot = self
            .load_game_slots
            .get(slot_index)
            .cloned()
            .ok_or_else(|| format!("missing save slot {slot_index}"))?;
        let destination = Self::normalize_load_game_export_destination(destination);
        if let Some(parent) = destination.parent() {
            std::fs::create_dir_all(parent).map_err(|error| {
                format!("failed to create export dir {}: {error}", parent.display())
            })?;
        }
        std::fs::copy(&slot.file, &destination).map_err(|error| {
            let message = format!(
                "failed to export save {} -> {}: {error}",
                slot.file.display(),
                destination.display()
            );
            self.load_game_error = Some(message.clone());
            message
        })?;
        let result = DesktopLoadGameExportResult {
            slot: slot.index(),
            source: slot.file.display().to_string(),
            destination: destination.display().to_string(),
            map_name: slot.meta.as_ref().and_then(|meta| meta.map_name.clone()),
            timestamp: slot.timestamp(),
            status: "exported".into(),
        };
        self.last_load_game_export_result = Some(result.clone());
        Ok(result)
    }

    fn rename_load_game_slot(
        &mut self,
        slot_index: usize,
        new_name: impl Into<String>,
    ) -> Result<DesktopLoadGameRenameResult, String> {
        let slot = self
            .load_game_slots
            .get(slot_index)
            .cloned()
            .ok_or_else(|| format!("missing save slot {slot_index}"))?;
        let new_name = new_name.into();
        if new_name.is_empty() {
            let message = "@save.rename.text".to_string();
            self.load_game_error = Some(message.clone());
            return Err(message);
        }
        let previous_name = self.load_game_slot_display_title(&slot);
        let setting_key = slot.name_setting_key();
        self.load_game_slot_names
            .insert(setting_key.clone(), new_name.clone());
        let result = DesktopLoadGameRenameResult {
            slot: slot.index(),
            setting_key,
            previous_name,
            new_name,
            status: "renamed".into(),
        };
        self.last_load_game_rename_result = Some(result.clone());
        Ok(result)
    }

    fn write_save_game_slot_snapshot(
        &mut self,
        destination: impl AsRef<Path>,
        name: impl Into<String>,
        status: &'static str,
    ) -> Result<DesktopSaveGameResult, String> {
        let destination = destination.as_ref();
        let name = name.into();
        if name.is_empty() {
            let message = "@save.newslot".to_string();
            self.load_game_error = Some(message.clone());
            return Err(message);
        }
        if let Some(parent) = destination.parent() {
            std::fs::create_dir_all(parent).map_err(|error| {
                format!("failed to create save dir {}: {error}", parent.display())
            })?;
        }
        let timestamp = current_millis();
        let mut tags = BTreeMap::new();
        tags.insert("version".into(), LATEST_SAVE_VERSION.to_string());
        tags.insert("build".into(), UPSTREAM_BASELINE.to_string());
        tags.insert("saved".into(), timestamp.to_string());
        tags.insert("playtime".into(), "0".into());
        tags.insert("mapname".into(), name.clone());
        tags.insert("wave".into(), "0".into());
        tags.insert("rules".into(), "{}".into());
        tags.insert("mods".into(), "[]".into());
        let mut bytes = Vec::new();
        write_deflated_save_meta_prefix(&mut bytes, LATEST_SAVE_VERSION, &tags)
            .map_err(|error| format!("failed to encode save meta: {error}"))?;
        std::fs::write(destination, bytes)
            .map_err(|error| format!("failed to write save {}: {error}", destination.display()))?;
        let slot = SaveSlotRecord::new(destination.to_path_buf());
        self.load_game_slot_names
            .insert(slot.name_setting_key(), name.clone());
        self.refresh_load_game_slots();
        let result = DesktopSaveGameResult {
            slot: slot.index(),
            file: destination.display().to_string(),
            name,
            timestamp,
            status: status.into(),
        };
        self.last_save_game_result = Some(result.clone());
        Ok(result)
    }

    fn start_save_game_pending_save(&mut self, operation: DesktopSaveGamePendingOperation) {
        self.load_game_error = None;
        self.save_game_pending_save = Some(DesktopSaveGamePendingSave::new(operation));
    }

    fn tick_save_game_pending_save(&mut self) -> bool {
        let should_complete = match self.save_game_pending_save.as_mut() {
            Some(pending) => {
                if pending.frames_remaining > 0 {
                    pending.frames_remaining -= 1;
                }
                pending.frames_remaining == 0
            }
            None => false,
        };
        if should_complete {
            self.complete_save_game_pending_save();
        }
        should_complete
    }

    fn complete_save_game_pending_save(&mut self) -> Option<DesktopSaveGameResult> {
        let pending = self.save_game_pending_save.take()?;
        let close_route_after_success = pending.operation.closes_route_after_success();
        let result = match pending.operation {
            DesktopSaveGamePendingOperation::New { name } => self.add_save_game_slot(name),
            DesktopSaveGamePendingOperation::Overwrite { slot_index } => {
                self.overwrite_save_game_slot(slot_index)
            }
        };

        match result {
            Ok(result) => {
                self.load_game_error = None;
                if close_route_after_success {
                    self.active_menu_route = None;
                    self.load_game_search_focused = false;
                    self.load_game_rename_dialog_slot = None;
                    self.load_game_rename_text.clear();
                    self.save_game_new_dialog_open = false;
                    self.save_game_new_text.clear();
                    self.save_game_overwrite_dialog_slot = None;
                }
                Some(result)
            }
            Err(error) => {
                self.load_game_error = Some(format!("[accent]@savefail: {error}"));
                None
            }
        }
    }

    fn add_save_game_slot(
        &mut self,
        name: impl Into<String>,
    ) -> Result<DesktopSaveGameResult, String> {
        let destination = self.next_load_game_slot_file();
        self.write_save_game_slot_snapshot(destination, name, "created")
    }

    fn overwrite_save_game_slot(
        &mut self,
        slot_index: usize,
    ) -> Result<DesktopSaveGameResult, String> {
        let slot = self
            .load_game_slots
            .get(slot_index)
            .cloned()
            .ok_or_else(|| format!("missing save slot {slot_index}"))?;
        let name = self.load_game_slot_display_title(&slot);
        self.write_save_game_slot_snapshot(slot.file, name, "saved")
    }

    fn max_load_game_scroll_offset_for_counts(
        total_slots: usize,
        visible_rows: usize,
        columns: usize,
    ) -> usize {
        let total_rows = total_slots.div_ceil(columns.max(1));
        total_rows.saturating_sub(visible_rows.max(1))
    }

    fn max_load_game_scroll_offset(&self, list: RenderRect) -> usize {
        Self::max_load_game_scroll_offset_for_counts(
            self.filtered_load_game_slot_indices().len(),
            Self::load_game_visible_row_capacity_for_list(list),
            Self::load_game_slot_column_count_for_list(list),
        )
    }

    fn apply_load_game_scroll_delta(
        &mut self,
        surface_size: DesktopSurfaceSize,
        delta_y: f32,
    ) -> bool {
        if !matches!(
            self.active_menu_route,
            Some(DesktopMenuRoute::LoadGame | DesktopMenuRoute::SaveGame)
        ) {
            return false;
        }
        let Some(cursor) = self.last_menu_cursor else {
            return false;
        };
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel = Self::active_menu_route_shell_panel_for_route(
            viewport,
            self.active_menu_route.unwrap(),
        );
        let list = Self::load_game_list_rect_for_panel(panel);
        if !list.contains_point(cursor) {
            return false;
        }
        let max = self.max_load_game_scroll_offset(list);
        if max == 0 {
            return false;
        }
        let current = self.load_game_scroll_offset.min(max);
        let rows = delta_y.abs().ceil().max(1.0) as isize;
        let step = if delta_y < 0.0 {
            rows
        } else if delta_y > 0.0 {
            -rows
        } else {
            0
        };
        let next = (current as isize + step).clamp(0, max as isize) as usize;
        self.load_game_scroll_offset = next;
        next != current
    }

    fn active_menu_route_shell_panel_for_viewport(viewport: RenderViewport) -> RenderRect {
        let panel_width = (viewport.width * 0.46).clamp(280.0, 520.0);
        let panel_height = 220.0;
        RenderRect::new(
            viewport.x + viewport.width - panel_width - 48.0,
            viewport.y + (viewport.height - panel_height) * 0.5,
            panel_width,
            panel_height,
        )
    }

    fn active_menu_route_shell_panel_for_route(
        viewport: RenderViewport,
        route: DesktopMenuRoute,
    ) -> RenderRect {
        if route == DesktopMenuRoute::About {
            let panel_width = (viewport.width * 0.72).clamp(360.0, 720.0);
            let panel_height = (viewport.height - 120.0).clamp(360.0, 700.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Settings {
            let panel_width = (viewport.width * 0.62).clamp(340.0, 680.0);
            let panel_height = (viewport.height - 150.0).clamp(300.0, 560.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Host {
            let panel_width = (viewport.width * 0.58).clamp(360.0, 640.0);
            let panel_height = (viewport.height - 160.0).clamp(300.0, 520.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Database {
            let panel_width = (viewport.width * 0.68).clamp(380.0, 760.0);
            let panel_height = (viewport.height - 130.0).clamp(330.0, 620.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::TechTree {
            let panel_width = (viewport.width * 0.70).clamp(420.0, 780.0);
            let panel_height = (viewport.height - 110.0).clamp(360.0, 650.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Join {
            let available_width = (viewport.width - 96.0).max(460.0);
            let panel_width = (viewport.width * 0.92)
                .clamp(520.0, 1740.0)
                .min(available_width);
            let panel_height = (viewport.height - 82.0).clamp(540.0, 760.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if matches!(
            route,
            DesktopMenuRoute::LoadGame | DesktopMenuRoute::SaveGame
        ) {
            let panel_width = (viewport.width * 0.62).clamp(380.0, 720.0);
            let panel_height = (viewport.height - 130.0).clamp(340.0, 620.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if matches!(
            route,
            DesktopMenuRoute::CustomGame | DesktopMenuRoute::Editor
        ) {
            let panel_width = (viewport.width * 0.66).clamp(380.0, 740.0);
            let panel_height = (viewport.height - 130.0).clamp(330.0, 600.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Schematics {
            let panel_width = (viewport.width * 0.66).clamp(380.0, 740.0);
            let panel_height = (viewport.height - 80.0).clamp(430.0, 700.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        if route == DesktopMenuRoute::Mods {
            let panel_width = (viewport.width * 0.68).clamp(380.0, 760.0);
            let panel_height = (viewport.height - 120.0).clamp(360.0, 640.0);
            return RenderRect::new(
                viewport.x + viewport.width - panel_width - 48.0,
                viewport.y + (viewport.height - panel_height) * 0.5,
                panel_width,
                panel_height,
            );
        }
        Self::active_menu_route_shell_panel_for_viewport(viewport)
    }

    #[cfg(test)]
    fn pause_overlay_panel_for_viewport(viewport: RenderViewport) -> RenderRect {
        Self::pause_overlay_panel_for_viewport_with_button_count(viewport, 6)
    }

    fn pause_overlay_panel_for_viewport_with_button_count(
        viewport: RenderViewport,
        button_count: usize,
    ) -> RenderRect {
        let button_count = button_count.max(1);
        let panel_width = PAUSE_OVERLAY_PANEL_WIDTH.clamp(280.0, 360.0);
        let panel_height = PAUSE_OVERLAY_BUTTON_TOP_PADDING
            + PAUSE_OVERLAY_TITLE_HEIGHT
            + 18.0
            + button_count as f32 * PAUSE_OVERLAY_BUTTON_HEIGHT
            + button_count.saturating_sub(1) as f32 * PAUSE_OVERLAY_BUTTON_GAP
            + PAUSE_OVERLAY_BUTTON_BOTTOM_PADDING;
        RenderRect::new(
            viewport.x + 48.0,
            viewport.y
                + ((viewport.height - panel_height).max(0.0) * 0.5)
                    .min(
                        viewport.y + viewport.height
                            - panel_height
                            - PAUSE_OVERLAY_PANEL_TOP_MARGIN,
                    )
                    .max(viewport.y + PAUSE_OVERLAY_PANEL_TOP_MARGIN),
            panel_width,
            panel_height,
        )
    }

    #[cfg(test)]
    fn pause_overlay_panel_for_current_state(&self, viewport: RenderViewport) -> RenderRect {
        Self::pause_overlay_panel_for_viewport_with_button_count(
            viewport,
            self.pause_overlay_button_specs().len(),
        )
    }

    #[cfg(test)]
    fn pause_overlay_button_count_from_panel(panel: RenderRect) -> usize {
        let available_height = (panel.height
            - PAUSE_OVERLAY_BUTTON_TOP_PADDING
            - PAUSE_OVERLAY_TITLE_HEIGHT
            - 18.0
            - PAUSE_OVERLAY_BUTTON_BOTTOM_PADDING)
            .max(0.0);
        let total_button_step = PAUSE_OVERLAY_BUTTON_HEIGHT + PAUSE_OVERLAY_BUTTON_GAP;
        (((available_height + PAUSE_OVERLAY_BUTTON_GAP) / total_button_step)
            .round()
            .max(1.0)) as usize
    }

    #[cfg(test)]
    fn pause_overlay_button_rect_for_panel(panel: RenderRect, index: usize) -> RenderRect {
        let button_count = Self::pause_overlay_button_count_from_panel(panel);
        Self::pause_overlay_button_rect_for_panel_with_button_count(panel, index, button_count)
    }

    fn pause_overlay_button_rect_for_panel_with_button_count(
        panel: RenderRect,
        index: usize,
        button_count: usize,
    ) -> RenderRect {
        let button_count = button_count.max(1);
        let total_height = button_count as f32 * PAUSE_OVERLAY_BUTTON_HEIGHT
            + button_count.saturating_sub(1) as f32 * PAUSE_OVERLAY_BUTTON_GAP;
        let button_width =
            PAUSE_OVERLAY_BUTTON_WIDTH.min(panel.width - PAUSE_OVERLAY_BUTTON_SIDE_PADDING * 2.0);
        let start_y = panel.y
            + PAUSE_OVERLAY_BUTTON_TOP_PADDING
            + PAUSE_OVERLAY_TITLE_HEIGHT
            + 18.0
            + (panel.height
                - PAUSE_OVERLAY_BUTTON_TOP_PADDING
                - PAUSE_OVERLAY_TITLE_HEIGHT
                - 18.0
                - PAUSE_OVERLAY_BUTTON_BOTTOM_PADDING
                - total_height)
                * 0.0;
        RenderRect::new(
            panel.x + (panel.width - button_width) * 0.5,
            start_y + index as f32 * (PAUSE_OVERLAY_BUTTON_HEIGHT + PAUSE_OVERLAY_BUTTON_GAP),
            button_width.max(1.0),
            PAUSE_OVERLAY_BUTTON_HEIGHT,
        )
    }

    fn pause_overlay_net_active(&self) -> bool {
        self.net_client
            .state()
            .lock()
            .map(|state| state.connected || state.connecting)
            .unwrap_or(false)
    }

    fn pause_overlay_has_objective(&self) -> bool {
        self.game_state
            .get_sector()
            .and_then(|sector| sector.preset.as_ref())
            .and_then(|preset| preset.description.as_ref())
            .is_some_and(|description| !description.trim().is_empty())
    }

    fn pause_overlay_button_specs(&self) -> Vec<DesktopPausedOverlayButtonSpec> {
        let net_active = self.pause_overlay_net_active();
        let is_campaign = self.game_state.is_campaign();
        let is_editor = self.game_state.is_editor();
        let mut specs = Vec::new();

        if is_campaign {
            if self.pause_overlay_has_objective() {
                specs.push(DesktopPausedOverlayButtonSpec {
                    action: DesktopPausedOverlayAction::Objective,
                    label: "@objective",
                    icon: Some("info"),
                    enabled: true,
                });
            }
            specs.push(DesktopPausedOverlayButtonSpec {
                action: DesktopPausedOverlayAction::Abandon,
                label: "@abandon",
                icon: Some("cancel"),
                enabled: !net_active && !self.game_state.game_over,
            });
        }

        specs.push(DesktopPausedOverlayButtonSpec {
            action: DesktopPausedOverlayAction::Back,
            label: "@back",
            icon: Some("left"),
            enabled: true,
        });
        specs.push(DesktopPausedOverlayButtonSpec {
            action: DesktopPausedOverlayAction::Settings,
            label: "@settings",
            icon: Some("settings"),
            enabled: true,
        });

        if !is_campaign && !is_editor {
            specs.push(DesktopPausedOverlayButtonSpec {
                action: DesktopPausedOverlayAction::SaveGame,
                label: "@savegame",
                icon: Some("save"),
                enabled: true,
            });
            specs.push(DesktopPausedOverlayButtonSpec {
                action: DesktopPausedOverlayAction::LoadGame,
                label: "@loadgame",
                icon: Some("load"),
                enabled: !net_active,
            });
        }

        specs.push(DesktopPausedOverlayButtonSpec {
            action: DesktopPausedOverlayAction::HostServer,
            label: if is_editor {
                "@hostserver.mobile"
            } else {
                "@hostserver"
            },
            icon: Some("host"),
            enabled: !net_active,
        });

        if is_editor {
            specs.push(DesktopPausedOverlayButtonSpec {
                action: DesktopPausedOverlayAction::WorldProcessors,
                label: "@editor.worldprocessors",
                icon: Some("logic"),
                enabled: true,
            });
        }

        specs.push(DesktopPausedOverlayButtonSpec {
            action: DesktopPausedOverlayAction::Quit,
            label: "@quit",
            icon: Some("exit"),
            enabled: true,
        });

        specs
    }

