    pub fn load_join_community_groups_from_server_json(&mut self, value: &str) -> usize {
        let groups = join_community_groups_from_server_json(value);
        if groups.is_empty() {
            return 0;
        }
        self.join_community_groups = groups;
        self.join_community_groups.len()
    }

    fn visible_join_community_groups(&self) -> Vec<(usize, &DesktopJoinCommunityGroup)> {
        let mut groups = self
            .join_community_groups
            .iter()
            .enumerate()
            .filter(|(_, group)| self.join_show_hidden || !self.join_community_group_hidden(group))
            .filter(|(_, group)| group.matches_query(&self.join_search))
            .collect::<Vec<_>>();
        if groups.len() > 1 {
            let java_half_column_offset = groups.len() / 2;
            groups.rotate_left(java_half_column_offset);
        }
        groups
    }

    fn join_community_group_connect_target(
        group: &DesktopJoinCommunityGroup,
    ) -> Option<DesktopConnectTarget> {
        if let Some(host) = group.hosts.first() {
            return Some(DesktopConnectTarget {
                host: host.address.clone(),
                port: u16::try_from(host.port).ok()?,
            });
        }
        group
            .addresses
            .first()
            .and_then(|address| parse_host_port(address))
    }

    fn join_community_group_connect_version(group: &DesktopJoinCommunityGroup) -> Option<i32> {
        group.hosts.first().map(|host| host.version)
    }

    fn join_server_version_mismatch_message(&self, server_version: i32) -> Option<String> {
        if server_version == DEFAULT_CLIENT_VERSION
            || DEFAULT_CLIENT_VERSION == -1
            || server_version == -1
        {
            return None;
        }

        let reason_key = if server_version > DEFAULT_CLIENT_VERSION {
            "server.kicked.clientOutdated"
        } else {
            "server.kicked.serverOutdated"
        };
        let reason = upstream_menu_bundle_value_for_locale(&self.settings_locale, reason_key)
            .unwrap_or(if server_version > DEFAULT_CLIENT_VERSION {
                "Outdated client! Update your game!"
            } else {
                "Outdated server! Ask the host to update!"
            });
        let client_version = DEFAULT_CLIENT_VERSION.to_string();
        let server_version = server_version.to_string();
        Some(format!(
            "[scarlet]{reason}\n[]{}",
            self.format_bundle_text(
                "server.versions",
                &[client_version.as_str(), server_version.as_str()]
            )
        ))
    }

    fn safe_connect_to_target(
        &mut self,
        target: DesktopConnectTarget,
        server_version: Option<i32>,
    ) -> io::Result<()> {
        if let Some(message) =
            server_version.and_then(|version| self.join_server_version_mismatch_message(version))
        {
            self.connect_target = Some(target);
            self.connect_error = Some(message.clone());
            self.join_version_mismatch_dialog_message = Some(message);
            self.join_connection_error_dialog_message = None;
            self.join_reconnect_target = None;
            self.join_reconnect_receiver = None;
            self.join_add_dialog_open = false;
            self.join_add_server_focused = false;
            self.join_add_server_edit_index = None;
            self.join_info_dialog_open = false;
            self.join_delete_dialog_index = None;
            self.join_search_focused = false;
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                "server version mismatch",
            ));
        }
        self.connect_to_target(target)
    }

    fn delete_join_saved_server_at(&mut self, index: usize) -> bool {
        if index >= self.join_saved_servers.len() {
            return false;
        }
        let removed = self.join_saved_servers.remove(index);
        if index < self.join_saved_server_refresh_states.len() {
            self.join_saved_server_refresh_states.remove(index);
        }
        if self.connect_target.as_ref() == Some(&removed) {
            self.connect_target = self.join_saved_servers.first().cloned();
        }
        self.connect_error = None;
        self.join_add_dialog_open = false;
        self.join_add_server_focused = false;
        self.join_add_server_edit_index = None;
        self.join_delete_dialog_index = None;
        self.persist_join_saved_servers_to_settings();
        true
    }

    fn refresh_join_local_hosts(&mut self) {
        let (tx, rx) = mpsc::channel::<Option<Host>>();
        let host_tx = tx.clone();
        self.join_local_hosts.clear();
        self.join_local_discovering = true;
        self.join_local_discovery_finished = false;
        self.join_local_discovery_receiver = Some(Arc::new(Mutex::new(rx)));
        self.net_client.net_mut().discover_servers(
            Box::new(move |host| {
                let _ = host_tx.send(Some(host));
            }),
            Box::new(move || {
                let _ = tx.send(None);
            }),
        );
    }

    fn poll_join_local_discovery(&mut self) {
        let Some(receiver) = self.join_local_discovery_receiver.as_ref().cloned() else {
            return;
        };
        let mut finished = false;
        let mut hosts = Vec::new();
        let receiver = receiver.lock().unwrap();
        while let Ok(message) = receiver.try_recv() {
            match message {
                Some(host) => hosts.push(host),
                None => finished = true,
            }
        }
        for host in hosts {
            let duplicate = self
                .join_local_hosts
                .iter()
                .any(|known| known.address == host.address && known.port == host.port);
            if !duplicate {
                self.join_local_hosts.push(host);
            }
        }
        if finished {
            self.join_local_discovering = false;
            self.join_local_discovery_finished = true;
            self.join_local_discovery_receiver = None;
        }
    }

