    fn join_route_server_card_index_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<usize> {
        let local_count = self.join_route_visible_local_host_count_for_panel(panel);
        let saved_capacity = self.join_route_visible_saved_server_card_capacity_for_panel(panel);
        self.join_saved_server_snapshots()
            .into_iter()
            .enumerate()
            .filter(|(_, snapshot)| snapshot.matches_query(&self.join_search))
            .take(saved_capacity)
            .enumerate()
            .find_map(|(visible_index, (index, _))| {
                let rect =
                    Self::join_route_server_card_rect_for_panel(panel, local_count + visible_index);
                rect.contains_point(point).then_some(index)
            })
    }

