    fn toggle_map_play_custom_rule(&mut self, index: usize, toggle: DesktopCustomRulesToggle) {
        let Some(map) = self.map_list_cards.get(index) else {
            return;
        };
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        if toggle.enabled(&rules) {
            toggle.toggle(&mut rules);
            self.map_play_rules = Some(rules);
        }
    }

    fn adjust_map_play_custom_rule_number(
        &mut self,
        index: usize,
        number: DesktopCustomRulesNumber,
        direction: i32,
    ) {
        let Some(map) = self.map_list_cards.get(index) else {
            return;
        };
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        if number.enabled(&rules) {
            number.adjust(&mut rules, direction);
            self.map_play_rules = Some(rules);
            self.map_play_rules_error = None;
        }
    }

    fn toggle_map_play_banned_content(
        &mut self,
        index: usize,
        kind: DesktopBannedContentKind,
        candidate_index: usize,
    ) {
        let Some(map) = self.map_list_cards.get(index) else {
            return;
        };
        let Some(name) = self
            .map_play_banned_content_candidate_names(kind)
            .get(candidate_index)
            .cloned()
        else {
            return;
        };
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        kind.toggle(&mut rules, &name);
        self.map_play_rules = Some(rules);
        self.map_play_rules_error = None;
    }

    fn set_all_map_play_banned_content(
        &mut self,
        index: usize,
        kind: DesktopBannedContentKind,
        banned: bool,
    ) {
        let Some(map) = self.map_list_cards.get(index) else {
            return;
        };
        let names = self.map_play_banned_content_candidate_names(kind);
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        kind.set_all(&mut rules, names, banned);
        let max = self.map_play_banned_content_max_scroll_offset(kind, &rules);
        self.map_play_banned_content_scroll_offset =
            self.map_play_banned_content_scroll_offset.min(max);
        self.map_play_rules = Some(rules);
        self.map_play_rules_error = None;
    }

    fn apply_map_play_banned_content_scroll_delta(
        &mut self,
        surface_size: DesktopSurfaceSize,
        delta_y: f32,
    ) -> bool {
        if self.active_menu_route != Some(DesktopMenuRoute::CustomGame)
            || !self.map_play_customize_dialog_open
        {
            return false;
        }
        let Some(kind) = self.map_play_banned_content_dialog else {
            return false;
        };
        let Some(index) = self.map_play_dialog_index else {
            return false;
        };
        let Some(cursor) = self.last_menu_cursor else {
            return false;
        };
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::CustomGame);
        let dialog = Self::map_card_dialog_rect_for_panel(panel);
        let child = Self::map_play_child_dialog_rect(dialog);
        let banned_dialog = Self::map_play_banned_content_dialog_rect(child);
        if !banned_dialog.contains_point(cursor) {
            return false;
        }
        let Some(map) = self.map_list_cards.get(index) else {
            return false;
        };
        let rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        let max = self.map_play_banned_content_max_scroll_offset(kind, &rules);
        if max == 0 {
            return false;
        }
        let current = self.map_play_banned_content_scroll_offset.min(max);
        let rows = delta_y.abs().ceil().max(1.0) as isize;
        let step = if delta_y < 0.0 {
            rows
        } else if delta_y > 0.0 {
            -rows
        } else {
            0
        };
        let next = (current as isize + step).clamp(0, max as isize) as usize;
        self.map_play_banned_content_scroll_offset = next;
        next != current
    }

    fn add_map_play_weather(&mut self, index: usize, candidate_index: usize) {
        let Some(map) = self.map_list_cards.get(index) else {
            return;
        };
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        let Some(name) = self
            .map_play_weather_candidate_names(&rules)
            .get(candidate_index)
            .cloned()
        else {
            return;
        };
        let Some(weather) = self.content_loader.weather_by_name(&name) else {
            return;
        };
        rules.weather.push(WeatherEntry::new(weather.weather()));
        self.map_play_rules = Some(rules);
        self.map_play_rules_error = None;
    }

    fn remove_map_play_weather(&mut self, index: usize, weather_index: usize) {
        let Some(map) = self.map_list_cards.get(index) else {
            return;
        };
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        if weather_index < rules.weather.len() {
            rules.weather.remove(weather_index);
            self.map_play_rules = Some(rules);
            self.map_play_rules_error = None;
        }
    }

    fn toggle_map_play_weather_always(&mut self, index: usize, weather_index: usize) {
        let Some(map) = self.map_list_cards.get(index) else {
            return;
        };
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        if let Some(entry) = rules.weather.get_mut(weather_index) {
            entry.always = !entry.always;
            self.map_play_rules = Some(rules);
            self.map_play_rules_error = None;
        }
    }

    fn adjust_map_play_weather_number(
        &mut self,
        index: usize,
        weather_index: usize,
        number: DesktopWeatherNumber,
        direction: i32,
    ) {
        let Some(map) = self.map_list_cards.get(index) else {
            return;
        };
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        if let Some(entry) = rules.weather.get_mut(weather_index) {
            number.adjust(entry, direction);
            self.map_play_rules = Some(rules);
            self.map_play_rules_error = None;
        }
    }

    fn update_map_play_rules_for_team(&mut self, index: usize, update: impl FnOnce(&mut Rules)) {
        let Some(map) = self.map_list_cards.get(index) else {
            return;
        };
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        update(&mut rules);
        self.map_play_rules = Some(rules);
        self.map_play_rules_error = None;
    }

    fn select_map_play_default_team(&mut self, index: usize, team_id: usize) {
        self.update_map_play_rules_for_team(index, |rules| {
            rules.default_team = team_id as i32;
        });
    }

    fn select_map_play_wave_team(&mut self, index: usize, team_id: usize) {
        self.update_map_play_rules_for_team(index, |rules| {
            rules.wave_team = team_id as i32;
        });
    }

    fn toggle_map_play_team_rule(
        &mut self,
        index: usize,
        team_id: usize,
        toggle: DesktopTeamRuleToggle,
    ) {
        self.update_map_play_rules_for_team(index, |rules| {
            toggle.toggle(rules.teams.get_or_insert(team_id));
        });
    }

    fn adjust_map_play_team_rule_number(
        &mut self,
        index: usize,
        team_id: usize,
        number: DesktopTeamRuleNumber,
        direction: i32,
    ) {
        self.update_map_play_rules_for_team(index, |rules| {
            number.adjust(rules.teams.get_or_insert(team_id), direction);
        });
    }

    fn map_play_rules_clipboard_json(rules: &Rules) -> String {
        let mode_name = rules.mode_name.as_deref().unwrap_or("custom");
        format!(
            concat!(
                "{{",
                "\"waves\":{},",
                "\"waveSending\":{},",
                "\"waveTimer\":{},",
                "\"winWave\":{},",
                "\"infiniteResources\":{},",
                "\"allowEditRules\":{},",
                "\"schematicsAllowed\":{},",
                "\"hideBannedBlocks\":{},",
                "\"blockWhitelist\":{},",
                "\"unitWhitelist\":{},",
                "\"bannedBlocks\":{},",
                "\"bannedUnits\":{},",
                "\"weather\":{},",
                "\"attackMode\":{},",
                "\"pvp\":{},",
                "\"coreCapture\":{},",
                "\"waveSpacing\":{},",
                "\"initialWaveSpacing\":{},",
                "\"dropZoneRadius\":{},",
                "\"defaultTeam\":{},",
                "\"waveTeam\":{},",
                "\"teams\":{},",
                "\"modeName\":\"{}\"",
                "}}"
            ),
            rules.waves,
            rules.wave_sending,
            rules.wave_timer,
            rules.win_wave,
            rules.infinite_resources,
            rules.allow_edit_rules,
            rules.schematics_allowed,
            rules.hide_banned_blocks,
            rules.block_whitelist,
            rules.unit_whitelist,
            json_string_array_from_set(&rules.banned_blocks),
            json_string_array_from_set(&rules.banned_units),
            json_weather_entries(&rules.weather),
            rules.attack_mode,
            rules.pvp,
            rules.core_capture,
            rules.wave_spacing,
            rules.initial_wave_spacing,
            rules.drop_zone_radius,
            rules.default_team,
            rules.wave_team,
            json_team_rules(rules),
            mode_name.replace('"', "\\\"")
        )
    }

    fn copy_map_play_rules_to_clipboard_with_platform<P: Platform>(
        &mut self,
        index: usize,
        platform: &mut P,
    ) -> Option<String> {
        let map = self.map_list_cards.get(index)?;
        let rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        let json = Self::map_play_rules_clipboard_json(&rules);
        platform.set_clipboard_text(&json);
        self.last_map_play_rules_clipboard_text = Some(json.clone());
        self.map_play_rules_error = None;
        Some(json)
    }

    fn load_map_play_rules_from_clipboard_with_platform<P: Platform>(
        &mut self,
        index: usize,
        platform: &mut P,
    ) -> Result<(), String> {
        let map = self
            .map_list_cards
            .get(index)
            .ok_or_else(|| "@rules.invaliddata".to_string())?;
        let text = platform
            .get_clipboard_text()
            .or_else(|| self.last_map_play_rules_clipboard_text.clone())
            .ok_or_else(|| "@rules.invaliddata".to_string())?;
        let mut rules = self
            .map_play_rules
            .clone()
            .unwrap_or_else(|| Self::map_play_rules_for_mode(map, self.map_play_selected_mode));
        match rules.apply_json_str(&text) {
            Ok(()) => {
                self.map_play_rules = Some(rules);
                self.map_play_rules_error = None;
                Ok(())
            }
            Err(_) => {
                self.map_play_rules_error = Some("@rules.invaliddata".to_string());
                Err("@rules.invaliddata".to_string())
            }
        }
    }

    fn reset_map_play_rules_for_map(&mut self, index: usize) -> bool {
        let Some(map) = self.map_list_cards.get(index) else {
            return false;
        };
        self.map_play_rules = Some(Self::map_play_rules_for_mode(
            map,
            self.map_play_selected_mode,
        ));
        self.map_play_rules_error = None;
        true
    }

    fn map_play_high_score(&self, map: &MapDescriptor) -> i32 {
        let key = map.high_score_key();
        self.settings_overrides
            .get(&key)
            .or_else(|| {
                self.settings_overrides
                    .get(&Self::settings_storage_key("game", &key))
            })
            .and_then(|value| value.trim().parse::<i32>().ok())
            .unwrap_or(0)
    }

    fn map_editor_action_button_rect(dialog: RenderRect, index: usize) -> RenderRect {
        let width = (dialog.width - 56.0) * 0.5;
        RenderRect::new(
            dialog.x + 24.0 + index as f32 * (width + 8.0),
            dialog.y + 72.0,
            width,
            54.0,
        )
    }

    fn map_editor_preview_size_for_panel(panel: RenderRect) -> f32 {
        if panel.height > panel.width {
            160.0
        } else {
            300.0
        }
    }

    fn map_editor_preview_size_for_dialog(dialog: RenderRect, panel: RenderRect) -> f32 {
        let desired: f32 = Self::map_editor_preview_size_for_panel(panel);
        let max_by_width = ((dialog.width - 88.0) * 0.5).max(160.0);
        let max_by_height = (dialog.height - 190.0).max(160.0);
        desired.min(max_by_width).min(max_by_height)
    }

    fn map_editor_preview_rect(dialog: RenderRect, panel: RenderRect) -> RenderRect {
        let size = Self::map_editor_preview_size_for_dialog(dialog, panel);
        RenderRect::new(
            dialog.x + 28.0,
            dialog.y + dialog.height - 88.0 - size,
            size,
            size,
        )
    }

    fn map_editor_secondary_action_kind(map: &MapDescriptor) -> Option<DesktopMapCardActionKind> {
        if map.workshop {
            Some(DesktopMapCardActionKind::ViewWorkshop)
        } else if map.custom {
            Some(DesktopMapCardActionKind::Delete)
        } else {
            None
        }
    }

    pub fn refresh_map_list_cards_from_assets(&mut self) -> usize {
        let mut cards = Self::load_map_cards_from_candidate_roots();
        if cards.is_empty() {
            cards = Self::fallback_builtin_map_cards();
        }
        cards.extend(self.load_custom_map_cards_from_configured_dir());
        let mut seen_files = BTreeSet::new();
        cards.retain(|map| seen_files.insert(map.file.clone()));
        cards.sort_by_key(|map| map.plain_name());
        self.merge_map_preview_textures(&cards);
        self.map_list_cards = cards;
        self.map_list_cards.len()
    }

    fn editor_new_map_name_conflicts(&self, name: &str) -> bool {
        self.map_list_cards.iter().any(|map| map.name() == name)
    }

    fn editor_new_map_file_slug(name: &str) -> String {
        let mut slug = String::new();
        for ch in name.chars() {
            if ch.is_ascii_alphanumeric() {
                slug.push(ch.to_ascii_lowercase());
            } else if !slug.ends_with('-') {
                slug.push('-');
            }
        }
        let slug = slug.trim_matches('-');
        if slug.is_empty() {
            "new-map".to_string()
        } else {
            slug.to_string()
        }
    }

    fn editor_new_map_descriptor(name: &str) -> MapDescriptor {
        let mut tags = BTreeMap::new();
        tags.insert("name".to_string(), name.to_string());
        MapDescriptor::new(
            format!("maps/custom/{}.msav", Self::editor_new_map_file_slug(name)),
            128,
            128,
            tags,
            true,
            1,
            DEFAULT_CLIENT_VERSION,
        )
    }

    fn clear_editor_new_map_dialog(&mut self) {
        self.editor_new_map_dialog_open = false;
        self.editor_new_map_name_text.clear();
        self.editor_new_map_name_focused = false;
        self.editor_new_map_error = None;
    }

    fn clear_editor_import_map_dialog(&mut self) {
        self.editor_import_map_dialog_open = false;
        self.editor_import_error = None;
        self.editor_import_overwrite_pending = None;
    }

    fn commit_editor_new_map(&mut self) -> bool {
        if !self.editor_new_map_dialog_open {
            return false;
        }
        let name = self.editor_new_map_name_text.clone();
        if name.is_empty() {
            self.editor_new_map_error = Some("@editor.mapname".to_string());
            return false;
        }
        if self.editor_new_map_name_conflicts(&name) {
            self.editor_new_map_error = Some("@editor.exists".to_string());
            return false;
        }

        let map = Self::editor_new_map_descriptor(&name);
        self.map_list_cards.push(map.clone());
        self.map_list_cards.sort_by_key(|map| map.plain_name());
        if self.map_list_search.trim().is_empty()
            || self.map_list_filter_matches_query(&map, &self.map_list_search)
        {
            self.map_list_scroll_offset = 0;
        }
        self.last_editor_new_map_name = Some(name.clone());
        self.last_map_card_action = Some(DesktopMapCardAction::new(
            self.map_list_cards
                .iter()
                .position(|candidate| candidate.name() == name)
                .unwrap_or(0),
            DesktopMapCardActionKind::OpenInEditor,
        ));
        self.game_state.map = map.clone();
        self.game_state.rules.editor = true;
        self.runtime.state.map = map;
        self.runtime.state.rules.editor = true;
        let map_make_plan = self.client.service.state().map_make_plan();
        let summary = map_make_plan.apply_to(
            &mut self.client.service,
            &mut self.client.achievement_state,
            AchievementContext::normal(),
        );
        self.last_service_trigger_apply_summary = Some(summary);
        self.clear_editor_new_map_dialog();
        self.map_list_search_focused = false;
        self.last_menu_info_message = Some(format!("MapMakeEvent: {name}"));
        true
    }

    fn begin_edit_map_from_index(&mut self, index: usize) -> bool {
        let Some(map) = self.map_list_cards.get(index).cloned() else {
            return false;
        };
        let mut rules = map.apply_rules(Gamemode::Editor);
        rules.mode_name = Some(Gamemode::Editor.wire_name().to_string());
        rules.editor = true;
        self.game_state.map = map.clone();
        self.game_state.rules = rules.clone();
        self.runtime.state.map = map.clone();
        self.runtime.state.rules = rules;
        self.active_menu_route = Some(DesktopMenuRoute::Editor);
        self.editor_map_info_dialog_index = None;
        self.map_play_dialog_index = None;
        self.map_play_mode_help_dialog_open = false;
        self.map_play_customize_dialog_open = false;
        self.map_play_rules_edit_dialog_open = false;
        self.map_play_banned_content_dialog = None;
        self.map_play_weather_dialog_open = false;
        self.map_play_rules = None;
        self.map_play_rules_error = None;
        self.map_play_playtesting = false;
        self.clear_editor_new_map_dialog();
        self.clear_editor_import_map_dialog();
        self.last_menu_info_message = Some(format!("beginEditMap: {}", map.plain_name()));
        true
    }

    fn dispatch_editor_import_map_with_platform<P: Platform>(
        &mut self,
        platform: &mut P,
    ) -> FileChooserRequest {
        self.clear_editor_new_map_dialog();
        self.editor_import_map_dialog_open = true;
        self.editor_import_error = None;
        self.editor_import_overwrite_pending = None;
        self.map_list_search_focused = false;
        let request = platform.show_file_chooser(true, "@editor.importmap", "msav");
        self.last_editor_import_request = Some(request.clone());
        request
    }

    fn editor_import_map_name_from_tags(tags: &BTreeMap<String, String>) -> Option<String> {
        tags.get("name")
            .or_else(|| tags.get("mapname"))
            .map(|name| name.trim())
            .filter(|name| !name.is_empty())
            .map(str::to_string)
    }

    fn next_unknown_editor_import_name(&self) -> String {
        let mut index = 1usize;
        loop {
            let name = format!("unknown{index}");
            if !self
                .map_list_cards
                .iter()
                .any(|map| map.name().eq_ignore_ascii_case(&name))
            {
                return name;
            }
            index += 1;
        }
    }

    fn editor_import_source_file_name(source: &Path, map_name: &str) -> String {
        let file_name = source
            .file_name()
            .and_then(|file_name| file_name.to_str())
            .filter(|file_name| !file_name.trim().is_empty())
            .map(str::to_string)
            .unwrap_or_else(|| format!("{}.msav", Self::editor_new_map_file_slug(map_name)));
        if file_name
            .rsplit_once('.')
            .map(|(_, extension)| extension.eq_ignore_ascii_case("msav"))
            .unwrap_or(false)
        {
            file_name
        } else {
            format!("{file_name}.msav")
        }
    }

    fn editor_map_dir(&self) -> PathBuf {
        PathBuf::from(&self.client.context.paths.map_dir)
    }

    fn next_editor_map_import_destination(&self, source: &Path, map_name: &str) -> PathBuf {
        let map_dir = self.editor_map_dir();
        let file_name = Self::editor_import_source_file_name(source, map_name);
        let candidate = map_dir.join(&file_name);
        if !candidate.exists() {
            return candidate;
        }
        let path = Path::new(&file_name);
        let stem = path
            .file_stem()
            .and_then(|stem| stem.to_str())
            .filter(|stem| !stem.trim().is_empty())
            .unwrap_or("map");
        let extension = path
            .extension()
            .and_then(|extension| extension.to_str())
            .unwrap_or("msav");
        let mut index = 1usize;
        loop {
            let candidate = map_dir.join(format!("{stem}-{index}.{extension}"));
            if !candidate.exists() {
                return candidate;
            }
            index += 1;
        }
    }

    fn editor_custom_map_file_for_descriptor(&self, map: &MapDescriptor) -> Option<PathBuf> {
        let relative = map.file.strip_prefix("maps/custom/")?;
        Some(self.editor_map_dir().join(relative))
    }

    fn map_list_custom_conflict_for_name(&self, name: &str) -> Option<(usize, &MapDescriptor)> {
        self.map_list_cards
            .iter()
            .enumerate()
            .find(|(_, map)| map.custom && map.name().eq_ignore_ascii_case(name))
    }

    fn map_list_builtin_conflicts_name(&self, name: &str) -> bool {
        self.map_list_cards
            .iter()
            .any(|map| !map.custom && map.name().eq_ignore_ascii_case(name))
    }

    fn import_editor_map_file(
        &mut self,
        source: impl AsRef<Path>,
    ) -> Result<DesktopEditorMapImportResult, String> {
        self.finish_import_editor_map_file(source.as_ref(), None)
    }

    fn confirm_editor_import_overwrite(&mut self) -> Result<DesktopEditorMapImportResult, String> {
        let pending = self
            .editor_import_overwrite_pending
            .clone()
            .ok_or_else(|| "@editor.overwrite.confirm".to_string())?;
        self.finish_import_editor_map_file(Path::new(&pending.source), Some(pending.existing_file))
    }

    fn finish_import_editor_map_file(
        &mut self,
        source: &Path,
        overwrite_existing_file: Option<String>,
    ) -> Result<DesktopEditorMapImportResult, String> {
        let bytes = std::fs::read(source).map_err(|error| {
            let message = format!("failed to read imported map {}: {error}", source.display());
            self.editor_import_error = Some(message.clone());
            message
        })?;
        if is_map_image_bytes(&bytes) {
            let message = "@editor.errorimage".to_string();
            self.editor_import_error = Some(message.clone());
            self.editor_import_map_dialog_open = true;
            return Err(message);
        }
        let mut info = read_deflated_map_info(bytes.as_slice(), true).map_err(|_| {
            let message = "@editor.errornot".to_string();
            self.editor_import_error = Some(message.clone());
            self.editor_import_map_dialog_open = true;
            message
        })?;
        let map_name = Self::editor_import_map_name_from_tags(&info.tags)
            .unwrap_or_else(|| self.next_unknown_editor_import_name());
        info.tags.insert("name".to_string(), map_name.clone());

        if self.map_list_builtin_conflicts_name(&map_name) {
            let message = "@editor.import.exists".to_string();
            self.editor_import_error = Some(message.clone());
            self.editor_import_map_dialog_open = true;
            return Err(message);
        }

        if overwrite_existing_file.is_none() {
            if let Some((_, existing)) = self.map_list_custom_conflict_for_name(&map_name) {
                let existing_file = existing.file.clone();
                let message = "@editor.overwrite.confirm".to_string();
                self.editor_import_error = Some(message.clone());
                self.editor_import_overwrite_pending = Some(DesktopEditorMapImportOverwrite {
                    source: source.display().to_string(),
                    map_name,
                    existing_file,
                });
                self.editor_import_map_dialog_open = true;
                return Err(message);
            }
        }

        let replaced = overwrite_existing_file;
        let replaced_path = replaced.as_ref().and_then(|file| {
            self.map_list_cards
                .iter()
                .find(|map| map.file == *file)
                .and_then(|map| self.editor_custom_map_file_for_descriptor(map))
        });
        if let Some(path) = replaced_path.as_ref() {
            if path != source {
                let _ = std::fs::remove_file(path);
            }
        }
        if let Some(file) = replaced.as_ref() {
            self.map_list_cards.retain(|map| map.file != *file);
        }

        let destination = self.next_editor_map_import_destination(source, &map_name);
        if let Some(parent) = destination.parent() {
            std::fs::create_dir_all(parent).map_err(|error| {
                let message = format!(
                    "failed to create imported map dir {}: {error}",
                    parent.display()
                );
                self.editor_import_error = Some(message.clone());
                message
            })?;
        }
        std::fs::write(&destination, &bytes).map_err(|error| {
            let message = format!(
                "failed to import map {} -> {}: {error}",
                source.display(),
                destination.display()
            );
            self.editor_import_error = Some(message.clone());
            message
        })?;
        let map_dir = self.editor_map_dir();
        let relative = destination
            .strip_prefix(&map_dir)
            .unwrap_or(&destination)
            .to_string_lossy()
            .replace('\\', "/");
        let map = MapDescriptor::new(
            format!("maps/custom/{relative}"),
            info.width,
            info.height,
            info.tags,
            true,
            info.version,
            info.build,
        );
        self.map_list_cards.push(map);
        self.map_list_cards.sort_by_key(|map| map.plain_name());
        let cards_for_preview = self.map_list_cards.clone();
        self.merge_map_preview_textures(&cards_for_preview);
        self.map_list_scroll_offset = 0;
        self.editor_import_map_dialog_open = false;
        self.editor_import_error = None;
        self.editor_import_overwrite_pending = None;
        self.map_list_search_focused = false;
        let result = DesktopEditorMapImportResult {
            source: source.display().to_string(),
            destination: destination.display().to_string(),
            map_name: map_name.clone(),
            replaced,
            status: "imported".to_string(),
        };
        self.last_editor_import_result = Some(result.clone());
        self.last_menu_info_message = Some(format!("MapImportEvent: {map_name}"));
        Ok(result)
    }

    fn map_preview_dir(&self) -> PathBuf {
        PathBuf::from(&self.client.context.paths.data_dir).join("previews")
    }

    fn map_play_preview_symbol(map: &MapDescriptor) -> String {
        let mut symbol = String::from("map_preview_");
        for ch in map.file.chars() {
            if ch.is_ascii_alphanumeric() {
                symbol.push(ch.to_ascii_lowercase());
            } else {
                symbol.push('_');
            }
        }
        symbol
    }

    fn map_play_preview_file_in_dir(map: &MapDescriptor, preview_dir: &Path) -> Option<PathBuf> {
        let preview_dir = preview_dir.to_string_lossy();
        let preview = map.preview_file(preview_dir.as_ref());
        let preview = PathBuf::from(preview);
        preview.exists().then_some(preview)
    }

    fn map_play_preview_symbol_if_loaded(&self, map: &MapDescriptor) -> Option<String> {
        let symbol = Self::map_play_preview_symbol(map);
        self.texture_atlas.has(&symbol).then_some(symbol)
    }

    fn merge_map_preview_textures(&mut self, maps: &[MapDescriptor]) -> usize {
        let preview_dir = self.map_preview_dir();
        let preview_atlas = TextureAtlasPlan::from_sprite_sources(maps.iter().filter_map(|map| {
            Self::map_play_preview_file_in_dir(map, &preview_dir).map(|path| {
                TextureAtlasSpriteSourceDescriptor::new(
                    path.display().to_string(),
                    Self::map_play_preview_symbol(map),
                )
                .with_page_hint("ui")
            })
        }));
        let mut merged = 0;
        for page in preview_atlas.pages {
            let page_type = page.page_type;
            for region in page.regions {
                let _ = self
                    .texture_atlas
                    .insert_or_replace_region(page_type, region);
                merged += 1;
            }
        }
        merged
    }

    fn load_map_cards_from_candidate_roots() -> Vec<MapDescriptor> {
        let mut cards = Vec::new();
        for root in Self::map_asset_candidate_roots() {
            if root.is_dir() && Self::collect_map_cards_from_dir(&root, &root, &mut cards).is_ok() {
                break;
            }
        }
        cards.sort_by_key(|map| map.plain_name());
        cards.dedup_by(|left, right| left.file == right.file);
        cards
    }

    fn load_custom_map_cards_from_configured_dir(&self) -> Vec<MapDescriptor> {
        let root = self.editor_map_dir();
        let mut cards = Vec::new();
        if root.is_dir() {
            let _ = Self::collect_custom_map_cards_from_dir(&root, &root, &mut cards);
        }
        cards.sort_by_key(|map| map.plain_name());
        cards
    }

    fn map_asset_candidate_roots() -> Vec<PathBuf> {
        let mut roots = Vec::new();
        if let Some(value) = std::env::var_os("MINDUSTRY_MAPS_DIR") {
            roots.push(PathBuf::from(value));
        }
        if let Some(value) = std::env::var_os("MINDUSTRY_ASSETS_DIR") {
            let assets = PathBuf::from(value);
            roots.push(assets.join("maps"));
            roots.push(assets);
        }
        if let Ok(cwd) = std::env::current_dir() {
            roots.push(cwd.join("core/assets/maps"));
            roots.push(cwd.join("../mindustry-upstream-v157.4/core/assets/maps"));
            roots.push(cwd.join("../_upstream_mindustry/core/assets/maps"));
        }
        roots.push(PathBuf::from(
            "D:/MDT/mindustry-upstream-v157.4/core/assets/maps",
        ));

        let mut deduped = Vec::new();
        for root in roots {
            if !deduped.iter().any(|known: &PathBuf| known == &root) {
                deduped.push(root);
            }
        }
        deduped
    }

    fn collect_map_cards_from_dir(
        root: &Path,
        dir: &Path,
        out: &mut Vec<MapDescriptor>,
    ) -> io::Result<()> {
        Self::collect_map_cards_from_dir_with_custom(root, dir, out, false, "maps")
    }

    fn collect_custom_map_cards_from_dir(
        root: &Path,
        dir: &Path,
        out: &mut Vec<MapDescriptor>,
    ) -> io::Result<()> {
        Self::collect_map_cards_from_dir_with_custom(root, dir, out, true, "maps/custom")
    }

    fn collect_map_cards_from_dir_with_custom(
        root: &Path,
        dir: &Path,
        out: &mut Vec<MapDescriptor>,
        custom: bool,
        file_prefix: &str,
    ) -> io::Result<()> {
        for entry in fs::read_dir(dir)? {
            let entry = entry?;
            let path = entry.path();
            if path.is_dir() {
                Self::collect_map_cards_from_dir_with_custom(
                    root,
                    &path,
                    out,
                    custom,
                    file_prefix,
                )?;
                continue;
            }
            if path
                .extension()
                .and_then(|extension| extension.to_str())
                .is_some_and(|extension| extension.eq_ignore_ascii_case("msav"))
            {
                let card = if custom {
                    Self::map_descriptor_from_file(root, &path, true, file_prefix)
                } else {
                    Self::map_descriptor_from_asset_file(root, &path)
                };
                if let Ok(card) = card {
                    out.push(card);
                }
            }
        }
        Ok(())
    }

    fn map_descriptor_from_asset_file(root: &Path, path: &Path) -> io::Result<MapDescriptor> {
        Self::map_descriptor_from_file(root, path, false, "maps")
    }

    fn map_descriptor_from_file(
        root: &Path,
        path: &Path,
        custom: bool,
        file_prefix: &str,
    ) -> io::Result<MapDescriptor> {
        let file = fs::File::open(path)?;
        let mut info = read_deflated_map_info(file, custom)?;
        if custom {
            if let Some(name) = Self::editor_import_map_name_from_tags(&info.tags) {
                info.tags.insert("name".to_string(), name);
            }
        }
        let relative = path
            .strip_prefix(root)
            .unwrap_or(path)
            .to_string_lossy()
            .replace('\\', "/");
        Ok(MapDescriptor::new(
            format!("{file_prefix}/{relative}"),
            info.width,
            info.height,
            info.tags,
            custom,
            info.version,
            info.build,
        ))
    }

