    fn schematic_modal_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopMenuRouteShellAction> {
        let modal = self.schematic_modal?;
        let dialog = Self::schematic_info_dialog_rect_for_panel(panel);
        match modal {
            DesktopSchematicModal::Info { .. } => self.schematic_info_action_at_point(panel, point),
            DesktopSchematicModal::Import => {
                for (index, button) in [
                    DesktopSchematicModalButton::ImportClipboard,
                    DesktopSchematicModalButton::ImportFile,
                    DesktopSchematicModalButton::BrowseWorkshop,
                ]
                .into_iter()
                .enumerate()
                {
                    if Self::schematic_modal_option_button_rect(dialog, index).contains_point(point)
                    {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(button));
                    }
                }
                if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::Back,
                    ));
                }
                None
            }
            DesktopSchematicModal::Tags => {
                let tags = self.schematics_tag_names();
                for (index, _) in tags.iter().enumerate() {
                    let row = Self::schematic_tag_editor_row_rect(dialog, index);
                    if Self::schematic_tag_editor_move_up_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagMoveUp(index),
                        ));
                    }
                    if Self::schematic_tag_editor_move_down_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagMoveDown(index),
                        ));
                    }
                    if Self::schematic_tag_editor_select_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagSelect(index),
                        ));
                    }
                    if Self::schematic_tag_editor_rename_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagRename(index),
                        ));
                    }
                    if Self::schematic_tag_editor_delete_rect(row).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::TagDelete(index),
                        ));
                    }
                }
                if Self::schematic_tag_editor_new_text_rect(dialog).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::TagNewText,
                    ));
                }
                if Self::schematic_tag_editor_new_icon_rect(dialog).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::TagNewIcon,
                    ));
                }
                if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::Back,
                    ));
                }
                None
            }
            DesktopSchematicModal::Export { index } => {
                let mut buttons = Vec::new();
                if self
                    .schematic_cards
                    .get(index)
                    .map(|entry| !entry.has_steam_id)
                    .unwrap_or(false)
                {
                    buttons.push(DesktopSchematicModalButton::ShareWorkshop);
                }
                buttons.extend([
                    DesktopSchematicModalButton::Copy,
                    DesktopSchematicModalButton::ExportFile,
                ]);
                for (button_index, button) in buttons.into_iter().enumerate() {
                    if Self::schematic_modal_option_button_rect(dialog, button_index)
                        .contains_point(point)
                    {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(button));
                    }
                }
                if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::Back,
                    ));
                }
                None
            }
            DesktopSchematicModal::Edit { index } => {
                if let Some(entry) = self.schematic_cards.get(index) {
                    for (tag_index, _) in entry.labels.iter().take(4).enumerate() {
                        let chip = Self::schematic_edit_owned_tag_chip_rect(dialog, tag_index);
                        if Self::schematic_edit_tag_remove_rect(chip).contains_point(point) {
                            return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                                DesktopSchematicModalButton::CardTagRemove {
                                    card_index: index,
                                    tag_index,
                                },
                            ));
                        }
                    }
                    let available = self
                        .schematics_tag_names()
                        .into_iter()
                        .filter(|tag| !entry.labels.iter().any(|label| label == tag))
                        .collect::<Vec<_>>();
                    for (tag_index, _) in available.iter().take(4).enumerate() {
                        if Self::schematic_edit_available_tag_chip_rect(dialog, tag_index)
                            .contains_point(point)
                        {
                            return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                                DesktopSchematicModalButton::CardTagAdd {
                                    card_index: index,
                                    tag_index,
                                },
                            ));
                        }
                    }
                    if Self::schematic_label_add_button_rect(dialog).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::CardTagNewText { card_index: index },
                        ));
                    }
                    if Self::schematic_label_add_icon_button_rect(dialog).contains_point(point) {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::CardTagNewIcon { card_index: index },
                        ));
                    }
                }
                if Self::schematic_info_button_rect(dialog, 1).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::EditOk,
                    ));
                }
                if Self::schematic_info_button_rect(dialog, 2).contains_point(point)
                    || Self::schematic_info_button_rect(dialog, 0).contains_point(point)
                {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::EditCancel,
                    ));
                }
                None
            }
            DesktopSchematicModal::IconTag { card_index } => {
                let candidates = self.schematic_icon_tag_candidates();
                for (icon_index, icon) in candidates.iter().take(24).enumerate() {
                    if Self::schematic_icon_tag_button_rect(dialog, icon_index)
                        .contains_point(point)
                    {
                        return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                            DesktopSchematicModalButton::CardTagAddIcon {
                                card_index,
                                icon_index,
                            },
                        ));
                    }
                    let _ = icon;
                }
                if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SchematicModalButton(
                        DesktopSchematicModalButton::Back,
                    ));
                }
                None
            }
        }
    }

    fn schematics_card_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopSchematicCardAction> {
        let grid = Self::schematics_grid_rect_for_panel(panel);
        for (visible_index, card_index) in self
            .filtered_schematic_card_indices()
            .into_iter()
            .enumerate()
        {
            let entry = &self.schematic_cards[card_index];
            let card = Self::schematics_card_rect_for_grid(grid, visible_index);
            if !Self::schematics_card_visible_in_grid(grid, card) || !card.contains_point(point) {
                continue;
            }
            for action_index in 0..4 {
                if Self::schematics_card_action_button_rect(card, action_index)
                    .contains_point(point)
                {
                    return Self::schematics_card_action_for_index(entry, card_index, action_index);
                }
            }
            return Some(DesktopSchematicCardAction::new(
                card_index,
                DesktopSchematicCardActionKind::Info,
            ));
        }
        None
    }

    fn join_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        let panel = Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Join);
        let point = RenderPoint::new(x, y);
        if self.join_route_loadfrag_visible() {
            if Self::join_connecting_loadfrag_cancel_button_rect_for_viewport(viewport)
                .contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::CancelJoinConnect);
            }
            return None;
        }
        if self.join_connection_error_dialog_message.is_some() {
            let dialog = Self::join_connection_error_dialog_rect_for_panel(panel);
            if Self::join_add_dialog_button_rect(dialog, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseJoinConnectionError);
            }
            return None;
        }
        if self.join_version_mismatch_dialog_message.is_some() {
            let dialog = Self::join_version_mismatch_dialog_rect_for_panel(panel);
            if Self::join_add_dialog_button_rect(dialog, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseJoinVersionMismatch);
            }
            return None;
        }
        if self.join_server_disclaimer_pending_target.is_some() {
            let dialog = Self::join_server_disclaimer_dialog_rect_for_panel(panel);
            if Self::join_add_dialog_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CancelJoinServerDisclaimer);
            }
            if Self::join_add_dialog_button_rect(dialog, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::ConfirmJoinServerDisclaimer);
            }
            return None;
        }
        if self.join_info_dialog_open {
            let dialog = Self::join_info_dialog_rect_for_panel(panel);
            if Self::join_add_dialog_button_rect(dialog, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseJoinInfo);
            }
            return None;
        }
        if self.join_delete_dialog_index.is_some() {
            let dialog = Self::join_delete_dialog_rect_for_panel(panel);
            if Self::join_add_dialog_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CancelDeleteJoinServerCard);
            }
            if Self::join_add_dialog_button_rect(dialog, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::ConfirmDeleteJoinServerCard);
            }
            return None;
        }
        if self.join_add_dialog_open {
            let dialog = Self::join_add_dialog_rect_for_panel(panel);
            if Self::join_add_dialog_text_rect(dialog).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::FocusJoinAddServerText);
            }
            if Self::join_add_dialog_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseJoinAddServer);
            }
            if self.join_add_server_confirm_enabled()
                && Self::join_add_dialog_button_rect(dialog, 1).contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::ConfirmJoinAddServer);
            }
            return None;
        }
        if Self::join_route_add_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenJoinAddServer);
        }
        if self.join_route_info_button_enabled_for_viewport(viewport)
            && Self::join_route_info_button_rect_for_panel(panel).contains_point(point)
        {
            return Some(DesktopMenuRouteShellAction::OpenJoinInfo);
        }
        if Self::join_route_refresh_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::RefreshJoinServers);
        }
        for section in [DesktopJoinSection::Local, DesktopJoinSection::Remote] {
            if Self::join_route_section_toggle_rect_for_panel(panel, section).contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::ToggleJoinSectionCollapsed(
                    section,
                ));
            }
        }
        if self.join_community_servers_enabled() {
            if Self::join_route_section_toggle_rect_for_panel(panel, DesktopJoinSection::Global)
                .contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::ToggleJoinSectionCollapsed(
                    DesktopJoinSection::Global,
                ));
            }
            if Self::join_route_show_hidden_button_rect_for_panel(panel).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::ToggleJoinShowHidden);
            }
            if self.join_route_section_collapsed(DesktopJoinSection::Global) {
                return None;
            }
            if Self::join_route_search_rect_for_panel(panel).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::FocusJoinSearch);
            }
            for (visible_index, (group_index, _)) in self
                .visible_join_community_groups()
                .into_iter()
                .take(JOIN_COMMUNITY_GROUP_VISIBLE_CARDS)
                .enumerate()
            {
                let row = Self::join_route_community_group_row_rect_for_panel(panel, visible_index);
                if !row.contains_point(point) {
                    continue;
                }
                for button_index in 0..3 {
                    if Self::join_route_community_group_action_button_rect(row, button_index)
                        .contains_point(point)
                    {
                        return Some(match button_index {
                            0 => DesktopMenuRouteShellAction::ToggleJoinCommunityFavorite(
                                group_index,
                            ),
                            1 => {
                                DesktopMenuRouteShellAction::ToggleJoinCommunityHidden(group_index)
                            }
                            _ => DesktopMenuRouteShellAction::AddJoinCommunityGroupToSaved(
                                group_index,
                            ),
                        });
                    }
                }
                return Some(DesktopMenuRouteShellAction::ConnectJoinCommunityGroup(
                    group_index,
                ));
            }
        }
        for local_index in 0..self.join_route_visible_local_host_count_for_panel(panel) {
            let rect = Self::join_route_server_card_rect_for_panel(panel, local_index);
            if rect.contains_point(point) {
                return Some(DesktopMenuRouteShellAction::ConnectJoinLocalHost(
                    local_index,
                ));
            }
        }
        if let Some(card_index) = self.join_route_server_card_index_at_point(panel, point) {
            let local_count = self.join_route_visible_local_host_count_for_panel(panel);
            let visible_saved_index = self
                .join_saved_server_snapshots()
                .into_iter()
                .enumerate()
                .filter(|(_, snapshot)| snapshot.matches_query(&self.join_search))
                .take(self.join_route_visible_saved_server_card_capacity_for_panel(panel))
                .position(|(index, _)| index == card_index)
                .unwrap_or(0);
            let card = Self::join_route_server_card_rect_for_panel(
                panel,
                local_count + visible_saved_index,
            );
            for button_index in 0..JOIN_SERVER_CARD_ACTION_BUTTONS {
                if Self::join_route_server_card_action_button_rect(card, button_index)
                    .contains_point(point)
                {
                    return Some(match button_index {
                        0 => DesktopMenuRouteShellAction::MoveJoinServerCardUp(card_index),
                        1 => DesktopMenuRouteShellAction::MoveJoinServerCardDown(card_index),
                        2 => DesktopMenuRouteShellAction::RefreshJoinServerCard(card_index),
                        3 => DesktopMenuRouteShellAction::EditJoinServerCard(card_index),
                        _ => DesktopMenuRouteShellAction::DeleteJoinServerCard(card_index),
                    });
                }
            }
            return Some(DesktopMenuRouteShellAction::ConnectJoinServerCard(
                card_index,
            ));
        }
        None
    }

    fn host_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        let panel = Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Host);
        let point = RenderPoint::new(x, y);
        if self.host_info_dialog_open {
            let dialog = RenderRect::new(
                panel.center().x - 210.0,
                panel.center().y - 76.0,
                420.0,
                152.0,
            );
            if Self::route_back_button_rect_for_panel(panel).contains_point(point)
                || Self::host_route_info_button_rect_for_panel(panel).contains_point(point)
                || Self::host_route_palette_close_rect_for_dialog(dialog).contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::CloseHostInfo);
            }
            return None;
        }
        if self.host_color_picker_open {
            let dialog = Self::host_route_palette_dialog_rect_for_panel(panel);
            for index in 0..HOST_PALETTE_COLORS.len() {
                if Self::host_route_palette_color_rect_for_dialog(dialog, index)
                    .contains_point(point)
                {
                    return Some(DesktopMenuRouteShellAction::SelectHostColor(index));
                }
            }
            if Self::route_back_button_rect_for_panel(panel).contains_point(point)
                || Self::host_route_palette_close_rect_for_dialog(dialog).contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::CloseHostColorPicker);
            }
            return None;
        }
        if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseRoute);
        }
        if Self::host_route_color_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenHostColorPicker);
        }
        if Self::host_route_name_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::FocusHostName);
        }
        if Self::host_route_friends_only_rect_for_panel(panel).contains_point(point) {
            if self.host_steam_enabled() {
                return Some(DesktopMenuRouteShellAction::ToggleHostFriendsOnly);
            }
            return None;
        }
        if Self::host_route_port_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::FocusHostPort);
        }
        if Self::host_route_info_button_rect_for_panel(panel).contains_point(point) {
            if !self.host_steam_enabled() {
                return Some(DesktopMenuRouteShellAction::OpenHostInfo);
            }
            return None;
        }
        if self.host_port_is_valid()
            && Self::host_route_host_button_rect_for_panel(panel).contains_point(point)
        {
            return Some(DesktopMenuRouteShellAction::HostRun);
        }
        None
    }

    fn map_list_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        route: DesktopMenuRoute,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        if !matches!(
            route,
            DesktopMenuRoute::CustomGame | DesktopMenuRoute::Editor
        ) {
            return None;
        }
        let panel = Self::active_menu_route_shell_panel_for_route(viewport, route);
        let point = RenderPoint::new(x, y);
        if route == DesktopMenuRoute::Editor && self.editor_new_map_dialog_open {
            let dialog = Self::editor_new_map_dialog_rect_for_panel(panel);
            if Self::editor_new_map_name_field_rect(dialog).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::FocusEditorNewMapName);
            }
            if Self::editor_new_map_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CancelEditorNewMap);
            }
            if !self.editor_new_map_name_text.is_empty()
                && Self::editor_new_map_button_rect(dialog, 1).contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::ConfirmEditorNewMap);
            }
            return None;
        }
        if route == DesktopMenuRoute::Editor
            && (self.editor_import_overwrite_pending.is_some()
                || self.editor_import_error.is_some())
        {
            let dialog = Self::editor_new_map_dialog_rect_for_panel(panel);
            if Self::editor_new_map_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CancelEditorImportOverwrite);
            }
            if self.editor_import_overwrite_pending.is_some()
                && Self::editor_new_map_button_rect(dialog, 1).contains_point(point)
            {
                return Some(DesktopMenuRouteShellAction::ConfirmEditorImportOverwrite);
            }
            return None;
        }
        if self.map_list_planet_filter_dialog_open {
            let dialog = Self::map_list_planet_filter_dialog_rect_for_panel(panel);
            if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseMapListPlanetFilters);
            }
            for (index, _) in self
                .map_list_planet_filter_candidates()
                .into_iter()
                .enumerate()
            {
                if Self::map_list_planet_filter_option_rect(dialog, index).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::MapListFilter(
                        DesktopMapListFilterAction::TogglePlanet(index),
                    ));
                }
            }
            return None;
        }
        if self.map_list_filter_dialog_open {
            let dialog = Self::map_list_filter_dialog_rect_for_panel(panel);
            if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseMapListFilters);
            }
            if Self::map_list_filter_planet_button_rect(dialog).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::OpenMapListPlanetFilters);
            }
            for (index, mode) in Gamemode::ALL.into_iter().enumerate() {
                if Self::map_list_filter_mode_rect(dialog, index).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::MapListFilter(
                        DesktopMapListFilterAction::ToggleMode(mode),
                    ));
                }
            }
            for (index, action) in [
                DesktopMapListFilterAction::TogglePrioritizeCustom,
                DesktopMapListFilterAction::TogglePrioritizeModded,
            ]
            .into_iter()
            .enumerate()
            {
                if Self::map_list_filter_priority_rect(dialog, index).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::MapListFilter(action));
                }
            }
            for (index, action) in [
                DesktopMapListFilterAction::ToggleShowCustom,
                DesktopMapListFilterAction::ToggleShowBuiltin,
                DesktopMapListFilterAction::ToggleShowModded,
            ]
            .into_iter()
            .enumerate()
            {
                if Self::map_list_filter_type_rect(dialog, index).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::MapListFilter(action));
                }
            }
            for (index, action) in [
                DesktopMapListFilterAction::ToggleSearchAuthor,
                DesktopMapListFilterAction::ToggleSearchDescription,
                DesktopMapListFilterAction::ToggleSearchModName,
            ]
            .into_iter()
            .enumerate()
            {
                if Self::map_list_filter_search_scope_rect(dialog, index).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::MapListFilter(action));
                }
            }
            return None;
        }
        if self.map_play_dialog_index.is_some() || self.editor_map_info_dialog_index.is_some() {
            let dialog = Self::map_card_dialog_rect_for_panel(panel);
            if self.map_play_mode_help_dialog_open || self.map_play_customize_dialog_open {
                let child = Self::map_play_child_dialog_rect(dialog);
                if self.map_play_customize_dialog_open {
                    if let Some(index) = self.map_play_dialog_index {
                        if let Some(kind) = self.map_play_banned_content_dialog {
                            let banned_dialog = Self::map_play_banned_content_dialog_rect(child);
                            if Self::map_play_banned_content_close_rect(banned_dialog)
                                .contains_point(point)
                            {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::CloseBannedContent,
                                    ),
                                ));
                            }
                            if Self::map_play_banned_content_search_rect(banned_dialog)
                                .contains_point(point)
                            {
                                if Self::map_play_banned_content_search_clear_rect(banned_dialog)
                                    .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(
                                            index,
                                            DesktopMapCardActionKind::ClearBannedContentSearch(
                                                kind,
                                            ),
                                        ),
                                    ));
                                }
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::FocusBannedContentSearch(kind),
                                    ),
                                ));
                            }
                            if kind == DesktopBannedContentKind::Blocks {
                                for (category_index, category) in
                                    Category::ALL.into_iter().enumerate()
                                {
                                    if Self::map_play_banned_content_category_rect(
                                        banned_dialog,
                                        category_index,
                                    )
                                    .contains_point(point)
                                    {
                                        return Some(DesktopMenuRouteShellAction::MapCard(
                                            DesktopMapCardAction::new(
                                                index,
                                                DesktopMapCardActionKind::ToggleBannedContentCategory(
                                                    category,
                                                ),
                                            ),
                                        ));
                                    }
                                }
                            }
                            if Self::map_play_banned_content_add_all_rect(banned_dialog, true)
                                .contains_point(point)
                            {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::AddAllBannedContent(kind),
                                    ),
                                ));
                            }
                            if Self::map_play_banned_content_add_all_rect(banned_dialog, false)
                                .contains_point(point)
                            {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::RemoveAllBannedContent(kind),
                                    ),
                                ));
                            }
                            let rules = self
                                .map_play_rules
                                .clone()
                                .or_else(|| {
                                    self.map_list_cards.get(index).map(|map| {
                                        Self::map_play_rules_for_mode(
                                            map,
                                            self.map_play_selected_mode,
                                        )
                                    })
                                })
                                .unwrap_or_default();
                            let candidates = self.map_play_banned_content_candidate_entries(kind);
                            let mut selected_row = 0usize;
                            let mut deselected_row = 0usize;
                            let scroll = self
                                .map_play_banned_content_scroll_offset
                                .min(self.map_play_banned_content_max_scroll_offset(kind, &rules));
                            let visible_rows = Self::map_play_banned_content_visible_rows();
                            for (candidate_index, entry) in candidates.iter().enumerate() {
                                let selected = kind.contains(&rules, &entry.name);
                                let row_index = if selected {
                                    let row = selected_row;
                                    selected_row += 1;
                                    row
                                } else {
                                    let row = deselected_row;
                                    deselected_row += 1;
                                    row
                                };
                                if row_index < scroll || row_index >= scroll + visible_rows {
                                    continue;
                                }
                                if Self::map_play_banned_content_item_rect(
                                    banned_dialog,
                                    selected,
                                    row_index - scroll,
                                )
                                .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(
                                            index,
                                            DesktopMapCardActionKind::ToggleBannedContent(
                                                kind,
                                                candidate_index,
                                            ),
                                        ),
                                    ));
                                }
                            }
                            return None;
                        }
                        if self.map_play_weather_dialog_open {
                            let weather_dialog = Self::map_play_weather_dialog_rect(child);
                            if self.map_play_weather_add_dialog_open {
                                let add_dialog =
                                    Self::map_play_weather_add_dialog_rect(weather_dialog);
                                if Self::map_play_weather_add_close_rect(add_dialog)
                                    .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(
                                            index,
                                            DesktopMapCardActionKind::CloseWeatherAdd,
                                        ),
                                    ));
                                }
                                let rules = self
                                    .map_play_rules
                                    .clone()
                                    .or_else(|| {
                                        self.map_list_cards.get(index).map(|map| {
                                            Self::map_play_rules_for_mode(
                                                map,
                                                self.map_play_selected_mode,
                                            )
                                        })
                                    })
                                    .unwrap_or_default();
                                for (candidate_index, _) in self
                                    .map_play_weather_candidate_names(&rules)
                                    .into_iter()
                                    .enumerate()
                                {
                                    if Self::map_play_weather_candidate_rect(
                                        add_dialog,
                                        candidate_index,
                                    )
                                    .contains_point(point)
                                    {
                                        return Some(DesktopMenuRouteShellAction::MapCard(
                                            DesktopMapCardAction::new(
                                                index,
                                                DesktopMapCardActionKind::AddWeather(
                                                    candidate_index,
                                                ),
                                            ),
                                        ));
                                    }
                                }
                                return None;
                            }
                            if Self::map_play_weather_close_rect(weather_dialog)
                                .contains_point(point)
                            {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::CloseWeather,
                                    ),
                                ));
                            }
                            let rules = self
                                .map_play_rules
                                .clone()
                                .or_else(|| {
                                    self.map_list_cards.get(index).map(|map| {
                                        Self::map_play_rules_for_mode(
                                            map,
                                            self.map_play_selected_mode,
                                        )
                                    })
                                })
                                .unwrap_or_default();
                            for (weather_index, _) in rules.weather.iter().take(4).enumerate() {
                                let row = Self::map_play_weather_entry_rect(
                                    weather_dialog,
                                    weather_index,
                                );
                                if Self::map_play_weather_entry_remove_rect(row)
                                    .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(
                                            index,
                                            DesktopMapCardActionKind::RemoveWeather(weather_index),
                                        ),
                                    ));
                                }
                                if Self::map_play_weather_entry_always_rect(row)
                                    .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(
                                            index,
                                            DesktopMapCardActionKind::ToggleWeatherAlways(
                                                weather_index,
                                            ),
                                        ),
                                    ));
                                }
                                if !rules.weather[weather_index].always {
                                    for (field_index, number) in
                                        DesktopWeatherNumber::ALL.into_iter().enumerate()
                                    {
                                        let field = Self::map_play_weather_entry_number_rect(
                                            row,
                                            field_index,
                                        );
                                        for (increase, direction) in [(false, -1), (true, 1)] {
                                            if Self::map_play_weather_entry_number_button_rect(
                                                field, increase,
                                            )
                                            .contains_point(point)
                                            {
                                                return Some(
                                                    DesktopMenuRouteShellAction::MapCard(
                                                        DesktopMapCardAction::new(
                                                            index,
                                                            DesktopMapCardActionKind::AdjustWeatherNumber(
                                                                weather_index,
                                                                number,
                                                                direction,
                                                            ),
                                                        ),
                                                    ),
                                                );
                                            }
                                        }
                                    }
                                }
                            }
                            if Self::map_play_weather_add_button_rect(weather_dialog)
                                .contains_point(point)
                            {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::OpenWeatherAdd,
                                    ),
                                ));
                            }
                            return None;
                        }
                        if self.map_play_team_rules_dialog_open {
                            let team_dialog = Self::map_play_team_rules_dialog_rect(child);
                            if Self::map_play_team_rules_close_rect(team_dialog)
                                .contains_point(point)
                            {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::CloseTeamRules,
                                    ),
                                ));
                            }
                            if Self::map_play_team_rules_allow_edit_rect(team_dialog)
                                .contains_point(point)
                            {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::ToggleAllowEditRules,
                                    ),
                                ));
                            }
                            let rules = self
                                .map_play_rules
                                .clone()
                                .or_else(|| {
                                    self.map_list_cards.get(index).map(|map| {
                                        Self::map_play_rules_for_mode(
                                            map,
                                            self.map_play_selected_mode,
                                        )
                                    })
                                })
                                .unwrap_or_default();
                            let teams = Self::map_play_team_options();
                            for (team_index, (team_id, _, _)) in teams.iter().enumerate() {
                                if Self::map_play_team_rules_selector_rect(
                                    team_dialog,
                                    0,
                                    team_index,
                                )
                                .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(
                                            index,
                                            DesktopMapCardActionKind::SelectDefaultTeam(*team_id),
                                        ),
                                    ));
                                }
                                if Self::map_play_team_rules_selector_rect(
                                    team_dialog,
                                    1,
                                    team_index,
                                )
                                .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(
                                            index,
                                            DesktopMapCardActionKind::SelectWaveTeam(*team_id),
                                        ),
                                    ));
                                }
                                if Self::map_play_team_rules_section_rect(team_dialog, team_index)
                                    .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(
                                            index,
                                            DesktopMapCardActionKind::ToggleTeamRuleSection(
                                                *team_id,
                                            ),
                                        ),
                                    ));
                                }
                            }
                            let selected_team = self
                                .map_play_team_rules_selected_team
                                .unwrap_or(rules.default_team.max(0) as usize);
                            for (field_index, toggle) in
                                DesktopTeamRuleToggle::ALL.into_iter().enumerate()
                            {
                                let row =
                                    Self::map_play_team_rules_field_rect(team_dialog, field_index);
                                if Self::map_play_team_rules_field_toggle_rect(row)
                                    .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(
                                            index,
                                            DesktopMapCardActionKind::ToggleTeamRule(
                                                selected_team,
                                                toggle,
                                            ),
                                        ),
                                    ));
                                }
                            }
                            let offset = DesktopTeamRuleToggle::ALL.len();
                            for (number_index, number) in
                                DesktopTeamRuleNumber::ALL.into_iter().enumerate()
                            {
                                let row = Self::map_play_team_rules_field_rect(
                                    team_dialog,
                                    offset + number_index,
                                );
                                for (increase, direction) in [(false, -1), (true, 1)] {
                                    if Self::map_play_team_rules_number_button_rect(row, increase)
                                        .contains_point(point)
                                    {
                                        return Some(DesktopMenuRouteShellAction::MapCard(
                                            DesktopMapCardAction::new(
                                                index,
                                                DesktopMapCardActionKind::AdjustTeamRuleNumber(
                                                    selected_team,
                                                    number,
                                                    direction,
                                                ),
                                            ),
                                        ));
                                    }
                                }
                            }
                            return None;
                        }
                        if self.map_play_rules_edit_dialog_open {
                            let edit = Self::map_play_rules_edit_dialog_rect(child);
                            for (button_index, kind) in [
                                DesktopMapCardActionKind::CopyCustomRules,
                                DesktopMapCardActionKind::LoadCustomRules,
                                DesktopMapCardActionKind::ResetCustomRules,
                                DesktopMapCardActionKind::CloseCustomRulesEdit,
                            ]
                            .into_iter()
                            .enumerate()
                            {
                                if Self::map_play_rules_edit_button_rect(edit, button_index)
                                    .contains_point(point)
                                {
                                    return Some(DesktopMenuRouteShellAction::MapCard(
                                        DesktopMapCardAction::new(index, kind),
                                    ));
                                }
                            }
                            return None;
                        }
                        if Self::map_play_customize_edit_button_rect(child, 0).contains_point(point)
                        {
                            return Some(DesktopMenuRouteShellAction::MapCard(
                                DesktopMapCardAction::new(
                                    index,
                                    DesktopMapCardActionKind::OpenCustomRulesEdit,
                                ),
                            ));
                        }
                        if Self::map_play_customize_edit_button_rect(child, 1).contains_point(point)
                        {
                            return Some(DesktopMenuRouteShellAction::MapCard(
                                DesktopMapCardAction::new(
                                    index,
                                    DesktopMapCardActionKind::ResetCustomRules,
                                ),
                            ));
                        }
                        if Self::map_play_customize_edit_button_rect(child, 2).contains_point(point)
                        {
                            return Some(DesktopMenuRouteShellAction::MapCard(
                                DesktopMapCardAction::new(
                                    index,
                                    DesktopMapCardActionKind::OpenBannedContent(
                                        DesktopBannedContentKind::Blocks,
                                    ),
                                ),
                            ));
                        }
                        if Self::map_play_customize_edit_button_rect(child, 3).contains_point(point)
                        {
                            return Some(DesktopMenuRouteShellAction::MapCard(
                                DesktopMapCardAction::new(
                                    index,
                                    DesktopMapCardActionKind::OpenBannedContent(
                                        DesktopBannedContentKind::Units,
                                    ),
                                ),
                            ));
                        }
                        if Self::map_play_customize_edit_button_rect(child, 4).contains_point(point)
                        {
                            return Some(DesktopMenuRouteShellAction::MapCard(
                                DesktopMapCardAction::new(
                                    index,
                                    DesktopMapCardActionKind::OpenWeather,
                                ),
                            ));
                        }
                        if Self::map_play_customize_edit_button_rect(child, 5).contains_point(point)
                        {
                            return Some(DesktopMenuRouteShellAction::MapCard(
                                DesktopMapCardAction::new(
                                    index,
                                    DesktopMapCardActionKind::OpenTeamRules,
                                ),
                            ));
                        }
                        let content = Self::map_play_customize_content_rect(child);
                        let rules = self
                            .map_play_rules
                            .clone()
                            .or_else(|| {
                                self.map_list_cards.get(index).map(|map| {
                                    Self::map_play_rules_for_mode(map, self.map_play_selected_mode)
                                })
                            })
                            .unwrap_or_default();
                        for (number_index, number) in
                            DesktopCustomRulesNumber::ALL.into_iter().enumerate()
                        {
                            if !number.enabled(&rules) {
                                continue;
                            }
                            let row =
                                Self::map_play_customize_number_row_rect(content, number_index);
                            let decrease = Self::map_play_customize_number_button_rect(row, false);
                            if decrease.contains_point(point) {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::AdjustCustomRuleNumber(
                                            number, -1,
                                        ),
                                    ),
                                ));
                            }
                            let increase = Self::map_play_customize_number_button_rect(row, true);
                            if increase.contains_point(point) {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::AdjustCustomRuleNumber(number, 1),
                                    ),
                                ));
                            }
                        }
                        for (policy_index, toggle) in MAP_PLAY_CUSTOM_RULE_BANNED_POLICY_TOGGLES
                            .iter()
                            .enumerate()
                        {
                            let row = Self::map_play_customize_banned_policy_row_rect(
                                content,
                                policy_index,
                            );
                            if row.contains_point(point) {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::ToggleCustomRule(*toggle),
                                    ),
                                ));
                            }
                        }
                        for (toggle, rect) in Self::map_play_customize_toggle_rects(content) {
                            if rect.contains_point(point) && toggle.enabled(&rules) {
                                return Some(DesktopMenuRouteShellAction::MapCard(
                                    DesktopMapCardAction::new(
                                        index,
                                        DesktopMapCardActionKind::ToggleCustomRule(toggle),
                                    ),
                                ));
                            }
                        }
                    }
                }
                let close = if self.map_play_mode_help_dialog_open {
                    Self::map_play_help_dialog_ok_rect(child)
                } else {
                    Self::map_play_child_dialog_close_rect(child)
                };
                if close.contains_point(point) {
                    return Some(if self.map_play_mode_help_dialog_open {
                        DesktopMenuRouteShellAction::CloseMapPlayHelp
                    } else {
                        DesktopMenuRouteShellAction::CloseMapPlayCustomize
                    });
                }
                return None;
            }
            if Self::map_card_dialog_close_rect(dialog).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseMapCardDialog);
            }
            if let Some(index) = self.map_play_dialog_index {
                if Self::map_play_help_button_rect(dialog).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::MapCard(
                        DesktopMapCardAction::new(index, DesktopMapCardActionKind::ShowModeHelp),
                    ));
                }
                for (mode_index, mode) in Self::map_play_dialog_modes().into_iter().enumerate() {
                    if Self::map_play_mode_button_rect(dialog, mode_index).contains_point(point) {
                        let Some(map) = self.map_list_cards.get(index) else {
                            return None;
                        };
                        if !mode.valid(map) {
                            return None;
                        }
                        return Some(DesktopMenuRouteShellAction::MapCard(
                            DesktopMapCardAction::new(
                                index,
                                DesktopMapCardActionKind::SelectPlayMode(mode),
                            ),
                        ));
                    }
                }
                if Self::map_play_primary_button_rect(dialog).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::MapCard(
                        DesktopMapCardAction::new(index, DesktopMapCardActionKind::PlaySelected),
                    ));
                }
                if Self::map_play_customize_button_rect(dialog).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::MapCard(
                        DesktopMapCardAction::new(index, DesktopMapCardActionKind::Customize),
                    ));
                }
            }
            if let Some(index) = self.editor_map_info_dialog_index {
                if Self::map_editor_action_button_rect(dialog, 0).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::MapCard(
                        DesktopMapCardAction::new(index, DesktopMapCardActionKind::OpenInEditor),
                    ));
                }
                if Self::map_editor_action_button_rect(dialog, 1).contains_point(point) {
                    if let Some(kind) = self
                        .map_list_cards
                        .get(index)
                        .and_then(Self::map_editor_secondary_action_kind)
                    {
                        return Some(DesktopMenuRouteShellAction::MapCard(
                            DesktopMapCardAction::new(index, kind),
                        ));
                    }
                }
            }
            return None;
        }
        if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseRoute);
        }
        if Self::map_list_search_rect_for_panel(panel, route).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::FocusMapListSearch);
        }
        if Self::map_list_filter_button_rect_for_panel(panel, route).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenMapListFilters);
        }
        if route == DesktopMenuRoute::Editor {
            if Self::map_list_action_button_rect_for_panel(panel, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::NewEditorMap);
            }
            if Self::map_list_action_button_rect_for_panel(panel, 1).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::ImportEditorMap);
            }
        }
        if let Some(index) = self.map_list_card_index_at_point(panel, route, point) {
            let kind = match route {
                DesktopMenuRoute::CustomGame => DesktopMapCardActionKind::OpenPlay,
                DesktopMenuRoute::Editor => DesktopMapCardActionKind::OpenEditorInfo,
                _ => return None,
            };
            return Some(DesktopMenuRouteShellAction::MapCard(
                DesktopMapCardAction::new(index, kind),
            ));
        }
        None
    }

    fn schematics_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Schematics);
        let point = RenderPoint::new(x, y);
        if self.schematic_modal.is_some() {
            return self.schematic_modal_action_at_point(panel, point);
        }
        if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseRoute);
        }
        if Self::schematics_search_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::FocusSchematicSearch);
        }
        if Self::schematics_import_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenSchematicImport);
        }
        if Self::schematics_tag_edit_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenSchematicTags);
        }
        if let Some(tag_index) = self.schematics_tag_chip_index_at_point(panel, point) {
            return Some(DesktopMenuRouteShellAction::ToggleSchematicTag(tag_index));
        }
        if let Some(action) = self.schematics_card_action_at_point(panel, point) {
            return Some(DesktopMenuRouteShellAction::SchematicCard(action));
        }
        None
    }

    fn tech_tree_route_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopMenuRouteShellAction> {
        if self.tech_tree_select_dialog_open {
            let dialog = Self::tech_tree_select_dialog_rect_for_panel(panel);
            for (index, _) in self.tech_tree_route_root_candidates().iter().enumerate() {
                if Self::tech_tree_select_root_button_rect(dialog, index).contains_point(point) {
                    return Some(DesktopMenuRouteShellAction::SelectTechTreeRoot(index));
                }
            }
            if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseTechTreeSelect);
            }
            return None;
        }
        if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseRoute);
        }
        if Self::tech_tree_select_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenTechTreeSelect);
        }
        let graph = Self::tech_tree_graph_rect_for_panel(panel);
        for (id, rect) in self.tech_tree_route_visible_node_rects(graph) {
            if rect.contains_point(point) {
                return Some(DesktopMenuRouteShellAction::OpenTechTreeNode(id));
            }
        }
        None
    }

    fn database_search_rect_for_panel(panel: RenderRect) -> RenderRect {
        RenderRect::new(
            panel.x + 28.0,
            panel.y + panel.height - 128.0,
            panel.width - 56.0,
            DATABASE_SEARCH_BAR_HEIGHT,
        )
    }

    fn database_tab_rect_for_panel(panel: RenderRect, index: usize) -> RenderRect {
        let search = Self::database_search_rect_for_panel(panel);
        let column = index % DATABASE_TAB_COLUMNS;
        let row = index / DATABASE_TAB_COLUMNS;
        RenderRect::new(
            panel.x + 28.0 + column as f32 * DATABASE_TAB_SIZE,
            search.y - DATABASE_TAB_SIZE - 10.0 - row as f32 * DATABASE_TAB_SIZE,
            DATABASE_TAB_SIZE,
            DATABASE_TAB_SIZE,
        )
    }

    fn database_row_height() -> f32 {
        DATABASE_CONTENT_CELL_SIZE + DATABASE_CONTENT_CELL_GAP + 46.0
    }

    fn database_content_list_rect_for_panel(panel: RenderRect) -> RenderRect {
        let first_header = Self::database_category_header_rect_for_panel(panel, 0);
        let bottom = panel.y + 42.0;
        RenderRect::new(
            panel.x + 24.0,
            bottom,
            panel.width - 48.0,
            (first_header.y + first_header.height + 6.0 - bottom).max(44.0),
        )
    }

    fn database_visible_row_capacity_for_panel(panel: RenderRect) -> usize {
        let first_header = Self::database_category_header_rect_for_panel(panel, 0);
        let bottom = panel.y + 42.0;
        if first_header.y < bottom {
            return 0;
        }
        (((first_header.y - bottom) / Self::database_row_height()).floor() as usize + 1)
            .max(1)
            .min(DATABASE_VISIBLE_CATEGORIES)
    }

    fn max_database_scroll_offset_for_rows(row_count: usize, panel: RenderRect) -> usize {
        row_count.saturating_sub(Self::database_visible_row_capacity_for_panel(panel).max(1))
    }

    fn max_database_scroll_offset(&self, panel: RenderRect) -> usize {
        Self::max_database_scroll_offset_for_rows(
            self.database_visible_grid_rows_for_panel(panel).len(),
            panel,
        )
    }

    fn clamped_database_scroll_offset_for_panel(&self, panel: RenderRect) -> usize {
        self.database_scroll_offset
            .min(self.max_database_scroll_offset(panel))
    }

    fn apply_database_scroll_delta(
        &mut self,
        surface_size: DesktopSurfaceSize,
        delta_y: f32,
    ) -> bool {
        if self.active_menu_route != Some(DesktopMenuRoute::Database)
            || self.last_database_content_opened.is_some()
        {
            return false;
        }
        let Some(cursor) = self.last_menu_cursor else {
            return false;
        };
        let viewport = self.default_render_viewport_for_surface(surface_size);
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Database);
        if !Self::database_content_list_rect_for_panel(panel).contains_point(cursor) {
            return false;
        }
        let max = self.max_database_scroll_offset(panel);
        if max == 0 {
            return false;
        }
        let current = self.database_scroll_offset.min(max);
        let rows = delta_y.abs().ceil().max(1.0) as isize;
        let step = if delta_y < 0.0 {
            rows
        } else if delta_y > 0.0 {
            -rows
        } else {
            0
        };
        let next = (current as isize + step).clamp(0, max as isize) as usize;
        self.database_scroll_offset = next;
        next != current
    }

    fn database_category_header_rect_for_panel(panel: RenderRect, index: usize) -> RenderRect {
        let first_y = Self::database_tab_rect_for_panel(panel, 0).y - 38.0;
        RenderRect::new(
            panel.x + 28.0,
            first_y - index as f32 * Self::database_row_height(),
            panel.width - 56.0,
            22.0,
        )
    }

    fn database_content_cell_rect_for_panel(
        panel: RenderRect,
        category_index: usize,
        item_index: usize,
    ) -> RenderRect {
        let header = Self::database_category_header_rect_for_panel(panel, category_index);
        RenderRect::new(
            header.x + item_index as f32 * (DATABASE_CONTENT_CELL_SIZE + DATABASE_CONTENT_CELL_GAP),
            header.y - DATABASE_CONTENT_CELL_SIZE - 9.0,
            DATABASE_CONTENT_CELL_SIZE,
            DATABASE_CONTENT_CELL_SIZE,
        )
    }

    fn database_content_info_dialog_rect_for_panel(panel: RenderRect) -> RenderRect {
        let width = (panel.width - 70.0).clamp(420.0, 640.0);
        let height = (panel.height - 70.0).clamp(360.0, 560.0);
        RenderRect::new(
            panel.x + (panel.width - width) * 0.5,
            panel.y + (panel.height - height) * 0.5,
            width,
            height,
        )
    }

    fn database_content_info_icon_rect(dialog: RenderRect) -> RenderRect {
        RenderRect::new(
            dialog.x + 32.0,
            dialog.y + dialog.height - 130.0,
            72.0,
            72.0,
        )
    }

    fn database_content_info_scrollpane_rect(dialog: RenderRect) -> RenderRect {
        RenderRect::new(
            dialog.x + 24.0,
            dialog.y + 82.0,
            dialog.width - 48.0,
            (dialog.height - 232.0).max(120.0),
        )
    }

    fn database_content_info_close_rect(dialog: RenderRect) -> RenderRect {
        RenderRect::new(dialog.center().x - 55.0, dialog.y + 18.0, 110.0, 50.0)
    }

    fn database_content_fields_class_name(
        &self,
        content_type: ContentType,
        name: &str,
    ) -> &'static str {
        match content_type {
            ContentType::Item => "Item",
            ContentType::Block => "Block",
            ContentType::Liquid => "Liquid",
            ContentType::Status => "StatusEffect",
            ContentType::Unit => "UnitType",
            ContentType::Weather => "Weather",
            ContentType::Sector => "SectorPreset",
            ContentType::Planet => "Planet",
            ContentType::Bullet => "BulletType",
            ContentType::Team => "Team",
            ContentType::UnitCommand => "UnitCommand",
            ContentType::UnitStance => "UnitStance",
            ContentType::Error => "ErrorContent",
            _ => self
                .content_loader
                .get_by_name(content_type, name)
                .map(|_| "Content")
                .unwrap_or("Content"),
        }
    }

    fn database_content_fields_url(&self, content_type: ContentType, name: &str) -> String {
        format!(
            "{}{}",
            DATABASE_FIELDS_URI_PREFIX,
            self.database_content_fields_class_name(content_type, name)
        )
    }

    fn database_content_info_viewfields_rect_for_content(
        &self,
        clip: RenderRect,
        content_type: ContentType,
        name: &str,
    ) -> Option<RenderRect> {
        if !self.menu_console_setting_enabled {
            return None;
        }

        let mut y = clip.y + clip.height - 18.0;
        if self
            .database_content_description(content_type, name)
            .is_some()
        {
            y -= 70.0;
        }

        let stats = self.database_content_stat_lines(content_type, name);
        if !stats.is_empty() {
            y -= 24.0 + stats.len() as f32 * 20.0 + 12.0;
        }

        if self.database_content_details(content_type, name).is_some() {
            y -= 58.0;
        }

        let button_width = 300.0_f32.min((clip.width - 28.0).max(140.0));
        Some(RenderRect::new(
            clip.x + (clip.width - button_width) * 0.5,
            (y - 58.0).max(clip.y + 10.0),
            button_width,
            50.0,
        ))
    }

    fn database_tab_index_at_point(&self, panel: RenderRect, point: RenderPoint) -> Option<usize> {
        (0..self.database_tab_count())
            .find(|index| Self::database_tab_rect_for_panel(panel, *index).contains_point(point))
    }

    fn database_content_cell_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<(ContentType, usize)> {
        let row_capacity = Self::database_visible_row_capacity_for_panel(panel);
        let scroll_offset = self.clamped_database_scroll_offset_for_panel(panel);
        for (row_index, row) in self
            .database_visible_grid_rows_for_panel(panel)
            .into_iter()
            .skip(scroll_offset)
            .take(row_capacity)
            .enumerate()
        {
            let header = Self::database_category_header_rect_for_panel(panel, row_index);
            if header.y < panel.y + 42.0 {
                break;
            }
            for (item_index, (record_index, name)) in row.records.into_iter().enumerate() {
                if Self::database_content_cell_rect_for_panel(panel, row_index, item_index)
                    .contains_point(point)
                {
                    if !self.database_content_unlocked(row.content_type, &name) {
                        return None;
                    }
                    return Some((row.content_type, record_index));
                }
            }
        }
        None
    }

    fn database_route_shell_action_at_surface_point(
        &self,
        viewport: RenderViewport,
        x: f32,
        y: f32,
    ) -> Option<DesktopMenuRouteShellAction> {
        let panel =
            Self::active_menu_route_shell_panel_for_route(viewport, DesktopMenuRoute::Database);
        let point = RenderPoint::new(x, y);
        if let Some((content_type, name)) = self.last_database_content_opened.as_ref() {
            let dialog = Self::database_content_info_dialog_rect_for_panel(panel);
            if Self::database_content_info_close_rect(dialog).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::CloseDatabaseContent);
            }
            let clip = Self::database_content_info_scrollpane_rect(dialog);
            if self
                .database_content_info_viewfields_rect_for_content(clip, *content_type, name)
                .is_some_and(|rect| rect.contains_point(point))
            {
                return Some(DesktopMenuRouteShellAction::OpenDatabaseContentFields);
            }
            return None;
        }
        if Self::route_back_button_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseRoute);
        }
        if Self::database_search_rect_for_panel(panel).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::FocusDatabaseSearch);
        }
        if let Some(index) = self.database_tab_index_at_point(panel, point) {
            return Some(DesktopMenuRouteShellAction::SelectDatabaseTab(index));
        }
        if let Some((content_type, record_index)) =
            self.database_content_cell_at_point(panel, point)
        {
            if self.menu_shift_pressed
                && self
                    .content_loader
                    .get_by(content_type)
                    .get(record_index)
                    .and_then(|record| record.name())
                    .and_then(|name| self.database_content_icon_emoji(content_type, name))
                    .is_some()
            {
                return Some(DesktopMenuRouteShellAction::CopyDatabaseContentIcon(
                    content_type,
                    record_index,
                ));
            }
            return Some(DesktopMenuRouteShellAction::OpenDatabaseContent(
                content_type,
                record_index,
            ));
        }
        None
    }

