    fn push_tech_tree_select_dialog(&self, pass: &mut RenderPass, panel: RenderRect) {
        if !self.tech_tree_select_dialog_open {
            return;
        }
        let dialog = Self::tech_tree_select_dialog_rect_for_panel(panel);
        pass.push(RenderCommand::fill_rect(
            panel,
            [0.0, 0.0, 0.0, 0.46],
            Layer::END_PIXELED + 0.070,
        ));
        pass.push(RenderCommand::draw_sprite(
            Self::settings_drawable_symbol("pane"),
            dialog,
            [1.0, 1.0, 1.0, 0.98],
            0.0,
            Layer::END_PIXELED + 0.071,
        ));
        pass.push(RenderCommand::stroke_rect(
            dialog,
            [0.52, 0.68, 0.82, 0.95],
            2.0,
            Layer::END_PIXELED + 0.072,
        ));
        pass.push(RenderCommand::draw_text_styled(
            self.localize_bundle_markup_text("@techtree.select"),
            RenderPoint::new(dialog.center().x, dialog.y + dialog.height - 34.0),
            [0.94, 0.98, 1.0, 1.0],
            15.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            Layer::END_PIXELED + 0.073,
        ));
        for (index, (root_name, tree, root)) in self
            .tech_tree_route_root_candidates()
            .iter()
            .copied()
            .enumerate()
        {
            let label = tree
                .node(root)
                .map(|node| Self::tech_tree_display_label(&node.content.localized_name))
                .unwrap_or_else(|| Self::tech_tree_display_label(root_name));
            let selected = self
                .tech_tree_selected_root
                .as_deref()
                .map(|selected| selected == root_name)
                .unwrap_or(index == 0);
            self.push_settings_text_button(
                pass,
                Self::tech_tree_select_root_button_rect(dialog, index),
                label,
                Some(if selected { "ok" } else { "rightOpen" }),
                Layer::END_PIXELED + 0.074 + index as f32 * 0.001,
            );
        }
        self.push_settings_text_button(
            pass,
            Self::schematic_info_button_rect(dialog, 0),
            self.localize_bundle_markup_text("@back"),
            Some("left"),
            Layer::END_PIXELED + 0.083,
        );
    }

    fn tech_tree_node_locked(node: &TechNode) -> bool {
        !node.content.unlocked_host
    }

    fn tech_tree_node_selectable(node: &TechNode) -> bool {
        node.content.unlocked_host || node.objectives.iter().all(|objective| objective.complete())
    }

    fn tech_tree_node_progress_percent(node: &TechNode) -> Option<i32> {
        if node.requirements.is_empty() {
            return None;
        }
        let total = node
            .requirements
            .iter()
            .map(|stack| stack.amount.max(0))
            .sum::<i32>();
        if total <= 0 {
            return None;
        }
        let finished = node
            .finished_requirements
            .iter()
            .map(|stack| stack.amount.max(0))
            .sum::<i32>();
        Some(((finished as f32 / total as f32) * 100.0).floor() as i32)
    }

    fn tech_tree_node_detail_row_count(node: &TechNode) -> usize {
        let requirement_rows = if node.requirements.is_empty() {
            1
        } else {
            node.requirements
                .iter()
                .enumerate()
                .filter(|(index, requirement)| {
                    let finished = node
                        .finished_requirements
                        .get(*index)
                        .map(|stack| stack.amount)
                        .unwrap_or(0);
                    requirement.amount > finished
                })
                .count()
                .max(1)
        };
        let objective_rows = node
            .objectives
            .iter()
            .filter(|objective| !objective.complete())
            .count()
            .max(usize::from(node.objectives.is_empty()));
        4 + requirement_rows + objective_rows
    }

    fn tech_tree_global_item_amount(&self, item_id: i16) -> i32 {
        self.game_state
            .teams
            .get_or_null(self.player.team.0)
            .or_else(|| {
                self.game_state
                    .teams
                    .get_or_null(self.game_state.rules.default_team as u8)
            })
            .and_then(|team| team.core_items.get(&item_id).copied())
            .unwrap_or(0)
    }

    fn tech_tree_content_icon_symbol(&self, content: &TechContentRef) -> Option<String> {
        match content.content_type {
            ContentType::Block => self
                .content_loader
                .block_by_name(&content.name)
                .and_then(block_full_icon_region_symbol),
            ContentType::Unit => unit_full_icon_region_symbol(&content.name, &self.content_loader),
            ContentType::Item => item_full_icon_region_symbol(&content.name, &self.content_loader),
            ContentType::Liquid => {
                liquid_full_icon_region_symbol(&content.name, &self.content_loader)
            }
            _ => None,
        }
        .filter(|symbol| self.texture_atlas.lookup(symbol).is_ok())
        .or_else(|| Some(content.name.clone()))
    }

