    fn about_links_line(&self) -> String {
        let names = self
            .visible_about_links()
            .into_iter()
            .map(|link| link.name)
            .collect::<Vec<_>>()
            .join(", ");
        format!("links: {names}")
    }

    fn about_link_description(&self, link: &AboutLinkEntry) -> String {
        self.localize_bundle_markup_text(format!("@link.{}.description", link.name))
    }

    fn about_route_link_lines(&self) -> Vec<String> {
        let mut lines = vec![
            self.localize_bundle_markup_text("@credits.text"),
            self.about_links_line(),
            format!("button: {}", self.localize_bundle_markup_text("@credits")),
        ];
        for link in self.visible_about_links() {
            lines.push(format!(
                "{}: {}",
                link.name,
                self.about_link_description(link)
            ));
            lines.push(format!("url: {}", link.url));
        }
        lines
    }

    fn about_route_credit_lines(&self) -> Vec<String> {
        let mut lines = vec![
            self.localize_bundle_markup_text("@credits.text"),
            format!(
                "{} ({})",
                self.localize_bundle_markup_text("@contributors"),
                ABOUT_CONTRIBUTORS.len()
            ),
        ];
        for chunk in ABOUT_CONTRIBUTORS.chunks(3) {
            lines.push(chunk.join(" | "));
        }
        lines
    }

    fn push_about_route_page(&self, pass: &mut RenderPass, panel: RenderRect) {
        self.push_about_links_page(pass, panel);
        if self.about_route_page == DesktopAboutRoutePage::Credits {
            self.push_about_credits_page(pass, panel);
        }
    }

    fn push_about_links_page(&self, pass: &mut RenderPass, panel: RenderRect) {
        let clip = Self::about_links_clip_rect_for_panel(panel);
        let links = self.visible_about_links();
        let visible_rows = Self::about_links_visible_capacity_for_panel(panel);
        let max_scroll = Self::max_about_links_scroll_offset_for_counts(links.len(), visible_rows);
        let scroll_offset = self.about_links_scroll_offset.min(max_scroll);
        pass.push(RenderCommand::set_clip(clip));
        for (visible_index, link) in links.into_iter().skip(scroll_offset).enumerate() {
            let rect = Self::about_link_card_rect_for_panel(panel, visible_index);
            self.push_about_link_card(pass, rect, link, visible_index);
        }
        pass.push(RenderCommand::clear_clip());
        if max_scroll > 0 {
            let track = RenderRect::new(clip.right() - 5.0, clip.y, 4.0, clip.height);
            let visible_ratio =
                (visible_rows as f32 / (visible_rows + max_scroll) as f32).clamp(0.05, 1.0);
            let thumb_height = (track.height * visible_ratio).max(18.0);
            let progress = scroll_offset as f32 / max_scroll as f32;
            let thumb = RenderRect::new(
                track.x,
                track.y + track.height - thumb_height - (track.height - thumb_height) * progress,
                track.width,
                thumb_height,
            );
            pass.push(RenderCommand::fill_rect(
                track,
                [0.10, 0.14, 0.18, 0.64],
                Layer::END_PIXELED + 0.088,
            ));
            pass.push(RenderCommand::fill_rect(
                thumb,
                [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, 0.86],
                Layer::END_PIXELED + 0.089,
            ));
        }
    }

    fn push_about_link_card(
        &self,
        pass: &mut RenderPass,
        rect: RenderRect,
        link: &AboutLinkEntry,
        index: usize,
    ) {
        let base_layer = Layer::END_PIXELED + 0.03 + index as f32 * 0.0001;
        pass.push(RenderCommand::fill_rect(
            rect,
            [0.10, 0.11, 0.14, 0.94],
            base_layer,
        ));
        pass.push(RenderCommand::draw_sprite(
            "whiteui",
            rect,
            [0.12, 0.13, 0.16, 0.96],
            0.0,
            base_layer + 0.001,
        ));
        pass.push(RenderCommand::fill_rect(
            RenderRect::new(rect.x, rect.y, 10.0, rect.height - 5.0),
            link.color_rgba(),
            base_layer + 0.002,
        ));
        pass.push(RenderCommand::fill_rect(
            RenderRect::new(rect.x, rect.y, 10.0, 5.0),
            link.dark_color_rgba(),
            base_layer + 0.003,
        ));

        let icon_rect = RenderRect::new(rect.x + 12.0, rect.y + 5.0, 42.0, rect.height - 10.0);
        pass.push(RenderCommand::fill_rect(
            icon_rect,
            [0.08, 0.09, 0.12, 0.98],
            base_layer + 0.004,
        ));
        pass.push(RenderCommand::stroke_rect(
            icon_rect,
            link.dark_color_rgba(),
            1.0,
            base_layer + 0.005,
        ));
        let icon_glyph = desktop_ui_icon_glyph_or_label(link.icon, link.icon);
        pass.push(RenderCommand::draw_text_styled(
            icon_glyph,
            icon_rect.center(),
            [0.92, 0.96, 1.0, 1.0],
            18.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_font(RenderFontId::Icon)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            base_layer + 0.006,
        ));

        let action_rect =
            RenderRect::new(rect.right() - 35.0, rect.y + 6.0, 28.0, rect.height - 12.0);
        pass.push(RenderCommand::draw_sprite(
            "button.9",
            action_rect,
            [1.0, 1.0, 1.0, 1.0],
            0.0,
            base_layer + 0.006,
        ));
        let link_glyph = desktop_ui_icon_glyph_or_label("link", "link");
        pass.push(RenderCommand::draw_text_styled(
            link_glyph,
            action_rect.center(),
            [0.92, 0.98, 1.0, 1.0],
            14.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_font(RenderFontId::Icon)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            base_layer + 0.007,
        ));

        let text_x = icon_rect.right() + 8.0;
        let text_width = (action_rect.x - text_x - 6.0).max(48.0);
        pass.push(RenderCommand::draw_text_styled(
            link.title,
            RenderPoint::new(text_x, rect.y + rect.height - 13.0),
            [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, 1.0],
            11.5,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Start)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            base_layer + 0.008,
        ));
        pass.push(RenderCommand::draw_text_styled(
            self.about_link_description(link),
            RenderPoint::new(text_x, rect.y + rect.height - 29.0),
            [0.74, 0.78, 0.82, 1.0],
            if text_width < 120.0 { 8.0 } else { 9.0 },
            0.0,
            RenderTextStyle::new(RenderTextAlign::Start)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            base_layer + 0.009,
        ));
        pass.push(RenderCommand::draw_text_styled(
            format!("url: {}", link.url),
            RenderPoint::new(text_x, rect.y + 11.0),
            [0.48, 0.56, 0.64, 1.0],
            7.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Start)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true),
            base_layer + 0.010,
        ));
    }

