    fn mods_route_detail_button_specs(
        &self,
        index: usize,
    ) -> Vec<(DesktopMenuRouteShellAction, &'static str, &'static str)> {
        let mut specs = vec![(
            DesktopMenuRouteShellAction::CloseModsDetail,
            "@back",
            "left",
        )];
        if self.mods_route_mod_root_at_index(index).is_some() {
            specs.push((
                DesktopMenuRouteShellAction::OpenModsFolder(index),
                "@mods.openfolder",
                "link",
            ));
        }
        if self.mods_route_mod_repo_at_index(index).is_some() {
            specs.push((
                DesktopMenuRouteShellAction::ModsDetailOpenGithub(index),
                "@mods.github.open",
                "link",
            ));
            specs.push((
                DesktopMenuRouteShellAction::ModsDetailReinstall(index),
                "@mods.browser.reinstall",
                "download",
            ));
        }
        specs
    }

    fn mods_route_detail_button_rect(
        dialog: RenderRect,
        index: usize,
        button_count: usize,
    ) -> RenderRect {
        if button_count <= 3 {
            return Self::schematic_info_button_rect(dialog, index);
        }
        let gap = 8.0;
        let width = ((dialog.width - 36.0 - gap * (button_count.saturating_sub(1) as f32))
            / button_count as f32)
            .clamp(70.0, 150.0);
        let total = width * button_count as f32 + gap * (button_count.saturating_sub(1) as f32);
        RenderRect::new(
            dialog.center().x - total * 0.5 + index as f32 * (width + gap),
            dialog.y + 18.0,
            width,
            46.0,
        )
    }

    fn mods_route_detail_content_button_rect(dialog: RenderRect) -> RenderRect {
        let width = (dialog.width - 68.0).clamp(220.0, 360.0);
        RenderRect::new(
            dialog.center().x - width * 0.5,
            dialog.y + 70.0,
            width,
            46.0,
        )
    }

    fn mods_route_detail_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopMenuRouteShellAction> {
        let index = self.mods_selected_mod_index?;
        let dialog = Self::mods_route_detail_dialog_rect_for_panel(panel);
        let specs = self.mods_route_detail_button_specs(index);
        for (button_index, (action, _, _)) in specs.iter().enumerate() {
            if Self::mods_route_detail_button_rect(dialog, button_index, specs.len())
                .contains_point(point)
            {
                return Some(*action);
            }
        }
        if Self::mods_route_detail_content_button_rect(dialog).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::OpenModsContent(index));
        }
        None
    }

    fn mods_route_detail_dialog_rect_for_panel(panel: RenderRect) -> RenderRect {
        Self::schematic_info_dialog_rect_for_panel(panel)
    }

    fn mods_content_action_at_point(
        &self,
        panel: RenderRect,
        point: RenderPoint,
    ) -> Option<DesktopMenuRouteShellAction> {
        self.mods_content_dialog_index?;
        let dialog = Self::mods_content_dialog_rect_for_panel(panel);
        if Self::schematic_info_button_rect(dialog, 0).contains_point(point) {
            return Some(DesktopMenuRouteShellAction::CloseModsContent);
        }
        let grid = Self::mods_content_grid_rect_for_dialog(dialog);
        for (entry_index, _) in self
            .mods_content_entries_for_mod(self.mods_content_dialog_index?)
            .iter()
            .take(8)
            .enumerate()
        {
            if Self::mods_content_entry_rect_for_grid(grid, entry_index).contains_point(point) {
                return Some(DesktopMenuRouteShellAction::OpenModsContentEntry(
                    entry_index,
                ));
            }
        }
        None
    }

    fn mods_content_dialog_rect_for_panel(panel: RenderRect) -> RenderRect {
        let detail = Self::mods_route_detail_dialog_rect_for_panel(panel);
        RenderRect::new(
            detail.x + 24.0,
            detail.y + 24.0,
            (detail.width - 48.0).max(240.0),
            (detail.height - 48.0).max(220.0),
        )
    }

    fn mods_content_grid_rect_for_dialog(dialog: RenderRect) -> RenderRect {
        RenderRect::new(
            dialog.x + 28.0,
            dialog.y + 76.0,
            dialog.width - 56.0,
            (dialog.height - 142.0).max(120.0),
        )
    }

    fn mods_content_entry_rect_for_grid(grid: RenderRect, index: usize) -> RenderRect {
        let columns = 2usize;
        let gap = 8.0;
        let card_height = 58.0;
        let card_width = ((grid.width - gap) / columns as f32).max(120.0);
        let row = index / columns;
        let column = index % columns;
        RenderRect::new(
            grid.x + column as f32 * (card_width + gap),
            grid.y + grid.height - card_height - row as f32 * (card_height + gap),
            card_width,
            card_height,
        )
    }

    fn mods_content_entries_for_mod(&self, index: usize) -> Vec<DesktopModsContentEntry> {
        let Some(mod_name) = self.mods_route_mod_display_name_at_index(index) else {
            return Vec::new();
        };
        let meta = self.mods_route_mod_meta_at_index(index);
        let mut entries = vec![
            DesktopModsContentEntry {
                title: self.localize_bundle_markup_text("@editor.name"),
                detail: mod_name.to_string(),
                icon: "book",
            },
            DesktopModsContentEntry {
                title: self.localize_bundle_markup_text("@editor.author"),
                detail: self.localize_bundle_markup_text(
                    meta.map(ModMetadata::author_or_unknown)
                        .unwrap_or("@unknown"),
                ),
                icon: "players",
            },
            DesktopModsContentEntry {
                title: self.localize_bundle_markup_text("@mod.version"),
                detail: self.localize_bundle_markup_text(
                    meta.map(ModMetadata::version_or_unknown)
                        .unwrap_or("@unknown"),
                ),
                icon: "info",
            },
        ];
        if let Some(description) = meta
            .and_then(|meta| meta.description.as_deref())
            .map(str::trim)
            .filter(|description| !description.is_empty())
        {
            entries.push(DesktopModsContentEntry {
                title: self.localize_bundle_markup_text("@editor.description"),
                detail: description.to_string(),
                icon: "fileText",
            });
        }
        if let Some(repo) = self.mods_route_mod_repo_at_index(index) {
            entries.push(DesktopModsContentEntry {
                title: self.localize_bundle_markup_text("@mods.github.open"),
                detail: repo.to_string(),
                icon: "github",
            });
        }
        if let Some(root) = self.mods_route_mod_root_label_at_index(index) {
            entries.push(DesktopModsContentEntry {
                title: self.localize_bundle_markup_text("@mods.openfolder"),
                detail: root,
                icon: "folder",
            });
        }
        entries
    }

    fn push_mods_detail_dialog(&self, pass: &mut RenderPass, panel: RenderRect) {
        let Some(index) = self.mods_selected_mod_index else {
            return;
        };
        let Some(mod_name) = self.mods_route_mod_display_name_at_index(index) else {
            return;
        };
        let meta = self.mods_route_mod_meta_at_index(index);
        let dialog = Self::mods_route_detail_dialog_rect_for_panel(panel);
        pass.push(RenderCommand::fill_rect(
            panel,
            [0.0, 0.0, 0.0, 0.42],
            Layer::END_PIXELED + 0.070,
        ));
        pass.push(RenderCommand::draw_sprite(
            Self::settings_drawable_symbol("pane"),
            dialog,
            [1.0, 1.0, 1.0, 0.98],
            0.0,
            Layer::END_PIXELED + 0.071,
        ));
        pass.push(RenderCommand::stroke_rect(
            dialog,
            [0.52, 0.68, 0.82, 0.95],
            2.0,
            Layer::END_PIXELED + 0.072,
        ));
        pass.push(RenderCommand::draw_text_styled(
            format!(
                "{} {mod_name}",
                self.localize_bundle_markup_text("@mods.name")
            ),
            RenderPoint::new(dialog.center().x, dialog.y + dialog.height - 28.0),
            [0.94, 0.98, 1.0, 1.0],
            15.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            Layer::END_PIXELED + 0.076,
        ));
        if let Some(root) = self.mods_route_mod_root_at_index(index) {
            pass.push(RenderCommand::draw_text_styled(
                format!(
                    "{}: {root}",
                    self.localize_bundle_markup_text("@mods.openfolder")
                ),
                RenderPoint::new(dialog.center().x, dialog.y + dialog.height - 58.0),
                [0.62, 0.72, 0.8, 1.0],
                10.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.076,
            ));
        }
        let version = meta
            .map(ModMetadata::version_or_unknown)
            .unwrap_or("@unknown");
        let author = meta
            .map(ModMetadata::author_or_unknown)
            .unwrap_or("@unknown");
        let mut details = vec![
            format!(
                "{} {mod_name}",
                self.localize_bundle_markup_text("@editor.name")
            ),
            format!(
                "{} {}",
                self.localize_bundle_markup_text("@editor.author"),
                self.localize_bundle_markup_text(author)
            ),
            format!(
                "{} {}",
                self.localize_bundle_markup_text("@mod.version"),
                self.localize_bundle_markup_text(version)
            ),
        ];
        if let Some(description) = meta
            .and_then(|meta| meta.description.as_deref())
            .filter(|description| !description.trim().is_empty())
        {
            details.push(format!(
                "{} {description}",
                self.localize_bundle_markup_text("@editor.description")
            ));
        }
        if let Some(repo) = meta
            .and_then(|meta| meta.repo.as_deref())
            .filter(|repo| !repo.trim().is_empty())
        {
            details.push(format!(
                "{} {repo}",
                self.localize_bundle_markup_text("@mods.github.open")
            ));
        }
        if let Some(state_text) = self.mods_route_mod_state_text_at_index(index) {
            details.push(state_text);
        }
        details.extend(self.mods_route_mod_state_details_at_index(index));
        for (row, detail) in details.iter().enumerate() {
            pass.push(RenderCommand::draw_text_styled(
                detail,
                RenderPoint::new(
                    dialog.x + 34.0,
                    dialog.y + dialog.height - 116.0 - row as f32 * 24.0,
                ),
                [0.72, 0.80, 0.86, 1.0],
                11.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Start)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.077 + row as f32 * 0.0001,
            ));
        }
        let button_specs = self.mods_route_detail_button_specs(index);
        for (button_index, (_, label, icon)) in button_specs.iter().enumerate() {
            self.push_settings_text_button(
                pass,
                Self::mods_route_detail_button_rect(dialog, button_index, button_specs.len()),
                self.localize_bundle_markup_text(*label),
                Some(*icon),
                Layer::END_PIXELED + 0.083 + button_index as f32 * 0.0005,
            );
        }
        self.push_settings_text_button(
            pass,
            Self::mods_route_detail_content_button_rect(dialog),
            self.localize_bundle_markup_text("@mods.viewcontent"),
            Some("book"),
            Layer::END_PIXELED + 0.086,
        );
    }

    fn push_mods_content_dialog(&self, pass: &mut RenderPass, panel: RenderRect) {
        let Some(index) = self.mods_content_dialog_index else {
            return;
        };
        let Some(mod_name) = self.mods_route_mod_display_name_at_index(index) else {
            return;
        };
        let dialog = Self::mods_content_dialog_rect_for_panel(panel);
        pass.push(RenderCommand::fill_rect(
            panel,
            [0.0, 0.0, 0.0, 0.46],
            Layer::END_PIXELED + 0.086,
        ));
        pass.push(RenderCommand::draw_sprite(
            Self::settings_drawable_symbol("pane"),
            dialog,
            [1.0, 1.0, 1.0, 0.98],
            0.0,
            Layer::END_PIXELED + 0.087,
        ));
        pass.push(RenderCommand::stroke_rect(
            dialog,
            [0.52, 0.68, 0.82, 0.95],
            2.0,
            Layer::END_PIXELED + 0.088,
        ));
        pass.push(RenderCommand::draw_text_styled(
            format!(
                "{}: {mod_name}",
                self.localize_bundle_markup_text("@mods.viewcontent")
            ),
            RenderPoint::new(dialog.center().x, dialog.y + dialog.height - 30.0),
            [0.94, 0.98, 1.0, 1.0],
            14.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Center)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            Layer::END_PIXELED + 0.089,
        ));
        let entries = self.mods_content_entries_for_mod(index);
        let grid = Self::mods_content_grid_rect_for_dialog(dialog);
        if entries.is_empty() {
            pass.push(RenderCommand::draw_text_styled(
                self.localize_bundle_markup_text("@none"),
                grid.center(),
                [0.70, 0.78, 0.84, 1.0],
                12.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.090,
            ));
        }
        for (entry_index, entry) in entries.iter().take(8).enumerate() {
            let card = Self::mods_content_entry_rect_for_grid(grid, entry_index);
            let layer = Layer::END_PIXELED + 0.090 + entry_index as f32 * 0.001;
            let selected = self.last_mods_content_entry_index == Some(entry_index);
            pass.push(RenderCommand::draw_sprite(
                Self::settings_image_button_symbol("defaulti", selected, false),
                card,
                [1.0, 1.0, 1.0, if selected { 0.98 } else { 0.88 }],
                0.0,
                layer,
            ));
            pass.push(RenderCommand::stroke_rect(
                card,
                if selected {
                    [Pal::ACCENT.r, Pal::ACCENT.g, Pal::ACCENT.b, 0.96]
                } else {
                    [0.38, 0.50, 0.62, 0.78]
                },
                if selected { 2.0 } else { 1.0 },
                layer + 0.0001,
            ));
            pass.push(RenderCommand::draw_text_styled(
                desktop_ui_icon_glyph_or_label(entry.icon, entry.icon),
                RenderPoint::new(card.x + 24.0, card.center().y),
                [0.78, 0.88, 0.96, 1.0],
                16.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Center)
                    .with_font(RenderFontId::Icon)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true)
                    .with_outline(true),
                layer + 0.0002,
            ));
            pass.push(RenderCommand::draw_text_styled(
                format!("{} {}", entry.title, entry.detail),
                RenderPoint::new(card.x + 48.0, card.center().y + 9.0),
                [0.88, 0.96, 1.0, 1.0],
                10.5,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Start)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true)
                    .with_outline(true),
                layer + 0.0003,
            ));
            pass.push(RenderCommand::draw_text_styled(
                self.localize_bundle_markup_text("@mods.viewcontent"),
                RenderPoint::new(card.x + 48.0, card.center().y - 11.0),
                [0.56, 0.68, 0.76, 1.0],
                8.5,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Start)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                layer + 0.0004,
            ));
        }
        self.push_settings_text_button(
            pass,
            Self::schematic_info_button_rect(dialog, 0),
            self.localize_bundle_markup_text("@back"),
            Some("left"),
            Layer::END_PIXELED + 0.092,
        );
    }

