    fn menu_boot_diagnostic_lines(&self) -> Vec<String> {
        let mut lines = Vec::new();
        let font_report = self.font_asset_validation_report();
        if !font_report.all_resolved() {
            lines.push(format!(
                "asset warning: fonts {}/{}",
                font_report.resolved_count, font_report.total_count
            ));
            if let Some(source) = font_report.missing_source_paths.first() {
                lines.push(format!("missing font: {source}"));
            }
        }

        let icon_report = self.content_icon_glyph_registry_report();
        if !icon_report.loaded() {
            lines.push(format!("asset warning: icons {}", icon_report.source_path));
            if let Some(error) = icon_report.load_error.as_deref() {
                lines.push(format!("icon load: {error}"));
            } else if icon_report.file_path.is_none() {
                lines.push("icon file unresolved".into());
            } else if icon_report.icon_count == 0 {
                lines.push("icon file contains no glyphs".into());
            }
        }

        let font_atlas = self.font_atlas_plan();
        if !font_atlas.ready_for_real_upload() {
            if let Some(symbol) = font_atlas.missing_icon_atlas_symbols.first() {
                lines.push(format!("missing icon atlas: {symbol}"));
            }
            if let Some(error) = font_atlas.content_icon_load_error.as_deref() {
                if !lines
                    .iter()
                    .any(|line| line == &format!("icon load: {error}"))
                {
                    lines.push(format!("icon load: {error}"));
                }
            }
        }

        lines.truncate(5);
        lines
    }

    fn push_menu_boot_diagnostics(&self, pass: &mut RenderPass, viewport: RenderViewport) {
        if std::env::var_os("MINDUSTRY_DESKTOP_HIDE_BOOT_DIAGNOSTICS").is_some() {
            return;
        }
        if !cfg!(test) && std::env::var_os("MINDUSTRY_DESKTOP_SHOW_BOOT_DIAGNOSTICS").is_none() {
            return;
        }
        let lines = self.menu_boot_diagnostic_lines();
        if lines.is_empty() {
            return;
        }
        let panel_width = (viewport.width - 32.0).clamp(280.0, 560.0);
        let panel_height = 28.0 + lines.len() as f32 * 16.0;
        let panel = RenderRect::new(
            viewport.x + 16.0,
            viewport.y + viewport.height - panel_height - 16.0,
            panel_width,
            panel_height,
        );
        pass.push(RenderCommand::fill_rect(
            panel,
            [0.20, 0.04, 0.03, 0.90],
            Layer::END_PIXELED + 0.110,
        ));
        pass.push(RenderCommand::stroke_rect(
            panel,
            [1.0, 0.34, 0.18, 0.98],
            2.0,
            Layer::END_PIXELED + 0.111,
        ));
        pass.push(RenderCommand::draw_text_styled(
            "render asset diagnostics",
            RenderPoint::new(panel.x + 12.0, panel.y + panel.height - 14.0),
            [1.0, 0.72, 0.58, 1.0],
            10.0,
            0.0,
            RenderTextStyle::new(RenderTextAlign::Start)
                .with_vertical_align(RenderTextVerticalAlign::Center)
                .with_integer_position(true)
                .with_outline(true),
            Layer::END_PIXELED + 0.112,
        ));
        for (index, line) in lines.iter().enumerate() {
            pass.push(RenderCommand::draw_text_styled(
                line.clone(),
                RenderPoint::new(
                    panel.x + 12.0,
                    panel.y + panel.height - 32.0 - index as f32 * 16.0,
                ),
                [0.98, 0.90, 0.82, 1.0],
                9.0,
                0.0,
                RenderTextStyle::new(RenderTextAlign::Start)
                    .with_vertical_align(RenderTextVerticalAlign::Center)
                    .with_integer_position(true),
                Layer::END_PIXELED + 0.113 + index as f32 * 0.0001,
            ));
        }
    }

    fn menu_background_layer_commands(&self, viewport: RenderViewport) -> Vec<RenderCommand> {
        let width = viewport.width.max(1.0);
        let height = viewport.height.max(1.0);
        let rect = viewport.as_rect();
        let time = self.menu_renderer_state.time;
        let mut commands = Vec::with_capacity(80);
        commands.push(RenderCommand::fill_rect(
            rect,
            [0.010, 0.015, 0.030, 1.0],
            -120.0,
        ));

        let bands = 10usize;
        for band in 0..bands {
            let t0 = band as f32 / bands as f32;
            let band_height = (height / bands as f32).ceil() + 1.0;
            let y = viewport.y + t0 * height;
            commands.push(RenderCommand::fill_rect(
                RenderRect::new(viewport.x, y, width, band_height),
                [
                    0.015 + 0.018 * t0,
                    0.022 + 0.030 * t0,
                    0.045 + 0.075 * t0,
                    1.0,
                ],
                -119.0,
            ));
        }

        for index in 0..42usize {
            let seed = index as u32;
            let x_hash = seed.wrapping_mul(1_103_515_245).wrapping_add(12_345);
            let y_hash = seed.wrapping_mul(747_796_405).wrapping_add(2_891_336_453);
            let x = viewport.x + (x_hash % 10_000) as f32 / 10_000.0 * width;
            let y = viewport.y + (y_hash % 10_000) as f32 / 10_000.0 * height;
            let twinkle = ((time * (0.7 + index as f32 * 0.013)) + index as f32).sin() * 0.5 + 0.5;
            let radius = 0.7 + (index % 3) as f32 * 0.35;
            commands.push(RenderCommand::draw_circle(
                RenderPoint::new(x, y),
                radius,
                [0.62, 0.78, 0.92, 0.28 + twinkle * 0.34],
                true,
                -117.0,
            ));
        }

        let planet_radius = width.min(height) * 0.29;
        let planet_center = RenderPoint::new(
            viewport.x + width * 0.70 + (time * 0.11).sin() * planet_radius * 0.06,
            viewport.y + height * 0.44 + (time * 0.07).cos() * planet_radius * 0.04,
        );
        commands.push(RenderCommand::draw_circle(
            planet_center,
            planet_radius * 1.18,
            [0.05, 0.22, 0.32, 0.20],
            true,
            -112.0,
        ));
        commands.push(RenderCommand::draw_circle(
            planet_center,
            planet_radius,
            [0.035, 0.105, 0.125, 0.78],
            true,
            -111.0,
        ));
        commands.push(RenderCommand::draw_circle(
            RenderPoint::new(
                planet_center.x - planet_radius * 0.18,
                planet_center.y + planet_radius * 0.16,
            ),
            planet_radius * 0.72,
            [0.10, 0.30, 0.24, 0.34],
            true,
            -110.0,
        ));
        commands.push(RenderCommand::draw_polygon(
            planet_center,
            planet_radius * 1.01,
            48,
            time * 0.025,
            [0.34, 0.66, 0.72, 0.22],
            false,
            -109.0,
        ));

        for index in 0..9usize {
            let offset = (index as f32 - 4.0) * planet_radius * 0.18;
            let half = (planet_radius.powi(2) - offset.powi(2)).max(0.0).sqrt();
            commands.push(RenderCommand::draw_line(
                RenderPoint::new(planet_center.x - half, planet_center.y + offset),
                RenderPoint::new(planet_center.x + half, planet_center.y + offset),
                1.0,
                [0.36, 0.74, 0.78, 0.10],
                -108.0,
            ));
            commands.push(RenderCommand::draw_line(
                RenderPoint::new(planet_center.x + offset, planet_center.y - half),
                RenderPoint::new(planet_center.x + offset, planet_center.y + half),
                1.0,
                [0.36, 0.74, 0.78, 0.07],
                -107.0,
            ));
        }

        for index in 0..5usize {
            let drift = time * (0.018 + index as f32 * 0.003);
            let radius = planet_radius * (0.62 + index as f32 * 0.08);
            commands.push(RenderCommand::draw_polygon(
                RenderPoint::new(
                    planet_center.x + (drift + index as f32).sin() * planet_radius * 0.06,
                    planet_center.y + (drift + index as f32).cos() * planet_radius * 0.04,
                ),
                radius,
                7 + index,
                drift,
                [0.78, 0.88, 0.92, 0.035 + index as f32 * 0.008],
                false,
                -106.0,
            ));
        }

        commands.push(RenderCommand::fill_rect(rect, [0.0, 0.0, 0.0, 0.22], -90.0));
        commands
    }

    fn render_command_layer(command: &RenderCommand) -> Option<f32> {
        match command {
            RenderCommand::FillRect { layer, .. }
            | RenderCommand::StrokeRect { layer, .. }
            | RenderCommand::DrawSprite { layer, .. }
            | RenderCommand::DrawLine { layer, .. }
            | RenderCommand::DrawCircle { layer, .. }
            | RenderCommand::DrawPolygon { layer, .. }
            | RenderCommand::DrawTriangle { layer, .. }
            | RenderCommand::DrawPixel { layer, .. }
            | RenderCommand::DrawText { layer, .. } => Some(*layer),
            RenderCommand::Clear { .. }
            | RenderCommand::SetBlend { .. }
            | RenderCommand::SetClip { .. }
            | RenderCommand::ClearClip
            | RenderCommand::Custom { .. } => None,
        }
    }

    fn menu_pass_has_java_world_background(pass: &RenderPass) -> bool {
        pass.commands.iter().any(|command| {
            Self::render_command_layer(command)
                .is_some_and(|layer| (-5.0..=MENU_DARKNESS_LAYER).contains(&layer))
        })
    }

    fn menu_pass_has_synthetic_background(pass: &RenderPass) -> bool {
        pass.commands.iter().any(|command| {
            Self::render_command_layer(command)
                .is_some_and(|layer| (-130.0..=-80.0).contains(&layer))
        })
    }

    fn insert_menu_background_layers(&self, pass: &mut RenderPass, viewport: RenderViewport) {
        if Self::menu_pass_has_java_world_background(pass)
            || Self::menu_pass_has_synthetic_background(pass)
        {
            return;
        }
        let commands = self.menu_background_layer_commands(viewport);
        let insert_at = pass
            .commands
            .iter()
            .position(|command| matches!(command, RenderCommand::Clear { .. }))
            .map(|index| index + 1)
            .unwrap_or(0);
        pass.commands.splice(insert_at..insert_at, commands);
    }

