    #[test]
    fn desktop_launcher_routes_world_label_snapshot_entities_into_overlay_pass() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let mut label = WorldLabelComp::new(9904, 40.0, 56.0);
        label.text = "rally".into();
        label.font_size = 1.5;
        label.z = 155.0;
        label.flags = WorldLabelComp::FLAG_BACKGROUND
            | WorldLabelComp::FLAG_OUTLINE
            | WorldLabelComp::FLAG_ALIGN_RIGHT;
        launcher
            .runtime
            .client_world_label_snapshot_entities
            .insert(label.id, label);

        let viewport = RenderViewport::new(0.0, 0.0, 120.0, 80.0);
        let camera = RenderCamera::new(RenderPoint::new(60.0, 40.0), viewport);
        let minimap_camera = MinimapCamera::new(60.0, 40.0, 120.0, 80.0);
        let frame = launcher.graphics_frame_for_render(
            15,
            camera,
            viewport,
            minimap_camera,
            sample_minimap_overlay_input(true),
        );
        let render_frame = frame.bundle.render_frame.as_ref().unwrap();
        let overlay = render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Overlay
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawText { text, .. } if text == "rally")
                    })
            })
            .expect("world label should be routed into an overlay render pass");
        let text_index = overlay
            .commands
            .iter()
            .position(|command| {
                matches!(command, RenderCommand::DrawText { text, .. } if text == "rally")
            })
            .expect("world label overlay pass should contain DrawText");
        assert!(
            overlay.commands[..text_index]
                .iter()
                .any(|command| matches!(command, RenderCommand::FillRect { .. })),
            "world label background should be emitted before DrawText"
        );
        match &overlay.commands[text_index] {
            RenderCommand::DrawText {
                text,
                position,
                size,
                align,
                style,
                layer,
                ..
            } => {
                assert_eq!(text, "rally");
                assert_eq!(*position, RenderPoint::new(40.0, 56.0));
                assert_eq!(*size, 18.0);
                assert_eq!(*align, RenderTextAlign::End);
                assert_eq!(style.horizontal_align, RenderTextAlign::End);
                assert_eq!(style.vertical_align, RenderTextVerticalAlign::Center);
                assert_eq!(style.font, RenderFontId::Outline);
                assert!(style.outline);
                assert_eq!(*layer, 155.0);
            }
            other => panic!("expected world label DrawText, got {other:?}"),
        }

        let mut renderer = HeadlessDesktopGraphicsRenderer::default();
        renderer.render_graphics_frame(&frame);
        assert!(
            renderer
                .last_opengl_backend_executor_state
                .draw_text_commands
                >= 1
        );
    }

    #[test]
    fn desktop_launcher_routes_fire_snapshot_entities_into_overlay_and_light_passes() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let mut fire = FireComp::new(42.25, 133.75, 120.0);
        fire.animation = 38.9;
        fire.warmup = 9.0;
        launcher
            .runtime
            .client_fire_snapshot_entities
            .insert(7002, fire);

        launcher.update();

        let viewport = RenderViewport::new(0.0, 0.0, 180.0, 180.0);
        let camera = RenderCamera::new(RenderPoint::new(90.0, 90.0), viewport);
        let minimap_camera = MinimapCamera::new(90.0, 90.0, 180.0, 180.0);
        let frame = launcher.graphics_frame_for_render(
            17,
            camera,
            viewport,
            minimap_camera,
            sample_minimap_overlay_input(true),
        );
        assert!(frame.texture_atlas.has("fire39"));

        let render_frame = frame.bundle.render_frame.as_ref().unwrap();
        let overlay = render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Overlay
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawSprite { symbol, .. } if symbol == "fire39")
                    })
            })
            .expect("fire snapshot should emit an overlay sprite pass");
        let sprite = overlay
            .commands
            .iter()
            .find(|command| {
                matches!(command, RenderCommand::DrawSprite { symbol, .. } if symbol == "fire39")
            })
            .expect("fire overlay pass should contain fire sprite");
        match sprite {
            RenderCommand::DrawSprite {
                symbol,
                rect,
                tint,
                layer,
                ..
            } => {
                assert_eq!(symbol, "fire39");
                assert!((rect.center().x - 42.25).abs() <= 2.0);
                assert!((rect.center().y - 133.75).abs() <= 2.0);
                assert_eq!(*tint, [1.0, 1.0, 1.0, 0.5]);
                assert_eq!(*layer, Layer::EFFECT);
            }
            other => panic!("expected fire DrawSprite, got {other:?}"),
        }

        let light_pass = render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Lighting
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawCircle { center, .. }
                            if *center == RenderPoint::new(42.25, 133.75))
                    })
            })
            .expect("fire snapshot should emit a light render pass");
        match light_pass.commands.iter().find(|command| {
            matches!(command, RenderCommand::DrawCircle { center, .. }
                if *center == RenderPoint::new(42.25, 133.75))
        }) {
            Some(RenderCommand::DrawCircle {
                radius,
                color,
                filled,
                layer,
                ..
            }) => {
                assert!(*radius > 50.0);
                assert!(*filled);
                assert_eq!(*layer, 50.0);
                assert!((color[0] - Pal::LIGHT_FLAME.r).abs() < 0.0001);
                assert!((color[1] - Pal::LIGHT_FLAME.g).abs() < 0.0001);
                assert!((color[2] - Pal::LIGHT_FLAME.b).abs() < 0.0001);
                assert!((color[3] - 0.3).abs() < 0.0001);
            }
            other => panic!("expected fire light DrawCircle, got {other:?}"),
        }
    }

    #[test]
    fn desktop_launcher_routes_basic_bullet_snapshot_entities_into_overlay_pass() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let bullet_content = launcher
            .content_loader
            .bullet_by_name("dagger_basic")
            .expect("base content should include dagger basic bullet");
        assert!(launcher.texture_atlas.has("bullet"));
        assert!(launcher.texture_atlas.has("bullet-back"));

        let mut bullet = BulletComp::new(
            bullet_content.id(),
            TeamId(1),
            type_io::EntityRef::null(),
            32.0,
            48.0,
        );
        bullet.lifetime = 60.0;
        bullet.time = 30.0;
        bullet.rotation = 180.0;
        launcher
            .runtime
            .client_bullet_snapshot_entities
            .insert(7103, bullet);

        let viewport = RenderViewport::new(0.0, 0.0, 96.0, 96.0);
        let camera = RenderCamera::new(RenderPoint::new(48.0, 48.0), viewport);
        let minimap_camera = MinimapCamera::new(48.0, 48.0, 96.0, 96.0);
        let frame = launcher.graphics_frame_for_render(
            18,
            camera,
            viewport,
            minimap_camera,
            sample_minimap_overlay_input(true),
        );
        let render_frame = frame.bundle.render_frame.as_ref().unwrap();
        let overlay = render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Overlay
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawSprite { symbol, .. } if symbol == "bullet")
                    })
            })
            .expect("basic bullet snapshot should emit an overlay sprite pass");
        let sprites = overlay
            .commands
            .iter()
            .filter_map(|command| match command {
                RenderCommand::DrawSprite {
                    symbol,
                    rect,
                    tint,
                    rotation,
                    layer,
                    ..
                } => Some((symbol.as_str(), *rect, *tint, *rotation, *layer)),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert_eq!(sprites.len(), 2);
        assert_eq!(sprites[0].0, "bullet-back");
        assert_eq!(sprites[1].0, "bullet");
        assert_eq!(
            sprites[0].2,
            [
                Pal::BULLET_YELLOW_BACK.r,
                Pal::BULLET_YELLOW_BACK.g,
                Pal::BULLET_YELLOW_BACK.b,
                Pal::BULLET_YELLOW_BACK.a,
            ]
        );
        assert_eq!(
            sprites[1].2,
            [
                Pal::BULLET_YELLOW.r,
                Pal::BULLET_YELLOW.g,
                Pal::BULLET_YELLOW.b,
                Pal::BULLET_YELLOW.a,
            ]
        );
        for (_, rect, _, rotation, layer) in sprites {
            assert_eq!(rect.center(), RenderPoint::new(32.0, 48.0));
            assert_eq!(rect.width, 7.0);
            assert_eq!(rect.height, 6.75);
            assert_eq!(rotation, 90.0);
            assert_eq!(layer, Layer::BULLET);
        }
    }

    #[test]
    fn desktop_launcher_routes_laser_bolt_snapshot_lines_into_overlay_pass() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let bullet_content = launcher
            .content_loader
            .bullet_by_name("beta_laser_bolt")
            .expect("base content should include beta laser bolt bullet");
        assert_eq!(bullet_content.spec.kind, super::BulletKind::LaserBolt);

        let mut bullet = BulletComp::new(
            bullet_content.id(),
            TeamId(1),
            type_io::EntityRef::null(),
            32.0,
            48.0,
        );
        bullet.lifetime = 60.0;
        bullet.time = 12.0;
        bullet.rotation = 0.0;
        launcher
            .runtime
            .client_bullet_snapshot_entities
            .insert(7104, bullet);

        let viewport = RenderViewport::new(0.0, 0.0, 96.0, 96.0);
        let camera = RenderCamera::new(RenderPoint::new(48.0, 48.0), viewport);
        let minimap_camera = MinimapCamera::new(48.0, 48.0, 96.0, 96.0);
        let frame = launcher.graphics_frame_for_render(
            23,
            camera,
            viewport,
            minimap_camera,
            sample_minimap_overlay_input(true),
        );
        let render_frame = frame.bundle.render_frame.as_ref().unwrap();
        let overlay = render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Overlay
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawLine { from, to, .. }
                            if *from == RenderPoint::new(29.75, 48.0)
                                && *to == RenderPoint::new(34.25, 48.0))
                    })
            })
            .expect("laser bolt snapshot should emit overlay line commands");

        let bullet_sprite_index = overlay
            .commands
            .iter()
            .position(|command| {
                matches!(command, RenderCommand::DrawSprite { symbol, .. } if symbol == "bullet")
            })
            .expect("LaserBolt super.draw should still emit the front sprite");
        let line_indices = overlay
            .commands
            .iter()
            .enumerate()
            .filter_map(|(index, command)| {
                matches!(command, RenderCommand::DrawLine { .. }).then_some(index)
            })
            .collect::<Vec<_>>();
        assert_eq!(line_indices.len(), 2);
        assert!(
            line_indices.iter().all(|index| *index > bullet_sprite_index),
            "LaserBolt line overlays should follow the BasicBullet sprite commands like Java super.draw()"
        );

        let lines = line_indices
            .iter()
            .map(|index| &overlay.commands[*index])
            .collect::<Vec<_>>();
        match lines[0] {
            RenderCommand::DrawLine {
                from,
                to,
                stroke,
                color,
                layer,
            } => {
                assert_eq!(*from, RenderPoint::new(29.75, 48.0));
                assert_eq!(*to, RenderPoint::new(34.25, 48.0));
                assert_eq!(*stroke, 1.5);
                assert_eq!(
                    *color,
                    super::desktop_effect_render_color(Some(Pal::YELLOW_BOLT_FRONT), 1.0)
                );
                assert_eq!(*layer, Layer::BULLET);
            }
            other => panic!("expected LaserBolt back DrawLine, got {other:?}"),
        }
        match lines[1] {
            RenderCommand::DrawLine {
                from,
                to,
                stroke,
                color,
                layer,
            } => {
                assert_eq!(*from, RenderPoint::new(30.875, 48.0));
                assert_eq!(*to, RenderPoint::new(33.125, 48.0));
                assert_eq!(*stroke, 1.5);
                assert_eq!(
                    *color,
                    super::desktop_effect_render_color(Some(DecalColor::WHITE), 1.0)
                );
                assert_eq!(*layer, Layer::BULLET);
            }
            other => panic!("expected LaserBolt front DrawLine, got {other:?}"),
        }
    }

    #[test]
    fn desktop_launcher_routes_laser_snapshot_primitives_and_light_pass() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let bullet_content = launcher
            .content_loader
            .bullet_by_name("quasar_beam")
            .expect("base content should include quasar laser bullet");
        assert_eq!(bullet_content.spec.kind, super::BulletKind::Laser);

        let mut bullet = BulletComp::new(
            bullet_content.id(),
            TeamId(1),
            type_io::EntityRef::null(),
            32.0,
            48.0,
        );
        bullet.lifetime = 16.0;
        bullet.time = 8.0;
        bullet.rotation = 0.0;
        bullet.fdata = 80.0;
        launcher
            .runtime
            .client_bullet_snapshot_entities
            .insert(7105, bullet);

        let viewport = RenderViewport::new(0.0, 0.0, 160.0, 128.0);
        let camera = RenderCamera::new(RenderPoint::new(80.0, 64.0), viewport);
        let minimap_camera = MinimapCamera::new(80.0, 64.0, 160.0, 128.0);
        let frame = launcher.graphics_frame_for_render(
            24,
            camera,
            viewport,
            minimap_camera,
            sample_minimap_overlay_input(true),
        );
        let render_frame = frame.bundle.render_frame.as_ref().unwrap();
        let overlay = render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Overlay
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawLine { from, to, .. }
                            if *from == RenderPoint::new(32.0, 48.0)
                                && *to == RenderPoint::new(112.0, 48.0))
                    })
            })
            .expect("laser bullet snapshot should emit overlay primitive commands");

        let lines = overlay
            .commands
            .iter()
            .filter_map(|command| match command {
                RenderCommand::DrawLine {
                    from,
                    to,
                    stroke,
                    color,
                    layer,
                } => Some((*from, *to, *stroke, *color, *layer)),
                _ => None,
            })
            .collect::<Vec<_>>();
        let circles = overlay
            .commands
            .iter()
            .filter_map(|command| match command {
                RenderCommand::DrawCircle {
                    center,
                    radius,
                    color,
                    filled,
                    layer,
                } => Some((*center, *radius, *color, *filled, *layer)),
                _ => None,
            })
            .collect::<Vec<_>>();
        let triangles = overlay
            .commands
            .iter()
            .filter_map(|command| match command {
                RenderCommand::DrawTriangle {
                    center,
                    width,
                    length,
                    rotation,
                    color,
                    layer,
                } => Some((*center, *width, *length, *rotation, *color, *layer)),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert_eq!(lines.len(), 3);
        assert_eq!(circles.len(), 3);
        assert_eq!(triangles.len(), 9);
        assert_eq!(lines[0].0, RenderPoint::new(32.0, 48.0));
        assert_eq!(lines[0].1, RenderPoint::new(112.0, 48.0));
        assert_eq!(lines[0].2, 3.75);
        assert_eq!(
            lines[0].3,
            super::desktop_bullet_render_color("heal@0.4", Pal::LANCER_LASER)
        );
        assert_eq!(lines[0].4, Layer::BULLET);

        assert_eq!(triangles[0].0, RenderPoint::new(112.0, 48.0));
        assert_eq!(triangles[0].1, 3.75);
        assert_eq!(triangles[0].2, 22.5);
        assert_eq!(triangles[0].3, 0.0);
        assert_eq!(triangles[1].0, RenderPoint::new(32.0, 48.0));
        assert_eq!(triangles[1].1, 3.75);
        assert_eq!(triangles[1].2, 70.0);
        assert_eq!(triangles[1].3, -45.0);
        assert_eq!(triangles[2].3, 45.0);

        assert_eq!(circles[0].0, RenderPoint::new(32.0, 48.0));
        assert_eq!(circles[0].1, 3.75);
        assert!(circles[0].3);
        assert_eq!(circles[0].4, Layer::BULLET);

        let lighting = render_frame
            .passes
            .iter()
            .find(|pass| {
                pass.kind == RenderPassKind::Lighting
                    && pass.commands.iter().any(|command| {
                        matches!(command, RenderCommand::DrawLine { from, to, .. }
                            if *from == RenderPoint::new(32.0, 48.0)
                                && *to == RenderPoint::new(120.0, 48.0))
                    })
            })
            .expect("laser bullet snapshot should emit Java Drawf.light equivalent");
        match lighting
            .commands
            .iter()
            .find(|command| {
                matches!(command, RenderCommand::DrawLine { from, to, .. }
                    if *from == RenderPoint::new(32.0, 48.0)
                        && *to == RenderPoint::new(120.0, 48.0))
            })
            .expect("laser lighting line should be present")
        {
            RenderCommand::DrawLine {
                stroke,
                color,
                layer,
                ..
            } => {
                assert_eq!(*stroke, 10.5);
                assert_eq!(
                    *color,
                    super::desktop_effect_render_color(
                        super::desktop_resolve_color_symbol("heal@0.4"),
                        0.6
                    )
                );
                assert_eq!(*layer, LIGHT_RENDER_LAYER);
            }
            other => panic!("expected laser lighting DrawLine, got {other:?}"),
        }
    }

