    #[test]
    fn desktop_graphics_opengl_backend_placeholder_text_honors_outline_style() {
        let base_style = RenderTextStyle::new(RenderTextAlign::Center)
            .with_vertical_align(RenderTextVerticalAlign::Center)
            .with_integer_position(true);
        let base_quads = super::opengl_backend_text_placeholder_quads(
            "Play",
            RenderPoint::new(80.0, 42.0),
            [0.88, 0.96, 1.0, 1.0],
            18.0,
            0.0,
            RenderTextAlign::Center,
            base_style,
            Layer::OVERLAY_UI,
            Some(RenderTarget::Screen),
            super::opengl_backend_default_sprite_shader_program(),
            super::DesktopGraphicsOpenGlBackendBlendState::default(),
            None,
        );
        let outlined_quads = super::opengl_backend_text_placeholder_quads(
            "Play",
            RenderPoint::new(80.0, 42.0),
            [0.88, 0.96, 1.0, 1.0],
            18.0,
            0.0,
            RenderTextAlign::Center,
            base_style.with_outline(true),
            Layer::OVERLAY_UI,
            Some(RenderTarget::Screen),
            super::opengl_backend_default_sprite_shader_program(),
            super::DesktopGraphicsOpenGlBackendBlendState::default(),
            None,
        );

        assert!(!base_quads.is_empty());
        assert!(
            outlined_quads.len() > base_quads.len() * 4,
            "Mindustry UI text uses outlined fonts; the native placeholder path must emit extra shadow quads instead of flat unreadable text"
        );
        assert!(outlined_quads.iter().any(|quad| {
            let color = quad.vertices[0].color;
            quad.layer < Layer::OVERLAY_UI
                && color[0] == 0.0
                && color[1] == 0.0
                && color[2] == 0.0
                && color[3] > 0.0
        }));
    }

    #[test]
    fn desktop_graphics_opengl_backend_placeholder_text_strips_mindustry_markup() {
        assert_eq!(
            super::opengl_backend_markup_plain_text("[accent]Play[] [lightgray]v158"),
            "Play v158"
        );
        assert_eq!(
            super::opengl_backend_markup_plain_text("[[not-a-tag] [bad tag]"),
            "[not-a-tag] [bad tag]"
        );

        let style = RenderTextStyle::new(RenderTextAlign::Center)
            .with_vertical_align(RenderTextVerticalAlign::Center)
            .with_markup(true)
            .with_integer_position(true);
        let plain_quads = super::opengl_backend_text_placeholder_quads(
            "Play v158",
            RenderPoint::new(80.0, 42.0),
            [0.88, 0.96, 1.0, 1.0],
            18.0,
            0.0,
            RenderTextAlign::Center,
            style,
            Layer::OVERLAY_UI,
            Some(RenderTarget::Screen),
            super::opengl_backend_default_sprite_shader_program(),
            super::DesktopGraphicsOpenGlBackendBlendState::default(),
            None,
        );
        let markup_quads = super::opengl_backend_text_placeholder_quads(
            "[accent]Play[] [lightgray]v158",
            RenderPoint::new(80.0, 42.0),
            [0.88, 0.96, 1.0, 1.0],
            18.0,
            0.0,
            RenderTextAlign::Center,
            style,
            Layer::OVERLAY_UI,
            Some(RenderTarget::Screen),
            super::opengl_backend_default_sprite_shader_program(),
            super::DesktopGraphicsOpenGlBackendBlendState::default(),
            None,
        );
        let raw_quads = super::opengl_backend_text_placeholder_quads(
            "[accent]Play[] [lightgray]v158",
            RenderPoint::new(80.0, 42.0),
            [0.88, 0.96, 1.0, 1.0],
            18.0,
            0.0,
            RenderTextAlign::Center,
            style.with_markup(false),
            Layer::OVERLAY_UI,
            Some(RenderTarget::Screen),
            super::opengl_backend_default_sprite_shader_program(),
            super::DesktopGraphicsOpenGlBackendBlendState::default(),
            None,
        );

        assert!(!plain_quads.is_empty());
        assert_eq!(
            markup_quads.len(),
            plain_quads.len(),
            "Mindustry color tags should affect styling, not the visible placeholder glyph stream"
        );
        assert!(
            raw_quads.len() > markup_quads.len(),
            "without markup parsing the native fallback would visibly draw bracket tag glyphs"
        );
    }

