    #[test]
    fn desktop_launcher_menu_frame_applies_pressed_button_down_drawable_and_release_clears() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        let surface = DesktopSurfaceSize::new(800, 600);
        let viewport = launcher.default_render_viewport_for_surface(surface);
        let input = DesktopLauncher::default_menu_frame_input_for_viewport(viewport);
        let settings_rect = launcher
            .menu_renderer_state
            .ui_plan(input)
            .buttons
            .iter()
            .find(|button| button.role == MenuButtonRole::Settings)
            .expect("menu ui should include SETTINGS")
            .rect;
        let settings_center = settings_rect.center();

        launcher.apply_menu_input_events(
            surface,
            &[
                DesktopInputTickEvent::CursorMoved {
                    x: settings_center.x,
                    y: settings_center.y,
                },
                DesktopInputTickEvent::MouseButton {
                    button: "primary".into(),
                    pressed: true,
                },
            ],
        );
        assert_eq!(
            launcher.last_menu_pressed_button,
            Some(MenuButtonRole::Settings)
        );

        let frame = launcher.menu_graphics_frame_for_surface(0, viewport);
        let commands = frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .collect::<Vec<_>>();
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite { symbol, rect, .. }
                    if symbol == "flat-down-base.9" && *rect == settings_rect
            )
        }));

        launcher.apply_menu_input_events(
            surface,
            &[DesktopInputTickEvent::MouseButton {
                button: "primary".into(),
                pressed: false,
            }],
        );
        assert_eq!(launcher.last_menu_pressed_button, None);
        assert_eq!(
            launcher.last_menu_visual_pressed_button,
            Some(MenuButtonRole::Settings)
        );
        assert_eq!(
            launcher.last_menu_visual_pressed_frames,
            MENU_VISUAL_PRESSED_HOLD_FRAMES
        );

        let release_frame = launcher.menu_graphics_frame_for_surface(1, viewport);
        let release_commands = release_frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .collect::<Vec<_>>();
        assert!(release_commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite { symbol, rect, .. }
                    if symbol == "flat-down-base.9" && *rect == settings_rect
            )
        }));
        assert_eq!(launcher.last_menu_pressed_button, None);
        assert_eq!(
            launcher.last_menu_visual_pressed_button,
            Some(MenuButtonRole::Settings)
        );

        for frame_index in 2..=(MENU_VISUAL_PRESSED_HOLD_FRAMES as u64) {
            launcher.menu_graphics_frame_for_surface(frame_index, viewport);
        }
        assert_eq!(launcher.last_menu_visual_pressed_button, None);
        assert_eq!(launcher.last_menu_visual_pressed_frames, 0);

        let expired_frame = launcher.menu_graphics_frame_for_surface(99, viewport);
        let expired_commands = expired_frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .collect::<Vec<_>>();
        assert!(!expired_commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite { symbol, rect, .. }
                    if symbol == "flat-down-base.9" && *rect == settings_rect
            )
        }));
    }

    #[test]
    fn desktop_launcher_menu_frame_draws_java_world_background_before_buttons() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.menu_renderer_state.flyer_count = 1;
        launcher.menu_renderer_state.flyer_type = "mono";
        let surface = DesktopSurfaceSize::new(1280, 720);
        let viewport = launcher.default_render_viewport_for_surface(surface);
        let frame = launcher.menu_graphics_frame_for_surface(0, viewport);
        let render_frame = frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame");
        let menu_pass = render_frame
            .passes
            .iter()
            .find(|pass| pass.kind == RenderPassKind::Custom("menu".to_string()))
            .expect("menu frame should contain the Java menu pass");
        let commands = menu_pass.commands.iter().collect::<Vec<_>>();

        assert!(
            DesktopLauncher::menu_pass_has_java_world_background(menu_pass),
            "menu pass should include Java MenuRenderer floor/shadow/wall/flyer/darkness layers"
        );
        assert!(
            !DesktopLauncher::menu_pass_has_synthetic_background(menu_pass),
            "the old planet/space fallback must not replace the original map-like menu background"
        );
        assert!(commands.iter().all(|command| {
            !matches!(
                command,
                RenderCommand::Custom { name, .. } if name == "menu-background-approximation"
            )
        }));

        let commands = commands.into_iter().collect::<Vec<_>>();

        let clear_index = commands
            .iter()
            .position(|command| matches!(command, RenderCommand::Clear { .. }))
            .expect("menu pass should clear before drawing");
        let background_index = commands
            .iter()
            .position(|command| {
                matches!(
                    command,
                    RenderCommand::FillRect { layer, .. } if *layer < 0.0
                )
            })
            .expect("menu pass should include Java MenuRenderer floor/background spans");
        let first_button_index = commands
            .iter()
            .position(|command| {
                matches!(
                    command,
                    RenderCommand::DrawText { text, .. }
                        if text.eq_ignore_ascii_case("play") || text == "开始游戏"
                )
            })
            .expect("menu pass should still render menu buttons");

        assert!(clear_index < background_index);
        assert!(background_index < first_button_index);
        assert!(commands.iter().any(|command| matches!(
            command,
            RenderCommand::DrawSprite { symbol, .. }
                if symbol.starts_with("sand")
                    || symbol.starts_with("shale")
                    || symbol.starts_with("stone")
                    || symbol.starts_with("ore-")
        )));
    }

