    #[test]
    fn desktop_launcher_paused_world_overlay_renders_save_and_load_entries() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.game_state.world.resize(16, 16);
        launcher.game_state.set(GameStateState::Paused);
        assert!(launcher.game_state.is_paused());

        let surface = DesktopSurfaceSize::new(1280, 720);
        let viewport = launcher.default_render_viewport_for_surface(surface);
        let mut renderer = HeadlessDesktopGraphicsRenderer::default();
        launcher.render_default_graphics_frame_for_surface_with(0, surface, 1, &mut renderer);

        let texts = renderer
            .last_trace
            .render_passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .filter_map(|command| match command {
                RenderCommand::DrawText { text, .. } => Some(text.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert!(texts.contains(&"PausedDialog"));
        assert!(texts.contains(&"upstream: PausedDialog"));
        assert!(texts.contains(&launcher.localize_bundle_markup_text("@back").as_str()));
        assert!(texts.contains(&launcher.localize_bundle_markup_text("@settings").as_str()));
        assert!(texts.contains(&launcher.localize_bundle_markup_text("@savegame").as_str()));
        assert!(texts.contains(&launcher.localize_bundle_markup_text("@loadgame").as_str()));
        assert!(texts.contains(&launcher.localize_bundle_markup_text("@hostserver").as_str()));
        assert!(texts.contains(&launcher.localize_bundle_markup_text("@quit").as_str()));

        let panel = DesktopLauncher::pause_overlay_panel_for_viewport(viewport);
        let save_center = DesktopLauncher::pause_overlay_button_rect_for_panel(panel, 2).center();
        launcher.apply_menu_input_events(
            surface,
            &[
                DesktopInputTickEvent::CursorMoved {
                    x: save_center.x,
                    y: save_center.y,
                },
                DesktopInputTickEvent::MouseButton {
                    button: "left".into(),
                    pressed: true,
                },
            ],
        );

        assert_eq!(
            launcher.active_menu_route,
            Some(super::DesktopMenuRoute::SaveGame)
        );
        assert!(launcher.game_state.is_paused());

        launcher.render_default_graphics_frame_for_surface_with(1, surface, 2, &mut renderer);
        let route_texts = renderer
            .last_trace
            .render_passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .filter_map(|command| match command {
                RenderCommand::DrawText { text, .. } => Some(text.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();
        assert!(route_texts.contains(&launcher.localize_bundle_markup_text("@savegame").as_str()));
        assert!(route_texts.contains(&launcher.localize_bundle_markup_text("@save.new").as_str()));
        assert!(route_texts.contains(&"upstream: SaveDialog"));
    }

    #[test]
    fn desktop_launcher_paused_world_overlay_respects_net_and_editor_branches() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.game_state.world.resize(16, 16);
        launcher.game_state.set(GameStateState::Paused);
        launcher.net_client.state().lock().unwrap().connected = true;

        let surface = DesktopSurfaceSize::new(1280, 720);
        let viewport = launcher.default_render_viewport_for_surface(surface);
        let panel = DesktopLauncher::pause_overlay_panel_for_viewport(viewport);
        let load_center = DesktopLauncher::pause_overlay_button_rect_for_panel(panel, 3).center();
        let host_center = DesktopLauncher::pause_overlay_button_rect_for_panel(panel, 4).center();

        assert_eq!(
            launcher.pause_overlay_action_at_surface_point(surface, load_center.x, load_center.y),
            None,
            "Java PausedDialog disables LoadDialog while net.active()"
        );
        assert_eq!(
            launcher.pause_overlay_action_at_surface_point(surface, host_center.x, host_center.y),
            None,
            "Java PausedDialog disables host while already connected as client"
        );
        launcher.dispatch_pause_overlay_action(super::DesktopPausedOverlayAction::LoadGame);
        assert_eq!(launcher.active_menu_route, None);
        launcher.dispatch_pause_overlay_action(super::DesktopPausedOverlayAction::HostServer);
        assert_eq!(launcher.active_menu_route, None);

        let mut renderer = HeadlessDesktopGraphicsRenderer::default();
        launcher.render_default_graphics_frame_for_surface_with(0, surface, 1, &mut renderer);
        let net_texts = renderer
            .last_trace
            .render_passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .filter_map(|command| match command {
                RenderCommand::DrawText { text, .. } => Some(text.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();
        assert!(net_texts.contains(&launcher.localize_bundle_markup_text("@loadgame").as_str()));
        assert!(net_texts.contains(&launcher.localize_bundle_markup_text("@hostserver").as_str()));

        launcher.net_client.state().lock().unwrap().connected = false;
        launcher.game_state.rules.editor = true;
        launcher.render_default_graphics_frame_for_surface_with(1, surface, 1, &mut renderer);
        let editor_panel = launcher.pause_overlay_panel_for_current_state(viewport);
        let world_processors_center =
            DesktopLauncher::pause_overlay_button_rect_for_panel(editor_panel, 3).center();
        let editor_texts = renderer
            .last_trace
            .render_passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .filter_map(|command| match command {
                RenderCommand::DrawText { text, .. } => Some(text.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();
        assert!(editor_texts.contains(
            &launcher
                .localize_bundle_markup_text("@hostserver.mobile")
                .as_str()
        ));
        assert!(editor_texts.contains(
            &launcher
                .localize_bundle_markup_text("@editor.worldprocessors")
                .as_str()
        ));
        assert!(!editor_texts.contains(&launcher.localize_bundle_markup_text("@savegame").as_str()));
        assert!(!editor_texts.contains(&launcher.localize_bundle_markup_text("@loadgame").as_str()));
        launcher.apply_menu_input_events(
            surface,
            &[
                DesktopInputTickEvent::CursorMoved {
                    x: world_processors_center.x,
                    y: world_processors_center.y,
                },
                DesktopInputTickEvent::MouseButton {
                    button: "left".into(),
                    pressed: true,
                },
            ],
        );
        assert_eq!(
            launcher.pause_overlay_modal,
            Some(super::DesktopPausedOverlayModal::WorldProcessors)
        );
        launcher.render_default_graphics_frame_for_surface_with(2, surface, 1, &mut renderer);
        let processor_texts = renderer
            .last_trace
            .render_passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .filter_map(|command| match command {
                RenderCommand::DrawText { text, .. } => Some(text.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();
        assert!(processor_texts.contains(&"MapProcessorsDialog"));
        assert!(processor_texts
            .iter()
            .any(|text| text.contains("processors: 0")));
    }

