    #[test]
    fn desktop_launcher_menu_renders_logo_and_version_overlay() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.settings_locale = "en".into();
        launcher.player_locale = "en".into();
        assert!(launcher.texture_atlas.lookup("logo").is_ok());
        assert!(launcher.texture_atlas.lookup("serpulo").is_ok());
        assert!(launcher.texture_atlas.lookup("erekir").is_ok());
        assert!(launcher.texture_atlas.lookup("discord-banner").is_ok());
        assert!(launcher.texture_atlas.lookup("info-banner").is_ok());
        assert!(launcher.texture_atlas.lookup("flat-down-base.9").is_ok());
        assert!(launcher.texture_atlas.lookup("window-empty.9").is_ok());
        assert!(launcher.texture_atlas.lookup("pane.9").is_ok());
        assert!(launcher.texture_atlas.lookup("button.9").is_ok());
        assert!(launcher.texture_atlas.lookup("button-down.9").is_ok());
        assert!(launcher.texture_atlas.lookup("whiteui").is_ok());
        assert!(launcher.texture_atlas.lookup("sand-floor1").is_ok());
        assert!(launcher.texture_atlas.lookup("shale-wall1").is_ok());
        assert!(launcher.texture_atlas.lookup("ore-copper1").is_ok());

        for source_path in upstream_ui_skin_sprite_source_paths() {
            let atlas_name =
                TextureAtlasSpriteSourceDescriptor::from_source_path(source_path).atlas_name;
            assert!(
                launcher.texture_atlas.lookup(&atlas_name).is_ok(),
                "default desktop atlas should include upstream UI skin sprite: {source_path}"
            );
        }

        for source_path in desktop_menu_label_sprite_virtual_source_paths() {
            let atlas_name =
                TextureAtlasSpriteSourceDescriptor::from_virtual_source_path(source_path.as_str())
                    .atlas_name;
            let region = launcher
                .texture_atlas
                .lookup(&atlas_name)
                .unwrap_or_else(|_| {
                    panic!(
                    "default desktop atlas should include Chinese menu label sprite: {source_path}"
                )
                });
            assert_eq!(region.region.source_path, source_path.as_str());
        }

        for source_path in desktop_menu_icon_sprite_virtual_source_paths() {
            let atlas_name =
                TextureAtlasSpriteSourceDescriptor::from_virtual_source_path(source_path.as_str())
                    .atlas_name;
            let region = launcher
                .texture_atlas
                .lookup(&atlas_name)
                .unwrap_or_else(|_| {
                    panic!(
                    "default desktop atlas should include upstream menu icon sprite: {source_path}"
                )
                });
            assert_eq!(region.region.source_path, source_path.as_str());
        }

        let viewport = RenderViewport::new(0.0, 0.0, 1280.0, 720.0);
        assert!(launcher
            .menu_renderer_state
            .select_desktop_root(MenuButtonRole::Play));
        let frame = launcher.menu_graphics_frame_for_surface(0, viewport);
        let render_frame = frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame");
        assert_eq!(render_frame.passes.len(), 1);
        let menu_pass = &render_frame.passes[0];
        assert!(!menu_pass.commands.is_empty());
        let commands = frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .collect::<Vec<_>>();

        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::FillRect { color, layer, .. }
                    if *color == [0.0, 0.0, 0.0, super::MENU_DARKNESS]
                        && (*layer - super::MENU_DARKNESS_LAYER).abs() < f32::EPSILON
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText { text, .. } if text == "Play"
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText { text, .. } if text == "Campaign"
            )
        }));
        let logo = commands
            .iter()
            .find_map(|command| match command {
                RenderCommand::DrawSprite {
                    symbol,
                    rect,
                    layer,
                    ..
                } if symbol == "logo" => Some((*rect, *layer)),
                _ => None,
            })
            .expect("menu chrome should draw the logo sprite");
        assert_eq!(
            logo,
            (
                RenderRect::new(256.0, 607.0, 768.0, 107.0),
                Layer::END_PIXELED + 0.08
            )
        );
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText { text, position, color, layer, .. }
                    if text == &upstream_menu_version_text()
                        && *position == RenderPoint::new(640.0, 605.0)
                        && *color == upstream_menu_version_color()
                        && (*layer - (Layer::END_PIXELED + 0.09)).abs() < f32::EPSILON
            )
        }));
    }

