    #[test]
    fn desktop_launcher_menu_uses_settings_locale_bundle_for_menu_buttons() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.settings_locale = "zh_CN".into();
        assert!(launcher
            .menu_renderer_state
            .select_desktop_root(MenuButtonRole::Database));

        let viewport = RenderViewport::new(0.0, 0.0, 1280.0, 720.0);
        let frame = launcher.menu_graphics_frame_for_surface(0, viewport);
        let texts = frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .filter_map(|command| match command {
                RenderCommand::DrawText { text, .. } => Some(text.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();
        let sprites = frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .filter_map(|command| match command {
                RenderCommand::DrawSprite { symbol, .. } => Some(symbol.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert!(texts.contains(&"数据库") || sprites.contains(&"menu-label-zh-database"));
        assert!(
            texts.contains(&"核心数据库") || sprites.contains(&"menu-label-zh-content-database")
        );
        assert!(texts.contains(&"蓝图") || sprites.contains(&"menu-label-zh-schematics"));
        assert!(
            !texts.contains(&"Core Database"),
            "Java MenuFragment resolves @database through the active Core.bundle locale; Rust may render the localized label as a prerendered menu sprite"
        );
    }

    #[test]
    fn desktop_launcher_menu_locale_bundle_covers_tw_and_fallback_paths() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.settings_locale = "zh_TW".into();
        assert!(launcher
            .menu_renderer_state
            .select_desktop_root(MenuButtonRole::Database));

        let frame =
            launcher.menu_frame_for_render(MenuFrameInput::new(1280.0, 720.0, 4.0, 1.0 / 60.0));
        let DesktopFramePayload::Menu(plan) = frame.payload else {
            panic!("menu_frame_for_render should return menu payload");
        };
        let labels = plan
            .ui
            .buttons
            .iter()
            .map(|button| button.label.as_str())
            .collect::<Vec<_>>();
        assert!(labels.contains(&"資料庫"));
        assert!(labels.contains(&"核心資料庫"));
        assert!(labels.contains(&"藍圖"));

        let mut fallback_launcher = DesktopLauncher::new(Vec::new());
        fallback_launcher.settings_locale = "unknown".into();
        assert!(fallback_launcher
            .menu_renderer_state
            .select_desktop_root(MenuButtonRole::Database));
        let frame = fallback_launcher.menu_frame_for_render(MenuFrameInput::new(
            1280.0,
            720.0,
            4.0,
            1.0 / 60.0,
        ));
        let DesktopFramePayload::Menu(plan) = frame.payload else {
            panic!("menu_frame_for_render should return menu payload");
        };
        let labels = plan
            .ui
            .buttons
            .iter()
            .map(|button| button.label.as_str())
            .collect::<Vec<_>>();
        assert!(labels.contains(&"Database"));
        assert!(labels.contains(&"Core Database"));
        assert!(labels.contains(&"Schematics"));
    }

    #[test]
    fn desktop_launcher_menu_route_titles_use_settings_locale_bundle_like_java_dialogs() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.settings_locale = "zh_CN".into();

        assert_eq!(
            launcher.localized_menu_route_title(DesktopMenuRoute::Join),
            "加入游戏"
        );
        assert_eq!(
            launcher.localized_menu_route_title(DesktopMenuRoute::Host),
            "创建联机游戏"
        );
        assert_eq!(
            launcher.localized_menu_route_title(DesktopMenuRoute::SaveGame),
            "保存游戏"
        );
        assert_eq!(
            launcher.localized_menu_route_title(DesktopMenuRoute::Database),
            "核心数据库"
        );
        assert_eq!(
            launcher.localized_menu_route_title(DesktopMenuRoute::TechTree),
            "",
            "Java ResearchDialog calls super(\"\"); @techtree is the menu-entry text, not the dialog title"
        );
        assert_eq!(
            launcher.localized_menu_route_title(DesktopMenuRoute::Discord),
            "",
            "Java DiscordDialog calls super(\"\") and renders @discord inside the dialog content"
        );
        assert_eq!(
            launcher.localized_menu_route_title(DesktopMenuRoute::Editor),
            "地图",
            "Java EditorMapsDialog uses @maps as its dialog title; @editor is only the menu-entry label"
        );

        launcher.active_menu_route = Some(DesktopMenuRoute::Join);
        let viewport = RenderViewport::new(0.0, 0.0, 1280.0, 720.0);
        let frame = launcher.menu_graphics_frame_for_surface(0, viewport);
        let texts = frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu route frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .filter_map(|command| match command {
                RenderCommand::DrawText { text, .. } => Some(text.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert!(texts.contains(&"加入游戏"));
        assert!(texts.contains(&"名称："));
        assert!(texts.contains(&"添加服务器"));
        assert!(texts.contains(&"刷新"));
        assert!(texts.contains(&"本地服务器"));
        assert!(texts.contains(&"已保存的服务器"));
        assert!(
            !texts.contains(&"JOIN GAME"),
            "route shell title should not bypass Core.bundle with hard-coded all-caps text"
        );
        for raw_key in ["@name", "@server.add", "@refresh", "@servers.local"] {
            assert!(
                !texts.contains(&raw_key),
                "JoinDialog chrome should resolve visible bundle key {raw_key} before rendering"
            );
        }

        let mut fallback_launcher = DesktopLauncher::new(Vec::new());
        fallback_launcher.settings_locale = "unknown".into();
        assert_eq!(
            fallback_launcher.localized_menu_route_title(DesktopMenuRoute::Join),
            "Join Game"
        );
        assert_eq!(
            fallback_launcher.localized_menu_route_title(DesktopMenuRoute::Host),
            "Host Multiplayer Game"
        );
    }

    #[test]
    fn desktop_launcher_default_font_asset_sources_follow_upstream_fonts_registry() {
        let launcher = DesktopLauncher::new(Vec::new());
        let source_paths = launcher
            .font_asset_sources
            .iter()
            .map(|source| source.source_path.as_str())
            .collect::<Vec<_>>();

        assert!(source_paths.contains(&"fonts/font.woff"));
        assert!(source_paths.contains(&"fonts/font_jp.woff"));
        assert!(source_paths.contains(&"fonts/icon.ttf"));
        assert!(source_paths.contains(&"fonts/logic.ttf"));
        assert!(source_paths.contains(&"fonts/monospace.woff"));
        assert!(source_paths.contains(&"fonts/tech.ttf"));
        assert!(source_paths.contains(&"icons/icons.properties"));
        let report = launcher.font_asset_validation_report();
        assert!(report.total_count <= launcher.font_asset_sources.len());
        assert_eq!(
            report.resolved_count + report.missing_source_paths.len(),
            report.total_count
        );
    }

    #[test]
    fn desktop_font_asset_sources_resolve_from_mindustry_asset_root() {
        let root = temp_desktop_path("font-asset-root");
        let asset_root = root.join("assets");
        let font_path = asset_root.join("fonts/font.woff");
        let icon_properties_path = asset_root.join("icons/icons.properties");
        std::fs::create_dir_all(font_path.parent().unwrap())
            .expect("font fixture dir should be writable");
        std::fs::create_dir_all(icon_properties_path.parent().unwrap())
            .expect("icon fixture dir should be writable");
        std::fs::write(&font_path, b"font").expect("font fixture should be writable");
        std::fs::write(&icon_properties_path, b"63743=spawn|block-spawn-ui\n")
            .expect("icons fixture should be writable");

        let _asset_guard = EnvVarGuard::set("MINDUSTRY_ASSET_ROOT", &asset_root);
        let sources = super::default_desktop_font_asset_source_traces();
        let font = sources
            .iter()
            .find(|source| source.source_path == "fonts/font.woff")
            .expect("font source should be listed");
        let icons = sources
            .iter()
            .find(|source| source.source_path == "icons/icons.properties")
            .expect("icons properties source should be listed");
        let expected_font_path = font_path.to_string_lossy().replace('\\', "/");
        let expected_icons_path = icon_properties_path.to_string_lossy().replace('\\', "/");

        assert!(font.resolved());
        assert!(icons.resolved());
        assert_eq!(font.file_path.as_deref(), Some(expected_font_path.as_str()));
        assert_eq!(
            icons.file_path.as_deref(),
            Some(expected_icons_path.as_str())
        );

        let report = super::desktop_validate_font_asset_sources(&sources);
        assert!(
            report.resolved_count >= 2,
            "fixture font and icons.properties should resolve even when local upstream defaults resolve additional assets"
        );
    }

    #[test]
    fn desktop_content_icon_glyph_registry_loads_upstream_icon_properties() {
        let root = temp_desktop_path("content-icon-glyph-root");
        let asset_root = root.join("assets");
        let icon_properties_path = asset_root.join("icons/icons.properties");
        std::fs::create_dir_all(icon_properties_path.parent().unwrap())
            .expect("icon fixture dir should be writable");
        std::fs::write(
            &icon_properties_path,
            b"63743=spawn|block-spawn-ui\n63744=router|block-router-ui\n",
        )
        .expect("icons fixture should be writable");

        let _asset_guard = EnvVarGuard::set("MINDUSTRY_ASSET_ROOT", &asset_root);
        let registry = super::default_desktop_content_icon_glyph_registry();
        let expected_icons_path = icon_properties_path.to_string_lossy().replace('\\', "/");

        assert_eq!(registry.source_path, "icons/icons.properties");
        assert_eq!(
            registry.file_path.as_deref(),
            Some(expected_icons_path.as_str())
        );
        assert!(registry.loaded());
        assert_eq!(registry.len(), 2);
        assert_eq!(
            registry
                .get_by_name("spawn")
                .map(|icon| icon.atlas_symbol.as_str()),
            Some("block-spawn-ui")
        );
        assert_eq!(
            registry
                .get_by_unicode(63744)
                .map(|icon| icon.name.as_str()),
            Some("router")
        );
        assert_eq!(
            registry
                .get_by_atlas_symbol("block-router-ui")
                .map(|icon| icon.unicode),
            Some(63744)
        );

        let report = registry.validation_report();
        assert!(report.loaded());
        assert_eq!(report.icon_count, 2);
        assert!(report.load_error.is_none());
    }

