    #[test]
    fn desktop_font_rasterization_plan_bridges_fonts_icons_and_texture_atlas() {
        let root = temp_desktop_path("font-rasterization-plan-root");
        let asset_root = root.join("assets");
        let font_path = asset_root.join("fonts/font.woff");
        let logic_path = asset_root.join("fonts/logic.ttf");
        let icon_properties_path = asset_root.join("icons/icons.properties");
        std::fs::create_dir_all(font_path.parent().unwrap())
            .expect("font fixture dir should be writable");
        std::fs::create_dir_all(icon_properties_path.parent().unwrap())
            .expect("icon fixture dir should be writable");
        std::fs::write(&font_path, b"font").expect("font fixture should be writable");
        std::fs::write(&logic_path, b"logic").expect("logic font fixture should be writable");
        std::fs::write(
            &icon_properties_path,
            b"63743=spawn|whiteui\n63744=missing|missing-atlas-symbol\n",
        )
        .expect("icons fixture should be writable");

        let _asset_guard = EnvVarGuard::set("MINDUSTRY_ASSET_ROOT", &asset_root);
        let launcher = DesktopLauncher::new(Vec::new());
        let plan = launcher.font_rasterization_plan();

        assert_eq!(plan.font_assets.len(), upstream_font_assets().len());
        assert!(plan.fallback_placeholder_enabled);
        assert!(plan
            .font_assets
            .iter()
            .any(|asset| asset.role == UpstreamFontRole::Default
                && asset.render_font_id == Some(RenderFontId::Default)
                && asset.resolved));
        assert!(plan
            .font_assets
            .iter()
            .any(|asset| asset.role == UpstreamFontRole::Logic
                && asset.render_font_id == Some(RenderFontId::Logic)
                && asset.resolved
                && asset.character_seed_count > 0));
        assert!(plan.font_assets.iter().any(|asset| {
            asset.role == UpstreamFontRole::Icon
                && asset.render_font_id == Some(RenderFontId::Icon)
                && asset.source_path == "fonts/icon.ttf"
        }));
        assert!(plan.font_assets.iter().any(|asset| {
            asset.role == UpstreamFontRole::IconLarge
                && asset.render_font_id == Some(RenderFontId::IconLarge)
                && asset.source_path == "fonts/icon.ttf"
                && asset.size == 48
                && asset.border_width == Some(5)
                && !asset.scaled
        }));
        assert_eq!(plan.content_icons.len(), 2);
        assert_eq!(
            plan.content_icons
                .iter()
                .find(|icon| icon.name == "spawn")
                .map(|icon| icon.atlas_region_resolved),
            Some(true)
        );
        assert_eq!(
            plan.content_icons
                .iter()
                .find(|icon| icon.name == "missing")
                .map(|icon| icon.atlas_region_resolved),
            Some(false)
        );

        let atlas_plan = launcher.font_atlas_plan();
        assert_eq!(
            atlas_plan.texture_name,
            DESKTOP_FONT_GLYPH_ATLAS_TEXTURE_NAME
        );
        assert_eq!(atlas_plan.content_icon_glyph_count, 2);
        assert_eq!(
            atlas_plan.missing_icon_atlas_symbols,
            vec!["missing-atlas-symbol".to_string()]
        );
        assert!(!atlas_plan.ready_for_real_upload());

        let upload_plan = launcher.font_glyph_upload_plan();
        assert_eq!(
            upload_plan.expected_glyph_count,
            atlas_plan.planned_glyph_count
        );
        assert!(!upload_plan.requires_texture_upload);
        assert!(upload_plan.fallback_placeholder_enabled);
        assert!(upload_plan.to_opengl_texture_upload_plan().is_none());
    }

    #[test]
    fn desktop_font_glyph_upload_plan_emits_runtime_texture_upload_when_ready() {
        let atlas_plan = super::DesktopFontAtlasPlan {
            texture_name: DESKTOP_FONT_GLYPH_ATLAS_TEXTURE_NAME.to_string(),
            font_asset_count: 2,
            resolved_font_asset_count: 2,
            content_icon_glyph_count: 1,
            planned_glyph_count: 8,
            unresolved_font_source_paths: Vec::new(),
            missing_icon_atlas_symbols: Vec::new(),
            content_icon_load_error: None,
            placeholder_fallback_required: true,
        };

        assert!(atlas_plan.ready_for_real_upload());
        let upload_plan = atlas_plan.upload_plan();
        assert!(upload_plan.requires_texture_upload);
        assert_eq!(
            upload_plan.texture_key,
            DESKTOP_FONT_GLYPH_ATLAS_TEXTURE_KEY
        );
        assert_eq!(
            upload_plan.texture_width,
            DESKTOP_FONT_GLYPH_ATLAS_PLACEHOLDER_WIDTH
        );
        assert_eq!(
            upload_plan.texture_height,
            DESKTOP_FONT_GLYPH_ATLAS_PLACEHOLDER_HEIGHT
        );

        let texture_upload = upload_plan
            .to_opengl_texture_upload_plan()
            .expect("ready font upload plan should emit an OpenGL texture upload plan");
        assert_eq!(
            texture_upload.resource_kind,
            super::DesktopGraphicsOpenGlBackendTextureResourceKind::RuntimeTexture
        );
        assert_eq!(
            texture_upload.texture_key,
            DESKTOP_FONT_GLYPH_ATLAS_TEXTURE_KEY
        );
        assert_eq!(
            texture_upload.kind,
            super::DesktopGraphicsOpenGlBackendTextureUploadKind::FullPage
        );
        assert!(texture_upload.recreate_texture);

        let generated_source = upload_plan
            .generated_rgba8888_pixel_source()
            .expect("ready font upload plan should expose generated RGBA pixels");
        let generated_pixels = generated_source
            .load_rgba8888_pixels()
            .expect("generated font glyph atlas pixels should load directly");
        assert_eq!(
            generated_pixels.pixels.len(),
            (generated_pixels.width * generated_pixels.height * 4) as usize
        );
        assert!(generated_pixels
            .pixels
            .chunks_exact(4)
            .any(|rgba| rgba == [255, 255, 255, 255]));

        let pixel_source =
            super::DesktopGraphicsOpenGlBackendTextureUploadPixelSource::RuntimeTexture {
                texture_key: texture_upload.texture_key.clone(),
                page_source_path: texture_upload.page_source_path.clone(),
                width: texture_upload.page_width,
                height: texture_upload.page_height,
            };
        let pixels = pixel_source
            .load_rgba8888_pixels()
            .expect("font glyph atlas runtime texture should provide placeholder pixels");
        assert_eq!(pixels.width, DESKTOP_FONT_GLYPH_ATLAS_PLACEHOLDER_WIDTH);
        assert_eq!(pixels.height, DESKTOP_FONT_GLYPH_ATLAS_PLACEHOLDER_HEIGHT);
        assert_eq!(
            pixels.pixels.len(),
            (pixels.width * pixels.height * 4) as usize
        );
        assert!(pixels
            .pixels
            .chunks_exact(4)
            .any(|rgba| rgba == [255, 255, 255, 255]));
    }

    #[test]
    fn desktop_launcher_synthetic_menu_background_uses_bucketed_layers_for_batching() {
        let launcher = DesktopLauncher::new(Vec::new());
        let commands =
            launcher.menu_background_layer_commands(RenderViewport::new(0.0, 0.0, 1280.0, 720.0));

        assert!(
            commands.len() >= 70,
            "synthetic menu fallback should still render the full animated background"
        );

        let mut synthetic_layer_keys = commands
            .iter()
            .filter_map(DesktopLauncher::render_command_layer)
            .filter(|layer| (-130.0..=-80.0).contains(layer))
            .map(|layer| (layer * 1000.0).round() as i32)
            .collect::<Vec<_>>();
        synthetic_layer_keys.sort_unstable();
        synthetic_layer_keys.dedup();

        assert_eq!(
            synthetic_layer_keys,
            vec![
                -120000, -119000, -117000, -112000, -111000, -110000, -109000, -108000, -107000,
                -106000, -90000,
            ],
            "menu background must keep heavy repeated primitives in stable layer buckets so the OpenGL backend can batch them"
        );
    }

    #[test]
    fn desktop_launcher_menu_renders_desktop_and_discord_chrome_buttons() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.menu_becheck_active = true;

        let viewport = RenderViewport::new(0.0, 0.0, 1280.0, 720.0);
        let frame = launcher.menu_graphics_frame_for_surface(0, viewport);
        let commands = frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .collect::<Vec<_>>();

        let discord_rect = RenderRect::new(1196.0, 0.0, 84.0, 45.0);
        let becheck_rect = RenderRect::new(1080.0, 0.0, 200.0, 60.0);
        assert!(!commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::FillRect { rect, .. } if *rect == discord_rect
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite { symbol, rect, .. }
                    if symbol == "discord-banner" && *rect == discord_rect
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText { text, .. }
                    if text == &super::desktop_ui_icon_glyph_or_label("discord", "discord")
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite { symbol, rect, .. }
                    if symbol == "button.9" && *rect == becheck_rect
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText { text, style, .. }
                    if text == &super::desktop_ui_icon_glyph_or_label("refresh", "refresh")
                        && style.font == RenderFontId::Icon
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText { text, style, .. }
                    if text == "@be.check" && style.horizontal_align == RenderTextAlign::Start
            )
        }));
        launcher.menu_becheck_update_available = true;
        launcher.menu_renderer_state.time = core::f32::consts::FRAC_PI_2 * 5.0 - (1.0 / 60.0);
        let update_frame = launcher.menu_graphics_frame_for_surface(1, viewport);
        let update_commands = update_frame
            .bundle
            .render_frame
            .as_ref()
            .expect("update-available menu frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .collect::<Vec<_>>();
        assert!(
            update_commands.iter().any(|command| matches!(
                command,
                RenderCommand::DrawText { text, color, .. }
                    if text == "@be.check"
                        && (color[0] - Pal::ACCENT.r).abs() < 0.02
                        && (color[1] - Pal::ACCENT.g).abs() < 0.02
                        && (color[2] - Pal::ACCENT.b).abs() < 0.02
            )),
            "Java MenuFragment pulses the BE check label toward Pal.accent when an update is available"
        );
        assert!(!commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText { text, .. } if text == "terminal"
            )
        }));
        assert!(!commands.iter().any(|command| {
            matches!(command, RenderCommand::FillRect { rect, .. } if rect.width == 14.0 && rect.height == 720.0)
        }));
    }

    #[test]
    fn desktop_launcher_menu_frame_input_uses_runtime_ui_scale_and_frame_delta_like_java() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.menu_ui_scale = 1.5;
        launcher.menu_frame_delta_seconds = 1.0 / 30.0;
        launcher.menu_scene_margin_top = 8.0;
        launcher.menu_scene_margin_bottom = 6.0;

        let input =
            launcher.menu_frame_input_for_viewport(RenderViewport::new(0.0, 0.0, 1280.0, 720.0));

        assert_eq!(input.graphics_width, 1280.0);
        assert_eq!(input.graphics_height, 720.0);
        assert_eq!(input.scene_margin_top, 8.0);
        assert_eq!(input.scene_margin_bottom, 6.0);
        assert_eq!(
            input.scl4, 6.0,
            "Java MenuRenderer uses Scl.scl(4f), so Rust must include current UI scale"
        );
        assert_eq!(
            input.delta,
            1.0 / 30.0,
            "submenu fade and menu animation should consume frame-loop delta instead of a hard-coded step"
        );
    }

    #[test]
    fn desktop_launcher_menu_renders_mobile_terminal_info_and_gutter_chrome() {
        let mut launcher = DesktopLauncher::new(Vec::new());
        launcher.menu_renderer_state.config.mobile = true;

        let viewport = RenderViewport::new(0.0, 0.0, 540.0, 960.0);
        let frame = launcher.menu_graphics_frame_for_surface(0, viewport);
        let commands = frame
            .bundle
            .render_frame
            .as_ref()
            .expect("menu frame should contain render frame")
            .passes
            .iter()
            .flat_map(|pass| pass.commands.iter())
            .collect::<Vec<_>>();

        let left_gutter = RenderRect::new(0.0, 0.0, 14.0, 960.0);
        let right_gutter = RenderRect::new(526.0, 0.0, 14.0, 960.0);
        let bottom_gutter = RenderRect::new(14.0, 0.0, 512.0, 12.0);
        let terminal_rect = RenderRect::new(4.0, 49.0, 60.0, 60.0);
        let info_rect = RenderRect::new(0.0, 0.0, 84.0, 45.0);
        let discord_rect = RenderRect::new(456.0, 0.0, 84.0, 45.0);

        for (symbol, rect) in [
            ("pane-right.9", left_gutter),
            ("pane-left.9", right_gutter),
            ("pane-top.9", bottom_gutter),
        ] {
            assert!(commands.iter().any(|command| {
                matches!(
                    command,
                    RenderCommand::DrawSprite { symbol: candidate, rect: candidate_rect, .. }
                        if candidate == symbol && *candidate_rect == rect
                )
            }));
        }

        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite { symbol, rect, .. }
                    if symbol == "button.9" && *rect == terminal_rect
            )
        }));
        for rect in [info_rect, discord_rect] {
            assert!(!commands.iter().any(|command| {
                matches!(
                    command,
                    RenderCommand::FillRect { rect: candidate, .. } if *candidate == rect
                )
            }));
        }
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText { text, .. }
                    if text == &super::desktop_ui_icon_glyph_or_label("terminal", "terminal")
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite { symbol, rect, .. }
                    if symbol == "info-banner" && *rect == info_rect
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawSprite { symbol, rect, .. }
                    if symbol == "discord-banner" && *rect == discord_rect
            )
        }));
        assert!(commands.iter().any(|command| {
            matches!(
                command,
                RenderCommand::DrawText { text, .. }
                    if text == &super::desktop_ui_icon_glyph_or_label("discord", "discord")
            )
        }));
        assert!(!commands.iter().any(|command| {
            matches!(command, RenderCommand::DrawText { text, .. } if text == "becheck")
        }));
    }

